-- Poems batch 7
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0a0f3730-bf09-4e6a-8fc4-d713b40149df','贈別韋兵曹歸池州','韓翃','唐','唐诗','tang','','[]','南陵八月天，暮色遠峰前。',48,'全唐诗/poet.tang.12000.json','["南陵八月天，暮色遠峰前。", "楚竹青陽路，吳江赤馬船。", "籝金諸客貴，佩玉主人賢。", "終日應相逐，歸期定幾年。"]'),
('e09998e4-ec09-4118-ac1b-92f7b53b2f7c','寄武陵李少府','韓翃','唐','唐诗','tang','','[]','小縣春山口，公孫吏隱時。',48,'全唐诗/poet.tang.12000.json','["小縣春山口，公孫吏隱時。", "楚歌催晚醉，蠻語入新詩。", "桂水遙相憶，花源暗有期。", "郢門千里外，莫怪尺書遲。"]'),
('19cd68eb-40b6-45d2-8010-912fee03f160','贈張建','韓翃','唐','唐诗','tang','','[]','結客平陵下，當年倚俠遊。',48,'全唐诗/poet.tang.12000.json','["結客平陵下，當年倚俠遊。", "傳看轆轤劍，醉脫驦驌裘。", "翠羽雙鬟妾，珠簾百尺樓。", "春風坐相待，晚日莫淹留。"]'),
('6723cc17-8c0f-4924-b703-bd1ae7e66bdc','送監軍李判官','韓翃','唐','唐诗','tang','','[]','上客佩雙劍，東城喜再遊。',48,'全唐诗/poet.tang.12000.json','["上客佩雙劍，東城喜再遊。", "舊從張博望，新事鄭長秋。", "踏水回金勒，看風試錦裘。", "知君不久住，漢將掃旄頭。"]'),
('7f75b9eb-4723-433f-9a55-3241ddd9c4ff','送客歸廣平','韓翃','唐','唐诗','tang','','[]','家在趙邯鄲，歸心輙自歡。',48,'全唐诗/poet.tang.12000.json','["家在趙邯鄲，歸心輙自歡。", "晚杯狐腋暖，春雪馬毛寒。", "孟月途中破，輕冰水上殘。", "到時楊柳色，奈向故園看。"]'),
('03aa2c0d-a012-4541-b8e6-e4661f8dd9ab','送張儋水路歸北海','韓翃','唐','唐诗','tang','','[]','千里東歸客，孤心憶舊游。',48,'全唐诗/poet.tang.12000.json','["千里東歸客，孤心憶舊游。", "片帆依白水，高枕臥青州。", "柏寢寒蕪變，梧臺宿雨收。", "知君心興遠，每上海邊樓。"]'),
('78d01744-4b3b-4562-ac43-9832e61e0648','送故人歸魯','韓翃','唐','唐诗','tang','','[]','魯客多歸興，居人悵別情。',48,'全唐诗/poet.tang.12000.json','["魯客多歸興，居人悵別情。", "雨餘衫袖冷，風急馬蹄輕。", "秋草靈光殿，寒雲曲阜城。", "知君拜親後，少婦下機迎。"]'),
('8e7a1341-509d-4548-b45e-2d223e034977','送故人歸蜀','韓翃','唐','唐诗','tang','','[]','一騎西南遠，翩翩入劍門。',48,'全唐诗/poet.tang.12000.json','["一騎西南遠，翩翩入劍門。", "客衣筒布潤，山舍荔枝繁。", "古廟祠金馬，春江帶白黿。", "自應成旅逸，愛客有王孫。"]'),
('ce493923-7c4b-41a9-94e9-cf95741c018c','酬程延秋夜即事見贈','韓翃','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u666f", "\u916c\u7b54", "\u4e94\u8a00\u5f8b\u8bd7"]','長簟迎風早，空城澹月華。',48,'全唐诗/poet.tang.12000.json','["長簟迎風早，空城澹月華。", "星河秋一雁，砧杵夜千家。", "節候看應晚，心期臥亦賒。", "向來吟秀句，不覺已鳴鴉。"]'),
('7e328454-fcde-4d6e-bfd6-578cc7a83c1e','送郭贊府歸淮南','韓翃','唐','唐诗','tang','','[]','駿馬淮南客，歸時引望新。',48,'全唐诗/poet.tang.12000.json','["駿馬淮南客，歸時引望新。", "江聲六合暮，楚色萬家春。", "白苧歌西曲，黃苞寄北人。", "不知心賞後，早晚見行塵。"]'),
('e10aa405-b065-4c47-857e-335a1e41e935','題龍興寺澹師房','韓翃','唐','唐诗','tang','','[]','雙林彼上人，詩興轉相親。',48,'全唐诗/poet.tang.12000.json','["雙林彼上人，詩興轉相親。", "竹裏經聲晚，門前山色春。", "卷簾苔點淨，下筯藥苗新。", "記取無生理，歸來問此身。"]'),
('9faf1d2f-d95e-4365-8987-6209027074af','送客遊江南','韓翃','唐','唐诗','tang','','[]','南使孤帆遠，東風任意吹。',48,'全唐诗/poet.tang.12000.json','["南使孤帆遠，東風任意吹。", "楚雲殊不斷，江鳥暫相隨。", "月淨鴛鴦水，春生豆蔻枝。", "賞稱佳麗地，君去莫應知。"]'),
('1cf37fa7-e435-414d-b713-b6af827ebb54','送高員外赴淄青使幕','韓翃','唐','唐诗','tang','','[]','遠水流春色，回風送落暉。',48,'全唐诗/poet.tang.12000.json','["遠水流春色，回風送落暉。", "人趨雙節近，馬遞百花歸。", "山驛嘗官酒，關城度客衣。", "從來赤管筆，提向幕中稀。"]'),
('3fab5b68-7192-44a7-80ef-7d8d88a8bb93','尋胡處士不遇','韓翃','唐','唐诗','tang','','[]','到來心自足，不見亦相親。',48,'全唐诗/poet.tang.12000.json','["到來心自足，不見亦相親。", "說法思居士，忘機憶丈人。", "微風吹藥案，晴日照茶巾。", "幽興殊未盡，東城飛暮塵。"]'),
('4596de8d-d072-4e80-b359-a4cc9905d8e0','贈張道者','韓翃','唐','唐诗','tang','','[]','採藥三山罷，乘風五日歸。',48,'全唐诗/poet.tang.12000.json','["採藥三山罷，乘風五日歸。", "翦荷成舊屋，剉蘗染新衣。", "玉粒指應久，丹砂驗不微。", "坐看青節引，要與白雲飛。"]'),
('e55d4da1-30b7-4498-b456-650ec5ca908c','題蘇許公林亭','韓翃','唐','唐诗','tang','','[]','平津東閣在，別是竹林期。',48,'全唐诗/poet.tang.12000.json','["平津東閣在，別是竹林期。", "萬葉秋聲裏，千家落照時。", "門隨深巷靜，窗過遠鐘遲。", "客舍苔生處，依依又賦詩。"]'),
('d98b5dcd-5189-4e53-948a-9be6745b10d4','送元詵還江東','韓翃','唐','唐诗','tang','','[]','過江秋色在，詩興與歸心。',48,'全唐诗/poet.tang.12000.json','["過江秋色在，詩興與歸心。", "客路隨楓岸，人家掃橘林。", "潮聲當晝起，山翠近南深。", "幾日華陽洞，寒花引獨尋。"]'),
('d4e73e49-bf61-4ef5-a45a-60feff913a4a','送客遊江南','韓翃','唐','唐诗','tang','','[]','桂水隨去遠，賞心知有餘。',48,'全唐诗/poet.tang.12000.json','["桂水隨去遠，賞心知有餘。", "衣香楚山橘，手鱠湘波魚。", "芳芷不共把，浮雲悵離居。", "遙想汩羅上，弔屈秋風初。"]'),
('85cc7beb-8663-4cf2-9ae6-d02f2bc2035d','送海州姚別駕','韓翃','唐','唐诗','tang','','[]','少年爲長史，東去事諸侯。',48,'全唐诗/poet.tang.12000.json','["少年爲長史，東去事諸侯。", "坐覺千閭靜，閑隨五馬遊。", "行人楚國道，暮雪鬱林州。", "他日知相憶，春風海上樓。"]'),
('11b6c062-596f-467a-89ab-ac3d2e52641d','送夏侯審','韓翃','唐','唐诗','tang','','[]','謝公鄰里在，日夕問佳期。',48,'全唐诗/poet.tang.12000.json','["謝公鄰里在，日夕問佳期。", "春水人歸後，東田花盡時。", "下樓閑待月，行樂笑題詩。", "他日吳中路，千山入夢思。"]'),
('5cfb41db-b6a7-4ec1-b254-6720d26601ae','送趙評事赴洪州使幕','韓翃','唐','唐诗','tang','','[]','孤舟行遠近，一路過湘東。',48,'全唐诗/poet.tang.12000.json','["孤舟行遠近，一路過湘東。", "官屬張廷尉，身隨杜幼公。", "山河映湘竹，水驛帶青楓。", "萬里思君處，秋江夜雨中。"]'),
('2ef99529-2556-4540-b085-b892572cd861','送李侍御赴徐州行營','韓翃','唐','唐诗','tang','','[]','少年兼柱史，東至舊徐州。',48,'全唐诗/poet.tang.12000.json','["少年兼柱史，東至舊徐州。", "遠屬平津閣，前驅博望侯。", "向營淮水滿，吹角楚天秋。", "客夢依依處，寒山對白樓。"]'),
('146e6923-f487-44c2-b053-293bbb390b6a','送李秀才歸江南','韓翃','唐','唐诗','tang','','[]','過淮芳草歇，千里又東歸。',48,'全唐诗/poet.tang.12000.json','["過淮芳草歇，千里又東歸。", "野水吳山出，家林越鳥飛。", "荷香隨去棹，梅雨點行衣。", "無數滄江客，如君達者稀。"]'),
('e96257fa-e83d-4c41-96f3-b78e53831550','題僧房','韓翃','唐','唐诗','tang','','[]','披衣聞客至，關鎖此時開。',48,'全唐诗/poet.tang.12000.json','["披衣聞客至，關鎖此時開。", "鳴罄夕陽盡，捲簾秋色來。", "名香連竹徑，清梵出花臺。", "身在心無住，他方到幾回。"]'),
('20de4d54-9f65-41e9-9c59-00f87670207a','送壽州陳錄事','韓翃','唐','唐诗','tang','','[]','壽陽南渡口，斂笏見諸侯。',48,'全唐诗/poet.tang.12000.json','["壽陽南渡口，斂笏見諸侯。", "五兩楚雲暮，千家淮水秋。", "開簾對芳草，送客上春洲。", "請問山中桂，王孫幾度遊。"]'),
('e11a480e-d654-42bd-9ffb-c73a36b28441','送趙陸司兵歸使幕','韓翃','唐','唐诗','tang','','[]','客路青蕪遍，關城白日低。',48,'全唐诗/poet.tang.12000.json','["客路青蕪遍，關城白日低。", "身趨雙節近，名共五雲齊。", "遠水公田上，春山郡舍西。", "無因得攜手，東望轉悽悽。"]'),
('81e75b1d-cebd-497a-9418-ba49ea11332b','送蔣員外端公歸淮南','韓翃','唐','唐诗','tang','','[]','淮南芳草色，日夕引歸船。',48,'全唐诗/poet.tang.12000.json','["淮南芳草色，日夕引歸船。", "御史王元貺，郎官顧彥先。", "光風千日暖，寒食百花燃。", "惆悵佳期近，澄江與暮天。"]'),
('b2c3957f-77eb-42bc-a2ae-0337b317a053','題慈仁寺竹院','韓翃','唐','唐诗','tang','','[]','千峰對古寺，何異到西林。',48,'全唐诗/poet.tang.12000.json','["千峰對古寺，何異到西林。", "幽罄蟬聲下，閑窗竹翠陰。", "詩人謝客興，法侶遠公心。", "寂寂爐煙裏，香花欲暮深。"]'),
('6fdca876-c4f1-470e-8a67-870d125662d5','贈鄆州馬使君','韓翃','唐','唐诗','tang','','[]','東方千馬騎，出望使君時。',48,'全唐诗/poet.tang.12000.json','["東方千馬騎，出望使君時。", "暮雪行看盡，春城到莫遲。", "路人趨墨幘，官柳度青絲。", "他日鈴齋內，知君亦賦詩。"]'),
('e7ba668e-13bd-43f5-8957-a35b65d22a69','送張丞歸使幕','韓翃','唐','唐诗','tang','','[]','獨受主恩歸，當朝似者稀。',48,'全唐诗/poet.tang.12000.json','["獨受主恩歸，當朝似者稀。", "玉壺分御酒，金殿賜春衣。", "拂席流鶯醉，鳴鞭駿馬肥。", "滿臺簪白筆，捧手戀清暉。"]'),
('92d193cc-bb31-43b0-b068-47192b8b75ec','贈長洲何主簿','韓翃','唐','唐诗','tang','','[]','挂席逐歸流，依依望虎丘。',48,'全唐诗/poet.tang.12000.json','["挂席逐歸流，依依望虎丘。", "殘春過楚縣，夜雨宿吳洲。", "野寺吟詩入，溪橋折筍游。", "到官無一事，清靜有諸侯。"]'),
('5ad4c6b9-3f4e-4bc6-b14d-d3aed0ce3bd7','送崔過歸淄青幕府','韓翃','唐','唐诗','tang','','[]','平陵車馬客，海上見旌旗。',48,'全唐诗/poet.tang.12000.json','["平陵車馬客，海上見旌旗。", "舊驛千山下，殘花一路時。", "春衣過水冷，暮雨出關遲。", "莫道青州客，迢迢在夢思。"]'),
('aa33df0c-ba55-4d68-b66e-5dc0ca6d4dfb','田倉曹東亭夏夜飲得春字','韓翃','唐','唐诗','tang','','[]','薛公門下人，公子又相親。',48,'全唐诗/poet.tang.12000.json','["薛公門下人，公子又相親。", "玉佩迎初夜，金壺醉老春。", "葛衣香有露，羅幕靜無塵。", "更羨風流外，文章是一秦。"]'),
('b6e8b758-e69f-41c5-9aa7-a5581b95f176','贈王逖','韓翃','唐','唐诗','tang','','[]','端笏事龍樓，思閑輙告休。',48,'全唐诗/poet.tang.12000.json','["端笏事龍樓，思閑輙告休。", "新調赭白馬，暫試黑貂裘。", "珠履迎佳客，金錢與莫愁。", "座中豪貴滿，誰道不風流。"]'),
('8a1b96b6-a498-472c-95ea-db26750163f8','送深州吳司馬歸使幕','韓翃','唐','唐诗','tang','','[]','東門送遠客，車馬正紛紛。',48,'全唐诗/poet.tang.12000.json','["東門送遠客，車馬正紛紛。", "舊識張京兆，新隨劉領軍。", "行驄看暮雨，歸雁踏青雲。", "一去藂臺北，佳聲幾日聞。"]'),
('dd6ce904-eab8-49b5-b11d-59e879262177','華亭夜宴庾侍御宅','韓翃','唐','唐诗','tang','','[]','世故他年別，心期此夜同。',48,'全唐诗/poet.tang.12000.json','["世故他年別，心期此夜同。", "千峰孤燭外，片雨一更中。", "酒客逢山簡，詩人得謝公。", "自憐驅匹馬，拂曙向關東。"]'),
('7241e2c5-7d41-4cbd-86d7-9be3e63208f7','送客之上谷','韓翃','唐','唐诗','tang','','[]','北客悲秋色，田園憶去來。',48,'全唐诗/poet.tang.12000.json','["北客悲秋色，田園憶去來。", "披衣朝易水，匹馬夕燕臺。", "風翦荷花碎，霜迎栗罅開。", "賞心知不淺，累月故人杯。"]'),
('15520925-c4b7-4f94-a3dd-e79e48420c45','同中書劉舍人題青龍上房','韓翃','唐','唐诗','tang','','[]','西掖歸來後，東林靜者期。',48,'全唐诗/poet.tang.12000.json','["西掖歸來後，東林靜者期。", "遠峰春雪裏，寒竹暮天時。", "笑說金人偈，閑聽寶月詩。", "更憐茶興在，好出下方遲。"]'),
('5011f528-4984-4fd1-a7dc-bb41a033c017','宴吳王宅','韓翃','唐','唐诗','tang','','[]','玉管簫聲合，金盃酒色殷。',48,'全唐诗/poet.tang.12000.json','["玉管簫聲合，金盃酒色殷。", "聽歌吳季札，縱飲漢中山。", "稱壽爭離席，留歡輙上關。", "莫言辭客醉，猶得曳裾還。"]'),
('4bcfad28-8899-4e64-a87c-5d45a7dddd37','題薦福寺衡嶽暕師房','韓翃','唐','唐诗','tang','','[]','春城乞食還，高論此中閑。',48,'全唐诗/poet.tang.12000.json','["春城乞食還，高論此中閑。", "僧臘堦前樹，禪心江上山。", "疎簾看雪卷，深戶映花關。", "晚送門人出，鐘聲杳靄間。"]'),
('b444a852-7d07-490b-a0fd-a880e200216f','送戴廸赴鳳翔幕府','韓翃','唐','唐诗','tang','','[]','青春帶文綬，去事魏征西。',48,'全唐诗/poet.tang.12000.json','["青春帶文綬，去事魏征西。", "上路金羇出，中人玉筯齊。", "當歌酒萬斛，看獵馬千蹄。", "自有從軍樂，何須怨解攜。"]'),
('c747b1e2-2035-40be-acfa-ec1ae2d352de','送郢州郎使君','韓翃','唐','唐诗','tang','','[]','千人插羽迎，知是范宣城。',48,'全唐诗/poet.tang.12000.json','["千人插羽迎，知是范宣城。", "暮雪楚山冷，春江漢水清。", "紅鮮供客飯，翠竹引舟行。", "一別何時見，相思芳草生。"]'),
('8d94a7b3-72a6-46ff-859f-b92a2db403df','送李中丞赴辰州','韓翃','唐','唐诗','tang','','[]','白羽逐青絲，翩翩南下時。',48,'全唐诗/poet.tang.12000.json','["白羽逐青絲，翩翩南下時。", "巴人迎道路，蠻帥引旌旗。", "暮雨山開少，秋江葉落遲。", "功成益地日，應見竹郎祠。"]'),
('19a3c463-3ce0-4051-b182-578fe08cd3d9','送劉侍御赴陝州','韓翃','唐','唐诗','tang','','[]','金羈映驌驦，後騎佩干將。',48,'全唐诗/poet.tang.12000.json','["金羈映驌驦，後騎佩干將。", "把酒春城晚，鳴鞭曉路長。", "帶冰新溜澀，間雪早梅香。", "明日懷賢處，依依御史牀。"]'),
('c099d08d-a94e-43e2-9d4c-ed3718f6c64b','李中丞宅夜宴送丘侍御赴江東便往辰州','韓翃','唐','唐诗','tang','','[]','積雪臨階夜，重裘對酒時。',48,'全唐诗/poet.tang.12000.json','["積雪臨階夜，重裘對酒時。", "中丞違沈約，才子送丘遲。", "一路三江上，孤舟萬里期。", "辰州佳興在，他日寄新詩。"]'),
('0186b0f2-2b80-4b51-a488-dd8d9d3733d4','送李侍御歸宣州使幕','韓翃','唐','唐诗','tang','','[]','春草東江外，翩翩北路歸。',48,'全唐诗/poet.tang.12000.json','["春草東江外，翩翩北路歸。", "官齊魏公子，身逐謝玄暉。", "山色隨行騎，鶯聲傍客衣。", "主人池上酌，攜手暮花飛。"]'),
('6e2768c1-3384-4c56-b865-dc2ab0e03210','東城水亭宴李侍御副使','韓翃','唐','唐诗','tang','','[]','東門留客處，沽酒用錢刀。',48,'全唐诗/poet.tang.12000.json','["東門留客處，沽酒用錢刀。", "秋水牀下急，斜暉林外高。", "金羇絡騕褭，玉匣閉豪曹。", "去日隨戎幕，東風見伯勞。"]'),
('d2dac645-ea92-432b-bc76-6656f5515a94','送祕書謝監赴江西使幕','韓翃','唐','唐诗','tang','','[]','謝監憶山程，辭家萬里行。',48,'全唐诗/poet.tang.12000.json','["謝監憶山程，辭家萬里行。", "寒衣傍楚色，孤枕宿潮聲。", "小寇不足問，新詩應漸清。", "府公相待日，引斾出江城。"]'),
('4fb425e3-3a20-479a-b171-f4cc68a1825e','送江陵元司錄','韓翃','唐','唐诗','tang','','[]','新領州從事，曾爲朝大夫。',48,'全唐诗/poet.tang.12000.json','["新領州從事，曾爲朝大夫。", "江城竹使待，山路橘官扶。", "片雨三江道，殘秋五葉湖。", "能令詩思好，楚色與寒蕪。"]'),
('71a22c58-646f-4873-b4c2-37882778875b','送李舍人攜家歸江東覲省','韓翃','唐','唐诗','tang','','[]','二十青宮吏，成名似者稀。',48,'全唐诗/poet.tang.12000.json','["二十青宮吏，成名似者稀。", "承顏陸郎去，攜手謝娘歸。", "夜月回孤燭，秋風試夾衣。", "扁舟楚水上，來往速如飛。"]'),
('ed4a9d77-5c29-469c-8165-6ea61fd94f1a','送劉侍御赴令公行營','韓翃','唐','唐诗','tang','','[]','東城躍紫騮，西路大刀頭。',48,'全唐诗/poet.tang.12000.json','["東城躍紫騮，西路大刀頭。", "上客劉公幹，元戎郭細侯。", "一軍偏許國，百戰又防秋。", "請問蕭關道，胡塵早晚收。"]'),
('30dafbe3-d073-47c6-8162-f13c61e9676d','送蘇州姚長史','韓翃','唐','唐诗','tang','','[]','江城驛路長，煙樹過雲陽。',48,'全唐诗/poet.tang.12000.json','["江城驛路長，煙樹過雲陽。", "舟領青絲纜，人歌白玉郎。", "葛衣行柳翠，花簟宿荷香。", "別有心期處，湖光滿訟堂。"]'),
('37fad560-b78b-470a-99c6-a557958d0b3c','送金華王明府','韓翃','唐','唐诗','tang','','[]','縣舍江雲裏，心閑境又偏。',48,'全唐诗/poet.tang.12000.json','["縣舍江雲裏，心閑境又偏。", "家貧陶令酒，月俸沈郎錢。", "黃蘗香山路，青楓暮雨天。", "時聞引車騎，竹外到銅泉。"]'),
('ba3767e8-52a3-4a53-a56a-7f5dd77dee68','送田倉曹汴州覲省','韓翃','唐','唐诗','tang','','[]','拜慶承天寵，朝來辭漢宮。',48,'全唐诗/poet.tang.12000.json','["拜慶承天寵，朝來辭漢宮。", "玉杯分湛露，金勒借追風。", "古驛秋山下，平蕪暮雨中。", "翩翩魏公子，人看渡關東。"]'),
('2da8b3fa-3e96-4b18-b529-24422f24f4ef','送張渚赴越州','韓翃','唐','唐诗','tang','','[]','白面誰家郎，青驪照地光。',48,'全唐诗/poet.tang.12000.json','["白面誰家郎，青驪照地光。", "桃花開綬色，蘇合借衣香。", "暮雪連峰近，春江海市長。", "風流似張緒，別後見垂楊。"]'),
('0d11d2ba-6ffb-4f62-92f5-6e8e9b099e97','奉和元相公家園即事寄王相公','韓翃','唐','唐诗','tang','','[]','共列中台貴，能齊物外心。',48,'全唐诗/poet.tang.12000.json','["共列中台貴，能齊物外心。", "回車青閣晚，解帶碧茸深。", "寒水分畦入，晴花度竹尋。", "題詩更相憶，一字重千金。"]'),
('27deddfa-8ab0-426b-b849-b55405959d5b','送道士姪歸池陽','韓翃','唐','唐诗','tang','','[]','銀角桃枝杖，東門贈別初。',48,'全唐诗/poet.tang.12000.json','["銀角桃枝杖，東門贈別初。", "幽州尋馬客，灞岸送驢車。", "野飯秋山靜，行衣落照餘。", "燕南羣從少，此去意何如。"]'),
('04d20df6-acac-4dcb-a54b-1be98c4e740e','送劉長上歸城南別業','韓翃','唐','唐诗','tang','','[]','數刻是歸程，花間落照明。',48,'全唐诗/poet.tang.12000.json','["數刻是歸程，花間落照明。", "春衣香不散，駿馬汗猶輕。", "南渡春流淺，西風片雨晴。", "朝還會相就，飯爾五侯鯖。"]'),
('13221990-df4d-4102-a1d6-381d15d089f8','贈張五諲歸濠州別業','韓翃','唐','唐诗','tang','','[]','常知罷官意，果與世人疎。',48,'全唐诗/poet.tang.12000.json','["常知罷官意，果與世人疎。", "復此涼風起，仍聞濠上居。", "故山期採菊，秋水憶觀魚。", "一去蓬蒿逕，羨君閑有餘。"]'),
('f03a16fb-dbb5-438e-994b-c51f89e1efbb','送營城李少府','韓翃','唐','唐诗','tang','','[]','懷錄兼就養，更懷趨府心。',48,'全唐诗/poet.tang.12000.json','["懷錄兼就養，更懷趨府心。", "晴山東里近，春水北門深。", "新綬映芳草，舊家依遠林。", "還乘鄭小駟，躞蹀縣城陰。"]'),
('b26ec135-4929-4076-a792-be57d748e820','魯中送魯使君歸鄭州','韓翃','唐','唐诗','tang','','[]','城中金絡騎，出餞沈東陽。',48,'全唐诗/poet.tang.12000.json','["城中金絡騎，出餞沈東陽。", "九月寒露白，六關秋草黃。", "齊謳聽處妙，魯酒把來香。", "醉後著鞭去，梅山道路長。"]'),
('59c50aa1-116c-4c99-bad7-83468ccd958a','送夏侯校書歸上都','韓翃','唐','唐诗','tang','','[]','後輩傳佳句，高流愛美名。',48,'全唐诗/poet.tang.12000.json','["後輩傳佳句，高流愛美名。", "青春事賀監，黃卷問張生。", "暮雪重裘醉，寒山匹馬行。", "此回將詣闕，幾日諫書成。"]'),
('a36d2096-432b-4a13-8527-0110a781f74f','送李明府赴連州','韓翃','唐','唐诗','tang','','[]','萬里向南湘，孤舟入桂陽。',48,'全唐诗/poet.tang.12000.json','["萬里向南湘，孤舟入桂陽。", "諸侯迎上客，小吏拜官郎。", "春服橦花細，初筵木槿芳。", "看承雨露速，不待荔枝香。"]'),
('3318ab7f-2f67-47df-af04-a611064d22bb','送盧大理趙侍御祭東嶽兼寄孟衮州','韓翃','唐','唐诗','tang','','["\u6cf0\u5c71"]','東嶽昔有事，兩臣朝望歸。',48,'全唐诗/poet.tang.12000.json','["東嶽昔有事，兩臣朝望歸。", "驛亭開歲酒，齋舍著新衣。", "上客鍾大理，主人陶武威。", "仍隨御史馬，山路滿光輝。"]'),
('afa6753b-8bdb-4e63-a41c-88a0f9294c6a','送皇甫大夫赴浙東','韓翃','唐','唐诗','tang','','[]','舟師分水國，漢將領秦官。',48,'全唐诗/poet.tang.12000.json','["舟師分水國，漢將領秦官。", "麾下同心吏，軍中囗囗端。", "吳門秋露溼，楚驛暮天寒。", "豪貴東山去，風流勝謝安。"]'),
('8d420df8-bf77-44be-9254-8b514a4f6b9b','送韋秀才','韓翃','唐','唐诗','tang','','[]','東人相見罷，秋草獨歸時。',48,'全唐诗/poet.tang.12000.json','["東人相見罷，秋草獨歸時。", "幾日孫弘閣，當年謝朓詩。", "寒山葉落早，多雨路行遲。", "好憶金門步，功名自有期。"]'),
('7a3afe60-f683-4e4f-a11d-ecfd38c7dc98','送客一歸襄陽二歸潯陽','韓翃','唐','唐诗','tang','','[]','南驅匹馬會心期，東望扁舟愜夢思。',64,'全唐诗/poet.tang.12000.json','["南驅匹馬會心期，東望扁舟愜夢思。", "熨斗山前春色早，香爐峰頂暮煙時。", "空林欲訪龐居士，古寺應懷遠法師。", "兩地由來堪取興，三賢他日幸留詩。"]'),
('d31a6edd-8609-47c6-9973-7f5c5fbb3eb7','送故人赴江陵尋庾牧','韓翃','唐','唐诗','tang','','[]','主人持節拜荆州，走馬應從一路遊。',64,'全唐诗/poet.tang.12000.json','["主人持節拜荆州，走馬應從一路遊。", "斑竹岡連山雨暗，枇杷門向楚天秋。", "佳期笑把齋中酒，遠意閑登城上樓。", "文體此時看又別，吾知小庾甚風流。"]'),
('01a80b15-c6bc-4315-8dbc-fd2285f8b4aa','送客水路歸陝','韓翃','唐','唐诗','tang','','[]','相風竿影曉來斜，渭水東流去不賒。',64,'全唐诗/poet.tang.12000.json','["相風竿影曉來斜，渭水東流去不賒。", "枕上未醒秦地酒，舟前已見陝人家。", "春橋楊柳應齊葉，古縣棠棃也作花。", "好是吾賢佳賞地，行逢三月會連沙。"]'),
('64523283-a09b-490b-ae50-f88023ecff9e','送丹陽劉太真','韓翃','唐','唐诗','tang','','[]','長干道上落花朝，羨爾當年賞事饒。',64,'全唐诗/poet.tang.12000.json','["長干道上落花朝，羨爾當年賞事饒。", "下筯已憐鵝炙美，開籠不奈鴨媒嬌。", "春衣晚入青楊巷，細馬初過皂莢橋。", "相訪不辭千里遠，西風好借木蘭橈。"]'),
('f7641ad3-b54a-476a-a72a-097328b264c1','送客歸江州','韓翃','唐','唐诗','tang','','[]','東歸復得采真遊，江水迎君日夜流。',64,'全唐诗/poet.tang.12000.json','["東歸復得采真遊，江水迎君日夜流。", "客舍不離青雀舫，人家舊在白鷗洲。", "風吹山帶遙知雨，露溼荷裳已報秋。", "聞道泉明居止近，籃輿相訪爲淹留。"]'),
('2a4a17b2-9471-40ba-ab49-1b83297af8a8','題張逸人園林','韓翃','唐','唐诗','tang','','[]','花源一曲映茅堂，清論閑階坐夕陽。',64,'全唐诗/poet.tang.12000.json','["花源一曲映茅堂，清論閑階坐夕陽。", "麈尾手中毛已脫，蟹螯尊上味初香。", "春深黃口傳窺樹，雨後青苔散點牆。", "更道小山宜助賞，呼兒舒簟醉巖芳。"]'),
('f2203760-0a7a-4392-8da7-159116242be4','又題張逸人園林','韓翃','唐','唐诗','tang','','[]','藏頭不復見時人，愛此雲山奉養真。',64,'全唐诗/poet.tang.12000.json','["藏頭不復見時人，愛此雲山奉養真。", "露色點衣孤嶼曉，花枝妨帽小園春。", "時攜幼稚諸峰上，閑濯眉須一水濱。", "興罷歸來還對酌，茅檐挂著紫荷巾。"]'),
('12aea2eb-9568-42b6-860d-24b40fb86825','送劉將軍','韓翃','唐','唐诗','tang','','[]','明光細甲照錏鍛，昨日承恩拜虎牙。',64,'全唐诗/poet.tang.12000.json','["明光細甲照錏鍛，昨日承恩拜虎牙。", "膽大欲期姜伯約，功多不讓李輕車。", "青巾校尉遙相許，墨矟將軍莫大誇。", "闕下來時親伏奏，胡塵未盡不爲家。"]'),
('eeea4c43-7ada-46ae-81a9-ad4975aec522','送鄭員外','韓翃','唐','唐诗','tang','','[]','風流不減杜陵時，五十爲郎未是遲。',64,'全唐诗/poet.tang.12000.json','["風流不減杜陵時，五十爲郎未是遲。", "孺子亦知名下士，樂人爭唱卷中詩。", "身齊吏部還多醉，心顧尚書自有期。", "要路眼青知己在，不應窮巷久低眉。"]'),
('af2e4d75-735e-4f63-a81e-b1b9915d2c2c','寄徐州鄭使君','韓翃','唐','唐诗','tang','','[]','江城五馬楚雲邊，不羨雍容畫省年。',64,'全唐诗/poet.tang.12000.json','["江城五馬楚雲邊，不羨雍容畫省年。", "才子舊稱何水部，使君還繼謝臨川。", "射堂草遍收殘雨，官路人稀對夕天。", "雖臥郡齋千里隔，與君同見月初圓。"]'),
('dbb1cb69-0620-43f0-ba72-ea57020358d9','送襄垣王君歸南陽別墅','韓翃','唐','唐诗','tang','','[]','都門霽後不飛塵，草色萋萋滿路春。',64,'全唐诗/poet.tang.12000.json','["都門霽後不飛塵，草色萋萋滿路春。", "雙兔坡東千室吏，三鴉水上一歸人。", "愁眠客舍衣香滿，走渡河橋馬汗新。", "少婦比來多遠望，應知蟢子上羅巾。"]'),
('63f3c6dc-30dc-4c1f-98ac-744cfaf96abf','送王誕渤海使赴李太守行營','韓翃','唐','唐诗','tang','','[]','少年結客散黃金，中歲連兵掃綠林。',64,'全唐诗/poet.tang.12000.json','["少年結客散黃金，中歲連兵掃綠林。", "渤海名王曾折首，漢家諸將盡傾心。", "行人去指徐州近，飲馬回看泗水深。", "喜見明時鍾太尉，功名一似舊淮陰。"]'),
('174be7d0-c5ca-4f82-8e5f-1e08cac85403','送王少府歸杭州','韓翃','唐','唐诗','tang','','[]','歸舟一路轉青蘋，更欲隨潮向富春。',64,'全唐诗/poet.tang.12000.json','["歸舟一路轉青蘋，更欲隨潮向富春。", "吳郡陸機稱地主，錢塘蘇小是鄉親。", "葛花滿把能消酒，梔子同心好贈人。", "早晚重過魚浦宿，遙憐佳句篋中新。"]'),
('367c97eb-901c-4688-ab45-2ee634454c0a','贈王隨','韓翃','唐','唐诗','tang','','[]','青雲自致晚應遙，朱邸新婚樂事饒。',64,'全唐诗/poet.tang.12000.json','["青雲自致晚應遙，朱邸新婚樂事饒。", "飲罷更憐雙袖舞，試來偏愛五花驕。", "帳裏爐香春夢曉，堂前燭影早更朝。", "更說毬場新雨歇，王孫今日定相邀。"]'),
('b411ce1e-ac09-4427-ab32-f8dc7a57e566','同題仙游觀','韓翃','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5411\u5f80", "\u4e03\u8a00\u5f8b\u8bd7", "\u6e38\u5386"]','仙臺下見五城樓，風物淒淒宿雨收。',64,'全唐诗/poet.tang.12000.json','["仙臺下見五城樓，風物淒淒宿雨收。", "山色遙連秦樹晚，砧聲近報漢宮秋。", "疎松影落空壇靜，細草香閑小洞幽。", "何用別尋方外去，人間亦自有丹丘。"]'),
('a3e8a1e0-aa8d-488f-86e9-7957ba5e46cd','訪王起居不遇留贈','韓翃','唐','唐诗','tang','','[]','雙龍闕下拜恩初，天子令君注起居。',64,'全唐诗/poet.tang.12000.json','["雙龍闕下拜恩初，天子令君注起居。", "載筆已齊周右史，論詩更事謝中書。", "行聞漏滴隨金仗，入對爐煙侍玉除。", "賀客自知來獨晚，青驪不見意何如。"]'),
('0205d533-59d4-4fb4-a9e1-f447f6de1134','送劉評事赴廣州使幕','韓翃','唐','唐诗','tang','','[]','征南官屬似君稀，才子當今劉孝威。',64,'全唐诗/poet.tang.12000.json','["征南官屬似君稀，才子當今劉孝威。", "蠻府參軍趨傳舍，交州刺史拜行衣。", "前臨瘴海無人過，却望衡陽少雁飛。", "爲報蒼梧雲影道，明年早送客帆歸。"]'),
('a3ed689f-6083-4041-b4d2-8f294506ee0c','送冷朝陽還上元','韓翃','唐','唐诗','tang','','[]','青絲䋏引木蘭船，名遂身歸拜慶年。',64,'全唐诗/poet.tang.12000.json','["青絲䋏引木蘭船，名遂身歸拜慶年。", "落日澄江烏榜外，秋風疎柳白門前。", "橋通小市家林近，山帶平湖野寺連。", "別後依依寒食裏，共君攜手在東田。"]'),
('00877f47-5209-41c9-b25c-2c0ba2caf637','送高別駕歸汴州','韓翃','唐','唐诗','tang','','[]','信陵門下識君偏，駿馬輕裘正少年。',64,'全唐诗/poet.tang.12000.json','["信陵門下識君偏，駿馬輕裘正少年。", "寒雨送歸千里外，東風沈醉百花前。", "身隨玉帳心應愜，官佐龍符勢又全。", "久客未知何計是，參差去借汶陽田。"]'),
('301b1228-db1f-47f2-9425-a732c65ef0ad','送康洗馬歸滑州','韓翃','唐','唐诗','tang','','[]','腰佩雕弓漢射聲，東歸銜命見雙旌。',64,'全唐诗/poet.tang.12000.json','["腰佩雕弓漢射聲，東歸銜命見雙旌。", "青絲玉勒康侯馬，孟水金堤滑伯城。", "臘雪夜看宜縱飲，寒蕪晝獵不妨行。", "懷君又隔千山遠，別後春風百草生。"]'),
('17fb8726-a553-4a26-bd21-7a344ae6c902','寄上田僕射','韓翃','唐','唐诗','tang','','[]','家封薛縣異諸田，報主榮親義兩全。',64,'全唐诗/poet.tang.12000.json','["家封薛縣異諸田，報主榮親義兩全。", "僕射臨戎謝安石，大夫持憲杜延年。", "金裝晝出羅千騎，玉案晨飡直萬錢。", "應念一身留闕下，闔門遙寄魯西偏。"]'),
('bafe4ffc-feca-4394-848c-a3b06d7bbdda','送王光輔歸青州兼寄儲侍郎','韓翃','唐','唐诗','tang','','[]','幾回奏事建章宮，聖主偏知漢將功。',64,'全唐诗/poet.tang.12000.json','["幾回奏事建章宮，聖主偏知漢將功。", "身著紫衣趨闕下，口銜丹詔出關東。", "蟬聲驛路秋山裏，草色河橋落照中。", "遠憶故人滄海別，當年好躍五花驄。"]'),
('b7029b05-dbc0-4c17-84b9-3582767b67ba','宴楊駙馬山池','韓翃','唐','唐诗','tang','','[]','垂楊拂岸草茸茸，繡戶簾前花影重。',64,'全唐诗/poet.tang.12000.json','["垂楊拂岸草茸茸，繡戶簾前花影重。", "鱠下玉盤紅縷細，酒開金甕綠醅濃。", "中朝駙馬何平叔，南國詞人陸士龍。", "落日泛舟同醉處，回潭百丈映千峰。"]'),
('7d22c6b8-dc91-46dd-bfe3-8fbbec90b121','送長史李少府入蜀','韓翃','唐','唐诗','tang','','[]','行行獨出故關遲，南望千山無盡期。',64,'全唐诗/poet.tang.12000.json','["行行獨出故關遲，南望千山無盡期。", "見舞巴童應暫笑，聞歌蜀道又堪悲。", "孤城晚閉清江上，匹馬寒嘶白露時。", "別後此心君自見，山中何事不相思。"]'),
('e388e44d-dfde-4c11-a146-5de448497720','送客還江東','韓翃','唐','唐诗','tang','','[]','不妨高臥順流歸，五兩行看掃翠微。',64,'全唐诗/poet.tang.12000.json','["不妨高臥順流歸，五兩行看掃翠微。", "鼯鼠夜喧孤枕近，鵁鶄曉避客船飛。", "一壺先醉桃枝簟，百和初熏苧布衣。", "君到新林江口泊，吟詩應賞謝玄暉。"]'),
('ac9a971b-9802-4303-a76d-fafaa49563df','寄令狐尚書','韓翃','唐','唐诗','tang','','[]','立身榮貴復何如，龍節紅旗從板輿。',64,'全唐诗/poet.tang.12000.json','["立身榮貴復何如，龍節紅旗從板輿。", "妙略多推霍驃騎，能文獨見沈尚書。", "臨風高會千門帳，映水連營百乘車。", "他日感恩慙未報，舉家猶似涸池魚。"]'),
('2a68c6d1-adc3-4c46-aaf0-4a199170c382','扈從郊廟因呈兩省諸公','韓翃','唐','唐诗','tang','','[]','丹墀列士主恩同，廄馬翩翩出漢宮。',64,'全唐诗/poet.tang.12000.json','["丹墀列士主恩同，廄馬翩翩出漢宮。", "奉引乘輿金仗裏，親嘗賜食玉盤中。", "晝趨行殿旌門北，夜宿齋房刻漏東。", "明日駕迴承雨露，齊將萬歲及春風。"]'),
('0bf15138-71d8-4a73-8b8e-d9c7654c9e80','送端州馮使君','韓翃','唐','唐诗','tang','','[]','白皙風流似有鬚，一門豪貴領蒼梧。',64,'全唐诗/poet.tang.12000.json','["白皙風流似有鬚，一門豪貴領蒼梧。", "三峰亭暗橘邊宿，八桂林香節下趨。", "玉樹羣兒爭翠羽，金盤少妾揀明珠。", "懷君樂事不可見，騣馬翩翩新虎符。"]'),
('3ca0e586-2804-4c73-9190-1ccc18267e00','送王府張參軍附學及第東歸','韓翃','唐','唐诗','tang','','[]','鄰家不識鬬雞翁，閉戶能齊隱者風。',64,'全唐诗/poet.tang.12000.json','["鄰家不識鬬雞翁，閉戶能齊隱者風。", "顧步曾爲小山客，成名因事大江公。", "一身千里寒蕪上，單馬重裘臘月中。", "寂寂故園行見在，暮天殘雪洛城東。"]'),
('aea75aac-91ff-4299-8d32-43ef9da2b346','送齊明府赴東陽','韓翃','唐','唐诗','tang','','[]','綠絲帆繂桂爲檣，過盡淮山楚水長。',64,'全唐诗/poet.tang.12000.json','["綠絲帆繂桂爲檣，過盡淮山楚水長。", "萬里移家背春穀，一官行府向東陽。", "風流好愛杯中物，豪蕩仍欺陌上郎。", "別後心期如在眼，猨聲煙色樹蒼蒼。"]'),
('880aa6dd-56a3-4432-9d27-f77f724ef37d','魯中送從事歸滎陽','韓翃','唐','唐诗','tang','','[]','故園衰草帶滎波，歲晚知如君思何。',64,'全唐诗/poet.tang.12000.json','["故園衰草帶滎波，歲晚知如君思何。", "輕橐歸時魯縞薄，寒衣縫處鄭綿多。", "萬人都督鳴騮送，百里邦君枉騎過。", "累路盡逢知己在，曾無對酒不高歌。"]'),
('9c9db622-4daa-499a-81d6-d991e2b426cd','衮州送李明府使蘇州便赴告期','韓翃','唐','唐诗','tang','','[]','莫言水國去迢迢，白馬吳門見不遙。',64,'全唐诗/poet.tang.12000.json','["莫言水國去迢迢，白馬吳門見不遙。", "楓樹林中經楚雨，木蘭舟上蹋江潮。", "空山古寺千年石，草色寒隄百尺橋。", "早晚盧家蘭室在，珊瑚玉佩徹青霄。"]'),
('cf9d968d-510c-4646-8bf6-7844b70a18fb','送田明府歸終南別業','韓翃','唐','唐诗','tang','','[]','故園此日多心賞，窗下泉流竹外雲。',64,'全唐诗/poet.tang.12000.json','["故園此日多心賞，窗下泉流竹外雲。", "近館應逢沈道士，比鄰自識卞田君。", "離宮樹影登山見，上苑鐘聲過雪聞。", "相勸早移丹鳳闕，不須常戀白鷗羣。"]'),
('866044e3-2a37-485d-aca7-3de867948317','家兄自山南罷歸獻詩敘事','韓翃','唐','唐诗','tang','','[]','時輩已爭先，吾兄未著鞭。',240,'全唐诗/poet.tang.12000.json','["時輩已爭先，吾兄未著鞭。", "空嗟鑷鬚日，猶是屈腰年。", "不以殊方遠，仍論水地偏。", "襄橙隨客路，漢竹引歸船。", "雲木巴東峽，林泉峴北川。", "池餘騎馬處，宅似臥龍邊。", "夜簟千峰月，朝窗萬井煙。", "朱荷江女院，青稻楚人田。", "縣舍多瀟灑，城樓入醉眠。", "黃苞柑正熟，紅縷鱠仍鮮。", "坐厭牽絲倦，因從解綬旋。", "初辭五斗米，唯奉一囊錢。", "室好生虛白，書耽守太玄。", "櫪中嘶欵段，階下引潺湲。", "落照淵明柳，春風叔夜弦。", "絳紗儒客帳，丹訣羽人篇。", "雅論承安石，新詩與惠連。", "興清湖見底，襟豁霧開天。", "魏闕心猶繫，周才道豈捐。", "一丘無自逸，三府會招賢。"]'),
('362e5391-9347-48d7-a42a-35efebb88ba3','奉送王相公縉赴幽州巡邊','韓翃','唐','唐诗','tang','','[]','黃閣開帷幄，丹墀侍冕旒。',72,'全唐诗/poet.tang.12000.json','["黃閣開帷幄，丹墀侍冕旒。", "位高湯左相，權總漢諸侯。", "不改周南化，仍分趙北憂。", "雙旌過易水，千騎入幽州。", "塞草連天暮，邊風動地秋。", "無因隨遠道，結束佩吳鉤。"]'),
('27400495-0bfe-4223-a30b-a6c4a1ef4816','寄贈虢州張參軍','韓翃','唐','唐诗','tang','','[]','三十事諸侯，賢豪冠北州。',144,'全唐诗/poet.tang.12000.json','["三十事諸侯，賢豪冠北州。", "桃花迎駿馬，蘇合染輕裘。", "觀妓將軍第，題詩關尹樓。", "青林朝送客，綠嶼晚回舟。", "好栗分通子，名香贈莫愁。", "洗杯新酒熟，把燭故人留。", "百雉歸雲過，千峰宿雨收。", "蒹葭露下晚，菡萏水中秋。", "憶昨陪行樂，常時接獻酬。", "佳期雖霧散，惠問亦川流。", "開卷酲堪解，含毫思苦抽。", "無因達情意，西望日悠悠。"]'),
('0c45227f-c9a5-403e-a742-01a617a66ce2','送李中丞赴商州','韓翃','唐','唐诗','tang','','[]','五馬渭橋東，連嘶逐曉風。',72,'全唐诗/poet.tang.12000.json','["五馬渭橋東，連嘶逐曉風。", "當年紫髯將，他日黑頭公。", "不異金吾寵，兼齊玉帳雄。", "閉營春雪下，吹角暮山空。", "香麝松陰裏，寒猨黛色中。", "郡齋多賞事，好與故人同。"]'),
('cd5b7b5d-6e30-449b-a44a-be293eb76a9d','漢宮曲二首 一','韓翃','唐','唐诗','tang','','[]','駿馬繡障泥，紅塵撲四蹄。',24,'全唐诗/poet.tang.12000.json','["駿馬繡障泥，紅塵撲四蹄。", "歸時何太晚，日照杏花西。"]'),
('794686a6-fc91-4d55-a50d-dfeda75dc75b','漢宮曲二首 二','韓翃','唐','唐诗','tang','','[]','繡幕珊瑚鉤，春開翡翠樓。',24,'全唐诗/poet.tang.12000.json','["繡幕珊瑚鉤，春開翡翠樓。", "深情不肯道，嬌倚鈿箜篌。"]'),
('ceae777e-f781-4d5a-ab55-33cd1a42effa','陪孟都督祭嶽途中有贈','韓翃','唐','唐诗','tang','','[]','封疆七百里，祿秩二千石。',24,'全唐诗/poet.tang.12000.json','["封疆七百里，祿秩二千石。", "擁節祠太山，寒天霜草白。"]'),
('d1a3295b-4d6e-40f6-99c6-ea38df448c9b','宿甑山','韓翃','唐','唐诗','tang','','[]','山中今夜何人，闕下當年近臣。',28,'全唐诗/poet.tang.12000.json','["山中今夜何人，闕下當年近臣。", "青瑣應須早去，白雲何用相親。"]'),
('1abbe7d9-55cc-4f8c-9f81-e2e402a10900','別甑山','韓翃','唐','唐诗','tang','','[]','一身趨侍丹墀，西路翩翩去時。',28,'全唐诗/poet.tang.12000.json','["一身趨侍丹墀，西路翩翩去時。", "惆悵青山綠水，何年更是來期。"]'),
('6688025a-ec4e-4857-997f-de52f7f13346','送陳明府赴淮南','韓翃','唐','唐诗','tang','','[]','年華近逼清明，落日微風送行。',56,'全唐诗/poet.tang.12000.json','["年華近逼清明，落日微風送行。", "黃鳥綿蠻芳樹，紫騮躞蹀東城。", "花間一杯促膝，煙外千里含情。", "應渡淮南信宿，諸侯擁斾相迎。"]'),
('e169bdee-e544-4a38-b659-f3acb51b9df6','送客知鄂州','韓翃','唐','唐诗','tang','','[]','江口千家帶楚雲，江花亂點雪紛紛。',32,'全唐诗/poet.tang.12000.json','["江口千家帶楚雲，江花亂點雪紛紛。", "春風落日誰相見，青翰舟中有鄂君。"]'),
('77ac62ee-6396-4ac0-a3ab-cb84ba2e5cd0','寒食','韓翃','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6e05\u660e", "\u5bd2\u98df\u8282", "\u5178\u6545", "\u4e03\u8a00\u7edd\u53e5", "\u8bbd\u523a"]','春城無處不飛花，寒食東風御柳斜。',32,'全唐诗/poet.tang.12000.json','["春城無處不飛花，寒食東風御柳斜。", "日暮漢宮傳蠟燭，輕煙散入五侯家。"]'),
('41a1a003-673c-461e-800c-5520dcad7400','羽林騎','韓翃','唐','唐诗','tang','','[]','駿馬牽來御柳中，鳴鞭欲向渭橋東。',32,'全唐诗/poet.tang.12000.json','["駿馬牽來御柳中，鳴鞭欲向渭橋東。", "紅蹄亂蹋春城雪，花頷驕嘶上苑風。"]'),
('976e4304-0924-4e80-9c5c-60c6646a9705','看調馬','韓翃','唐','唐诗','tang','','[]','鴛鴦赭白齒新齊，晚日花中散碧蹄。',32,'全唐诗/poet.tang.12000.json','["鴛鴦赭白齒新齊，晚日花中散碧蹄。", "玉勒斗回初噴沫，金鞭欲下不成嘶。"]'),
('394d5a0d-3970-4d74-a541-2d7f2aaa4f60','寄贈衡州楊使君','韓翃','唐','唐诗','tang','','[]','湘竹斑斑湘水春，衡陽太守虎符新。',32,'全唐诗/poet.tang.12000.json','["湘竹斑斑湘水春，衡陽太守虎符新。", "朝來笑向歸鴻道，早晚南飛見主人。"]'),
('575b9318-2d52-480d-8b79-4203109700fb','宿石邑山中','韓翃','唐','唐诗','tang','','["\u5199\u5c71", "\u5199\u666f", "\u63cf\u5199\u5c71"]','浮雲不共此山齊，山靄蒼蒼望轉迷。',32,'全唐诗/poet.tang.12000.json','["浮雲不共此山齊，山靄蒼蒼望轉迷。", "曉月暫飛高樹裏，秋河隔在數峰西。"]'),
('084a7bf6-dfe9-4f11-99b2-55ce23b21fa9','江南曲','韓翃','唐','唐诗','tang','','[]','長樂花枝雨點銷，江城日暮好相邀。',32,'全唐诗/poet.tang.12000.json','["長樂花枝雨點銷，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回通宛轉橋。"]'),
('d63caf47-6edc-46d4-b5b8-cacede26dc50','贈張千牛','韓翃','唐','唐诗','tang','','[]','蓬萊闕下是天家，上路新回白鼻騧。',32,'全唐诗/poet.tang.12000.json','["蓬萊闕下是天家，上路新回白鼻騧。", "急管晝催平樂酒，春衣夜宿杜陵花。"]'),
('6fc6b384-e4bf-4bc9-8d65-33804cc1ae82','漢宮曲二首 一','韓翃','唐','唐诗','tang','','[]','五柞宮中過臘看，萬年枝上雪花殘。',32,'全唐诗/poet.tang.12000.json','["五柞宮中過臘看，萬年枝上雪花殘。", "綺窗夜閉玉堂靜，素綆朝穿金井寒。"]'),
('041dffad-e61e-47eb-9aae-31b5150784a0','漢宮曲二首 二','韓翃','唐','唐诗','tang','','[]','家在長陵小市中，珠簾繡戶對春風。',32,'全唐诗/poet.tang.12000.json','["家在長陵小市中，珠簾繡戶對春風。", "君王昨日移仙仗，玉輦迎將入漢宮。"]'),
('ac7e882c-576b-479f-bc7b-88aa5b00fed6','贈李翼','韓翃','唐','唐诗','tang','','[]','王孫別舍擁朱輪，不羨空名樂此身。',32,'全唐诗/poet.tang.12000.json','["王孫別舍擁朱輪，不羨空名樂此身。", "門外碧潭春洗馬，樓前紅燭夜迎人。"]'),
('c3e790d3-91fa-4575-89d1-0cdd3701bb5c','少年行','韓翃','唐','唐诗','tang','','[]','千點斕斒玉勒驄，青絲結尾繡纏騣。',32,'全唐诗/poet.tang.12000.json','["千點斕斒玉勒驄，青絲結尾繡纏騣。", "鳴鞭曉出章臺路，葉葉春衣楊柳風。"]'),
('85c8567d-7db9-4c84-8352-86f530b1de88','題玉真觀李祕書院','韓翃','唐','唐诗','tang','','[]','白雲斜日影深松，玉宇瑤壇知幾重。',32,'全唐诗/poet.tang.12000.json','["白雲斜日影深松，玉宇瑤壇知幾重。", "把酒題詩人散後，華陽洞裏有疎鐘。"]'),
('9220d0e0-b30f-4186-8d35-945cdd49c036','送客之潞府','韓翃','唐','唐诗','tang','','[]','官柳青青匹馬嘶，迴風暮雨入銅鞮。',32,'全唐诗/poet.tang.12000.json','["官柳青青匹馬嘶，迴風暮雨入銅鞮。", "佳期別在春山裏，應是人蓡五葉齊。"]'),
('dc554577-3009-4589-9e39-f06493a654a3','送客貶五溪','韓翃','唐','唐诗','tang','','[]','南過猨聲一逐臣，回看秋草淚霑巾。',32,'全唐诗/poet.tang.12000.json','["南過猨聲一逐臣，回看秋草淚霑巾。", "寒天暮雪空山裏，幾處蠻家是主人。"]'),
('a5cc1b29-4977-48c0-92eb-a08063abf06b','送齊山人歸長白山','韓翃','唐','唐诗','tang','','[]','舊事仙人白兔公，掉頭歸去又乘風。',32,'全唐诗/poet.tang.12000.json','["舊事仙人白兔公，掉頭歸去又乘風。", "柴門流水依然在，一路寒山萬木中。"]'),
('fdc1bcb7-09a3-47fe-a04f-05a8543a0086','寄裴鄆州','韓翃','唐','唐诗','tang','','[]','烏紗靈壽對秋風，悵望浮雲濟水東。',32,'全唐诗/poet.tang.12000.json','["烏紗靈壽對秋風，悵望浮雲濟水東。", "官樹陰陰鈴閣暮，州人轉憶白頭翁。"]'),
('27622d64-c196-4bbf-9cbd-89ca4d3cf99e','梁城贈一二同幕','韓翃','唐','唐诗','tang','','[]','五營河畔列旌旗，吹角鳴鼙日暮時。',32,'全唐诗/poet.tang.12000.json','["五營河畔列旌旗，吹角鳴鼙日暮時。", "曾是信陵門下客，兩迴相弔不勝悲。"]'),
('8dd25e7d-c935-4eb6-993e-144a95798d50','河上寄故人','韓翃','唐','唐诗','tang','','[]','河流曉天，濮水清煙。',52,'全唐诗/poet.tang.12000.json','["河流曉天，濮水清煙。", "日暖昆吾臺上，春深顓頊城邊。", "鶯聲亂啁鵠囗，花片細點龍泉。", "西望情人早至，猶應得醉芳年。"]'),
('b26105a2-d9e4-4f3a-a0d4-1adb67facb0f','留題寧川香蓋寺壁','韓翃','唐','唐诗','tang','','[]','愛遠登高塵眼開。',64,'全唐诗/poet.tang.12000.json','["愛遠登高塵眼開。", "爲憐蕭寺上經臺，山川誰識龍蛇蟄。", "天地自迎風雨來，柳放寒條秋已老。", "雁搖孤翼暮空迴，何人會得其中事。", "又被殘花落日催。"]'),
('25a3e97e-464e-4d18-a912-1c1cf82b175d','寄柳氏','韓翃','唐','唐诗','tang','','[]','章臺柳，章臺柳，顏色青青今在否？縱使長條似舊垂，也應攀折他人手。',32,'全唐诗/poet.tang.12000.json','["章臺柳，章臺柳，顏色青青今在否？縱使長條似舊垂，也應攀折他人手。"]'),
('effc7dbe-9c0c-4dcf-aaab-d9a64a308bac','海上寄蕭立','獨孤及','唐','唐诗','tang','','[]','朔風剪塞草，寒露日夜結。',120,'全唐诗/poet.tang.12000.json','["朔風剪塞草，寒露日夜結。", "行行到瀛壖，歸思生暮節。", "驛樓見萬里，延首望遼碣。", "遠海入大荒，平蕪際窮髮。", "舊國在夢想，故人胡且越。", "契闊阻風期，荏苒成雨別。", "海西望京口，兩地各天末。", "索居動經秋，再笑知曷月。", "日南望中盡，唯見飛鳥滅。", "音塵未易得，何由慰飢渴。"]'),
('24ef8bab-1d3b-468f-97f5-d6518a5429cc','三月三日自京到華陰於水亭獨酌寄裴六薛八','獨孤及','唐','唐诗','tang','','[]','祗役匪遑息，經時客三秦。',144,'全唐诗/poet.tang.12000.json','["祗役匪遑息，經時客三秦。", "還家問節候，知到上巳辰。", "山縣何所有，高城閉青春。", "和風不吾欺，桃杏滿四鄰。", "舊友適遠別，誰當接歡欣。", "呼兒命長瓢，獨酌湘吳醇。", "一酌一朗詠，既酣意亦申。", "言筌暫兩忘，霞月祗相新。", "裴子塵表物，薛侯席上珍。", "寄書二傲吏，何日同車茵。", "詎肯使空名，終然羈此身。", "他年解桎梏，長作海上人。"]'),
('60eb6632-93f6-4d37-b50f-b4e9d7acc503','代書寄上裴六冀劉二潁','獨孤及','唐','唐诗','tang','','[]','昔余馬首東，君在海北汭。',240,'全唐诗/poet.tang.12000.json','["昔余馬首東，君在海北汭。", "盡屏簿領書，相與議巖穴。", "載來詣佳境，每山有車轍。", "長嘯林木動，高歌唾壺缺。", "此辭月未周，虜馬嘶絳闕。", "猛虎踞大道，九州當中裂。", "聞君棄孤城，猶自握漢節。", "恥栖惡木影，忍與故山別。", "脫舄挂嶺雲，冏然若鳥逝。", "唯留潺湲水，分付練溪月。", "爾來大谷梨，白花再成雪。", "關梁限天險，歡樂竟兩絕。", "大盜近削平，三川今底寧。", "句芒布春令，屏翳收雷霆。", "伊洛日夜漲，鳴臯蘭杜青。", "騫騫兩黃鵠，何處遊青冥。", "疇昔切玉刃，應如新發硎。", "及時當樹勳，高懸景鐘銘。", "莫抱白雲意，徑往丹丘庭。", "功成儻長揖，然後謀滄溟。"]'),
('997a7b34-550b-4f06-b160-ceedf658540e','客舍月下對酒醉後寄畢四燿','獨孤及','唐','唐诗','tang','','[]','鄉路風雪深，生事憂患迫。',192,'全唐诗/poet.tang.12000.json','["鄉路風雪深，生事憂患迫。", "天長波瀾廣，高舉無六翮。", "獨立寒夜移，幽境思彌積。", "霜月照膽淨，銀河入簷白。", "沽酒聊自勞，開樽坐簷隙。", "主人奏絲桐，能使高興劇。", "清機暫無累，獻酢更絡繹。", "慷慨葛天歌，愔愔廣陵陌。", "既醉萬事遺，耳熱心亦適。", "視身兀如泥，瞪目傲今昔。", "故人間城闕，音信兩脉脉。", "別時前盟在，寸景莫自擲。", "心與白日鬬，十無一滿百。", "寓形薪火內，甘作天地客。", "與物無親疎，斗酒勝竹帛。", "何必用自苦，將貽古賢責。"]'),
('6f278530-500b-4239-9fd7-cd476af8b08e','下弋陽江舟中代書寄裴侍御','獨孤及','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','故鄉隔西日，水去連長天。',144,'全唐诗/poet.tang.12000.json','["故鄉隔西日，水去連長天。", "前路知幾許，但指天南邊。", "愴恨極浦外，隱映青山連。", "東風滿帆來，五兩如弓弦。", "遙羨繡衣客，冏然馬首先。", "得餐武昌魚，不顧潯陽田。", "屈指數別日，忽乎成兩年。", "百花已滿眼，春草漸碧鮮。", "豈是離居時，奈何于役牽。", "洞庭有深涉，曷日期歸旋。", "且作異鄉料，詎知攜手緣。", "離憂未易銷，莫道樽酒賢。"]'),
('832f06ec-eb60-4f11-8564-bb3a7e8629a8','癸卯歲赴南豐道中聞京師失守寄權士繇韓幼深','獨孤及','唐','唐诗','tang','','[]','種田不遇歲，策名不遭時。',180,'全唐诗/poet.tang.12000.json','["種田不遇歲，策名不遭時。", "胡塵晦落日，西望泣路岐。", "猛虎嘯北風，麕麚皆載馳。", "深泥駕疲牛，踸踔余何之。", "詰屈白道轉，繚繞清溪隨。", "荒谷嘯山鬼，深林啼子規。", "長歎指故山，三奏歸來詞。", "不逢眼中人，調苦車逶遲。", "士繇松筠操，幼深瓊樹姿。", "別來平安否，何階一申眉。", "白雲失帝鄉，遠水恨天涯。", "昂藏雙威鳳，曷月還西枝。", "努力愛華髮，盛年振羽儀。", "但令迍難康，不負滄洲期。", "莫作新亭泣，徒使夷吾嗤。"]'),
('25721b8d-4d53-4494-9e32-f4ce981c4dfb','賈員外處見中書賈舍人巴陵詩集覧之懷舊代書寄贈','獨孤及','唐','唐诗','tang','','[]','海岸望青瑣，雲長天漫漫。',144,'全唐诗/poet.tang.12000.json','["海岸望青瑣，雲長天漫漫。", "十年不一展，知有關山難。", "適逢阮始平，立馬問長安。", "取公詠懷詩，示我江海瀾。", "暫若窺武庫，森然矛戟寒。", "眼明遺頭風，心悅忘朝餐。", "大駕今返正，熊羆扈鳴鑾。", "公遊鳳凰沼，獻可在筆端。", "繫越有長纓，封關祗一丸。", "冏然翔寥廓，仰望慚羽翰。", "嘉會不我與，相思歲雲殫。", "唯當袖佳句，持比青琅玕。"]'),
('59ef1225-521f-4e5d-8015-b5f2f306640c','代書寄上李廣州','獨孤及','唐','唐诗','tang','','[]','皖水望番禺，迢迢青天末。',144,'全唐诗/poet.tang.12000.json','["皖水望番禺，迢迢青天末。", "鴻鴈飛不到，音塵何由達。", "獨有輿人歌，隔雲聲諠聒。", "皆稱府君仁，百越賴全活。", "推誠魚鱉信，持正魑魅怛。", "疲民保中和，性足無夭閼。", "天子咨四岳，佇公濟方割。", "幾時復旋歸，入踐青瑣闥。", "賤子託明德，繚若松上葛。", "別離鄙恡生，結念思所豁。", "門欄關山阻，岐路天地闊。", "唯憑萬里書，持用慰飢渴。"]'),
('63eb44fd-c33b-462a-a22d-1dff34b55115','夏中詶于逖畢燿問病見贈','獨孤及','唐','唐诗','tang','','[]','救物智所昧，學仙願未從。',168,'全唐诗/poet.tang.12000.json','["救物智所昧，學仙願未從。", "行藏兩乖角，蹭蹬風波中。", "薄宦耻降志，臥痾非養蒙。", "閉關涉兩旬，羇思浩無窮。", "鸑鷟何處來，雙舞下碧空。", "離別隔雲雨，惠然此相逢。", "把手賀疾間，舉杯欣酒濃。", "新詩見久要，清論激深衷。", "高館舒夜簟，開門延微風。", "火雲赫嵯峨，日暮千萬峯。", "遙指故山笑，相看撫號鐘。", "聲和由心清，事感知氣同。", "出處未易料，且歌緩愁容。", "願君崇明德，歲暮如青松。"]'),
('7416f975-2ef2-4b64-81fa-41e24a9dc04e','詶梁二十宋中所贈兼留別梁少府','獨孤及','唐','唐诗','tang','','[]','少讀黃帝書，肯不笑機事。',194,'全唐诗/poet.tang.12000.json','["少讀黃帝書，肯不笑機事。", "意猶負深衷，未免名跡累。", "厭貧學干祿，欲徇賓王利。", "甘爲風波人，豈復江海意。", "擔簦平臺下，是日飲羇思。", "逢君道寸心，暫喜一交臂。", "緒言未及竟，離念已復至。", "甯[陵]望南丘，雲雨成兩地。", "途殊跡方間，河廣流且駛。", "暮帆望不及，覽贈心欲醉。", "愛君如金錫，昆弟皆茂異。", "奕赫連絲衣，榮養能錫類。", "君子道未長，深藏青雲器。", "巨鱗有縱時，今日不足議。", "唯當加餐飯，好我袖中字。", "別離動經年，莫道分首易。"]'),
('8082376a-6f93-46f4-9e4e-ea1e6a600c93','庚子歲避地至玉山詶韓司馬所贈','獨孤及','唐','唐诗','tang','','[]','滄海疾風起，洪波駭恬鱗。',96,'全唐诗/poet.tang.12000.json','["滄海疾風起，洪波駭恬鱗。", "已無濟川分，甘作乘桴人。", "揮手謝秣陵，舉帆指甌閩。", "安和風塵表，偶與瓊瑤親。", "共悲行路難，況逢江南春。", "故園忽如夢，返復知何辰。", "曠野豺虎滿，深山蘭蕙新。", "枉君灞陵什，廻首徒酸辛。"]'),
('0faec6a8-f7d3-44bf-b69b-db48b9e74f11','奉和李大夫同呂評事太行苦熱行兼寄院中諸公','獨孤及','唐','唐诗','tang','','[]','駟馬上太行，修途亙遼碣。',192,'全唐诗/poet.tang.12000.json','["駟馬上太行，修途亙遼碣。", "王程無留駕，日昃未遑歇。", "請問此何時，恢台朱明月。", "長蛇稽天討，上將方北伐。", "明主命使臣，皇華得時傑。", "已忘羊腸險，豈憚濕風熱。", "搖策汗滂滄，登岸思紆結。", "炎雲如煙火，谿谷將恐竭。", "晝景赩可畏，涼飆何由發。", "山長飛鳥墮，目極行車絕。", "趙魏方俶擾，安危俟明哲。", "歸路豈不懷，飲冰有苦節。", "會同傳檄至，疑議立談決。", "況有阮元瑜，翩翩秉書札。", "起予歌赤坂，永好踰白雪。", "誰念剖竹人，無因執羈紲。"]'),
('30a03a87-348d-477a-9f49-962ce991f8a8','詶皇甫侍御望天灊山見示之作','獨孤及','唐','唐诗','tang','','[]','早歲慕五嶽，嘗爲塵機礙。',264,'全唐诗/poet.tang.12000.json','["早歲慕五嶽，嘗爲塵機礙。", "孰知天柱峯，今與郡齋對。", "隱嶙抱元氣，氤氳含青靄。", "雲崖媚遠空，石壁寒古塞。", "漢皇南遊日，望秩此昭配。", "法駕到谷口，禮容振荒外。", "焚柴百神趨，執玉萬方會。", "天旋物順動，德布澤霶霈。", "講武威已耀，學仙功未艾。", "黃金竟何成，洪業遽淪昧。", "度世若一瞬，昨朝已千載。", "如今封禪壇，唯見雲雨晦。", "長望哀往古，勞生慚大塊。", "清暉幸相娛，幽獨知所賴。", "寒城春方正，初日明可愛。", "萬殊喜陽和，余亦荷時泰。", "山色日夜綠，下有清淺瀨。", "愧作拳僂人，沈迷簿書內。", "登臨歎拘限，出處悲老大。", "況聽郢中曲，復識湘南態。", "思免物累牽，敢令道機退。", "瞞然誦佳句，持此秋蘭佩。"]'),
('5d2e9ee1-99e7-4116-93c3-f3cf68e44527','送陳兼應辟兼寄高適賈至','獨孤及','唐','唐诗','tang','','[]','結綠處燕石，卞和不必知。',288,'全唐诗/poet.tang.12000.json','["結綠處燕石，卞和不必知。", "所以王佐才，未能忘茅茨。", "罷官梁山外，穫稻楚水湄。", "適會傅巖人，虛舟濟川時。", "天網忽搖頓，公才難棄遺。", "鳳凰翔千仞，今始一鳴岐。", "上馬指國門，舉鞭射書帷。", "預知大人賦，掩却歸來詞。", "天子方在宥，朝廷張四維。", "料君能獻可，努力副疇咨。", "舊友滿皇州，高冠飛翠蕤。", "相逢絳闕下，應道軒車遲。", "高侯秉戎翰，策馬觀西夷。", "方從幕中事，參謀王者師。", "賈生去洛陽，焜耀琳瑯姿。", "芳名動北步，逸韻陵南皮。", "肅肅舉鴻毛，冷然順風吹。", "波流有同異，由是限別離。", "漢塞隔隴底，秦川連鎬池。", "白雲日夜滿，道里安可思。", "夢想浩盈積，物華愁變衰。", "因君附錯刀，送遠益淒其。", "四海各橫絕，九霄應易期。", "不知故巢燕，決起棲何枝。"]'),
('3d130680-3936-409c-a214-f9e0257a27eb','送相里郎中赴江西','獨孤及','唐','唐诗','tang','','[]','君把一尺詔，南遊濟滄浪。',216,'全唐诗/poet.tang.12000.json','["君把一尺詔，南遊濟滄浪。", "受恩忘險艱，不道歧路長。", "戎狄方搆患，休牛殊未遑。", "三秦千倉空，戰卒如餓狼。", "委輸資外府，諏謀寄賢良。", "有才當陳力，安得遂翱翔。", "豈不慎井賦，賦均人亦康。", "遙知軒車到，萬室安耕桑。", "火伏金氣騰，昊天欲蒼茫。", "寒蟬慘巴鄧，秋色愁沅湘。", "昨日攜手西，於今芸再黃。", "歡娛詎幾許，復向天一方。", "蹢躅話世故，惆悵舉離觴。", "共求數刻歡，戲謔君此堂。", "今日把手笑，少時各他鄉。", "身名同風波，聚散未易量。", "曷月還朝天，及時開智囊。", "前期儻猶闊，加飯勉自強。"]'),
('42da4617-5aaf-4a12-8d01-d64fd9cecae5','觀海','獨孤及','唐','唐诗','tang','','[]','北登渤澥島，廻首秦東門。',120,'全唐诗/poet.tang.12000.json','["北登渤澥島，廻首秦東門。", "誰尸造物功，鑿此天池源。", "澒洞吞百谷，周流無四垠。", "廓然混茫際，望見天地根。", "白日自中吐，扶桑如可捫。", "超遙蓬萊峰，想像金臺存。", "秦帝昔經此，登臨冀飛翻。", "揚旌百神會，望日羣山奔。", "徐福竟何成，羨門徒空言。", "唯見石橋足，千年潮水痕。"]'),
('2fa64671-b74f-44f4-b685-99878869f07f','初晴抱琴登馬退山對酒望遠醉後作','獨孤及','唐','唐诗','tang','','[]','年長心易感，況爲憂患纏。',168,'全唐诗/poet.tang.12000.json','["年長心易感，況爲憂患纏。", "壯圖迫世故，行止兩茫然。", "王旅方伐叛，虎臣皆被堅。", "魯人著儒服，甘就南山田。", "挈榼上高磴，超遙望平川。", "滄江大如綖，隱映入遠天。", "荒服何所有，山花雪中然。", "寒泉得日景，吐霤鳴湔湔。", "舉酒勸白雲，唱歌慰頹年。", "微風度竹來，韻我號鍾弦。", "一彈一引滿，耳熱知心宣。", "曲終余亦酣，起舞山水前。", "人生幾何時，太半百憂煎。", "今日羇愁破，始知濁酒賢。"]'),
('df79e604-7c77-456d-97dc-9292f55c67c4','同徐侍郎五雲溪新庭重陽宴集作','獨孤及','唐','唐诗','tang','','[]','萬峰蒼翠色，雙溪清淺流。',96,'全唐诗/poet.tang.12000.json','["萬峰蒼翠色，雙溪清淺流。", "已符東山趣，況值江南秋。", "白露天地肅，黃花門館幽。", "山公惜美景，肯爲芳樽留。", "五馬照池塘，繁弦催獻酬。", "臨風孟嘉帽，乘興李膺舟。", "騁望傲千古，當歌遺四愁。", "豈令永和人，獨擅山陰遊。"]'),
('ccbc2bb1-3369-4f62-85b7-b90af85e03ea','雨晴後陪王員外泛後湖得溪字','獨孤及','唐','唐诗','tang','','[]','遠山媚平楚，宿雨漲清溪。',36,'全唐诗/poet.tang.12000.json','["遠山媚平楚，宿雨漲清溪。", "沿泝任舟檝，歡言無町畦。", "酒酣相視笑，心與白鷗齊。"]'),
('dc01e269-75e6-4f68-8ce1-ea2615ba9719','題思禪寺上方','獨孤及','唐','唐诗','tang','','[]','溪口聞法鼓，停橈登翠屏。',120,'全唐诗/poet.tang.12000.json','["溪口聞法鼓，停橈登翠屏。", "攀雲到金界，合掌開禪扃。", "鬱律衆山抱，空濛花雨零。", "老僧指香樓，云是不死庭。", "眇眇于越路，茫茫春草青。", "遠山噴百谷，繚繞馳東溟。", "目極道何在，境照心亦冥。", "騞然諸根空，破結如破瓶。", "下視三界狹，但聞五濁腥。", "山中有良藥，吾欲隳天形。"]'),
('556a1fa5-a3d2-48cb-bfb7-354c057e042f','季冬自嵩山赴洛道中作','獨孤及','唐','唐诗','tang','','[]','皇運偶中變，長蛇食中土。',216,'全唐诗/poet.tang.12000.json','["皇運偶中變，長蛇食中土。", "天蓋西北傾，衆星隕如雨。", "胡塵動地起，千里聞戰鼓。", "死人成爲阜，流血塗草莽。", "策馬何紛紛，捐軀抗豺虎。", "甘心赴國難，誰謂荼葉苦。", "天子初受命，省方造區宇。", "斬鯨安溟波，截鼇作天柱。", "三微復正統，五玉歸文祖。", "不圖漢官儀，今日忽再覩。", "升高望京邑，佳氣連海浦。", "寶鼎歊景雲，明堂舞干羽。", "虎臣囗激昂，囗囗囗禦侮。", "腐儒著縫掖，何處議鄒魯。", "西上轘轅山，丘陵橫今古。", "和氣蒸萬物，臘月春靄吐。", "得爲太平人，窮達不足數。", "他日遇封禪，著書繼三五。"]'),
('bef2cc78-10ff-4c56-8db2-7c496b1891b5','早發若峴驛望廬山','獨孤及','唐','唐诗','tang','','["\u5e90\u5c71"]','雨罷山翠鮮，泠泠東風好。',72,'全唐诗/poet.tang.12000.json','["雨罷山翠鮮，泠泠東風好。", "斷崖雲生處，是向峯頂道。", "誰謂峯頂遠，跂予可瞻討。", "忘緣祛天機，脫屐恨不早。", "祗恐歲云暮，遂與空名老。", "心往跡未幷，慚愧山上草。"]'),
('5cf815ef-1a26-4115-9b66-81baff361615','寒夜溪行舟中作','獨孤及','唐','唐诗','tang','','[]','日沈諸山昏，寂歷羣動宿。',96,'全唐诗/poet.tang.12000.json','["日沈諸山昏，寂歷羣動宿。", "孤舟獨不繫，風水夜相逐。", "雲歸恆星白，霜下天地肅。", "月輪大如盤，金波入空谷。", "魏闕萬里道，羇念千慮束。", "倦飛思故巢，敢望桐與竹。", "沈吟登樓賦，中夜起三復。", "憂來無良方，歸候春酒熟。"]'),
('7ceb6380-ba87-46cd-a32e-e257aea18af1','壬辰歲過舊居','獨孤及','唐','唐诗','tang','','[]','少年事遠遊，出入燕與秦。',96,'全唐诗/poet.tang.12000.json','["少年事遠遊，出入燕與秦。", "離居歲周天，猶作勞歌人。", "負劒渡潁水，歸馬自知津。", "緣源到舊廬，攬涕尋荒榛。", "鄰里喜相勞，壺觴展殷勤。", "酒蘭擊筑語，及此離會因。", "丈夫隨世波，豈料百年身。", "今日負鄙願，多慙故山春。"]'),
('ef546ff5-da19-4063-98ad-5a3cfae0849d','丙戌歲正月出洛陽書懷','獨孤及','唐','唐诗','tang','','[]','往歲衣褐見，受服金馬門。',120,'全唐诗/poet.tang.12000.json','["往歲衣褐見，受服金馬門。", "擬將忠與貞，來酬主人恩。", "天地暫雷雨，洪波生平原。", "窮鱗遂蹭蹬，夙昔事罕存。", "幸逢帝出震，授鉞清東藩。", "白日忽再中，萬方咸駿奔。", "王風從西來，春光滿乾坤。", "蟄蟲競飛動，余亦辭籠樊。", "遭遇思自強，寵辱安足言。", "唯將四方志，廻首謝故園。"]'),
('57afc121-9250-46ba-9503-6d19b0b49ff1','傷春懷歸','獨孤及','唐','唐诗','tang','','[]','誰謂鄉可望，望在天地涯。',96,'全唐诗/poet.tang.12000.json','["誰謂鄉可望，望在天地涯。", "但有時命同，萬里共歲華。", "昨夜南山雨，殷雷坼萌芽。", "源桃不余欺，先發秦人家。", "寂寂戶外掩，遲遲春日斜。", "源桃默無言，秦人獨長嗟。", "不惜中腸苦，但言會合賒。", "思歸吾誰訴，笑向南枝花。"]'),
('56f2dfa5-3d19-4b8f-a6da-8323290985ba','雜詩','獨孤及','唐','唐诗','tang','','[]','百花結成子，春物捨我去。',48,'全唐诗/poet.tang.12000.json','["百花結成子，春物捨我去。", "流年惜不得，獨坐空閨暮。", "心自有所待，甘爲物華悞。", "未必千黃金，買得一人顧。"]'),
('7aa53beb-a128-45f2-9bec-c2a15a0843c7','山中春思','獨孤及','唐','唐诗','tang','','[]','獺祭川水大，人家春日長。',108,'全唐诗/poet.tang.12000.json','["獺祭川水大，人家春日長。", "獨謠晝不暮，搔首慙年芳。", "靡草知節換，含葩向新陽。", "不嫌三徑深，爲我生池塘。", "亭午井竈閑，雀聲響空倉。", "花落沒屐齒，風動羣木香。", "歸路雲水外，天涯杳茫茫。", "獨卷萬里心，深入山鳥行。", "芳景勿相迫，春愁未遽忘。"]'),
('12286fc2-c262-43e8-817d-020327e8c690','雨後公超谷北原眺望寄高拾遺','獨孤及','唐','唐诗','tang','','[]','崖口雨足收，清光洗高天。',72,'全唐诗/poet.tang.12000.json','["崖口雨足收，清光洗高天。", "虹蜺斂殘靄，山水含碧鮮。", "遠空霞破露月輪，薄雲片片成魚鱗。", "五陵如薺渭如帶，目極千里關山春。", "朝來爽氣未易說，畫取花峯贈遠人。"]'),
('740e4166-38a6-4fa4-8ecb-5ff6eacc6de7','自東都還濠州奉詶王八諫議見贈','獨孤及','唐','唐诗','tang','','[]','關西仕時俱稚容，彪彪之鬢始相逢。',160,'全唐诗/poet.tang.12000.json','["關西仕時俱稚容，彪彪之鬢始相逢。", "天地變化縣城改，獨有故人交態在。", "不言會合跡未幷，猶以歲寒心相待。", "洛陽居守寄酇侯，君著貂冠參運籌。", "高閣連雲騎省夜，新文會友涼風秋。", "青袍白面昔攜手，冉冉府趨君記否。", "雲分雨散十五年，始得一笑樽酒前。", "未遑少留驟遠別，況值旅鴈鳴秋天。", "二華舊遊如夢想，他時再會何由緣。", "賴君贈我郢中曲，別後相思被管弦。"]'),
('bc326cee-2472-4d7d-8c4c-97a590a72ade','官渡柳歌送李員外承恩往揚州覲省','獨孤及','唐','唐诗','tang','','[]','君不見官渡河兩岸，三月楊柳枝。',183,'全唐诗/poet.tang.12000.json','["君不見官渡河兩岸，三月楊柳枝。", "千條萬條色，一一勝綠絲。", "花作鉛粉絮，葉成翠羽帳。", "此時送遠人，悵望春水上。", "遠客折楊柳，依依兩含情。", "夾郎木蘭舟，送郎千里行。", "郎把紫泥書，東征覲庭闈。", "脫却貂襜褕，新著五綵衣。", "雙鳳幷兩翅，將雛東南飛。", "五兩得便風，幾日到揚州。", "莫貪揚州好，客行剩淹留。", "郎到官渡頭，春闌已應久。", "殷勤道遠別，爲謝大堤柳。", "攀條儻相憶，五里一回首。", "明年柳枝黃，問郎還家否。"]'),
('68a65221-277b-4996-8d68-fed7604c1b8c','東平蓬萊驛夜宴平盧楊判官醉後贈別姚太守置酒留宴','獨孤及','唐','唐诗','tang','','[]','驛樓漲海壖，秋月寒城邊。',116,'全唐诗/poet.tang.12000.json','["驛樓漲海壖，秋月寒城邊。", "相見自不足，況逢主人賢。", "夜清酒濃人如玉，一斗何啻直十千。", "木蘭爲樽金爲杯，江南急管盧女弦。", "齊童如花解郢曲，起舞激楚歌採蓮。", "固知別多相逢少，樂極哀至心嬋娟。", "少留莫辭醉，前路方悠然。", "明日分飛儻相憶，祗應遙望西南天。"]'),
('8cd0788b-f590-4c33-afb9-22ca04af73e0','同岑郎中屯田韋員外花樹歌','獨孤及','唐','唐诗','tang','','[]','東風動地吹花發，渭城桃李千樹雪。',64,'全唐诗/poet.tang.12000.json','["東風動地吹花發，渭城桃李千樹雪。", "芳菲可愛不可留，武陵歸客心欲絕。", "金華省郎惜佳辰，秪持棣蕚照青春。", "君家自是成蹊處，況有庭花作主人。"]'),
('76c709fa-28a8-4635-a6c8-997b24e696fb','和李尚書畫射虎圖歌','獨孤及','唐','唐诗','tang','','[]','飢虎呀呀立當路，萬夫震恐百獸怒。',176,'全唐诗/poet.tang.12000.json','["飢虎呀呀立當路，萬夫震恐百獸怒。", "彤弓金鏃當者誰，鳴鞭飛控流星馳。", "居然畫中見真態，若務除惡不顧私。", "時和年豐五兵已，白額未誅壯士耻。", "分銖遠邇懸彀中，不中不發思全功。", "捨矢如破石可裂，應弦盡敵山爲空。", "殺氣滿堂觀者駭，颯若崖谷生長風。", "精微入神在毫末，作繢造物可同功。", "方叔秉鉞受命新，丹青起予氣益振。", "底綏靜難巧可擬，嗟歎不足聲成文。", "他時代天育萬物，亦以此道安斯民。"]'),
('99e0eca3-2edb-4967-b656-f055cf439e8a','和贈遠','獨孤及','唐','唐诗','tang','','[]','憶得去年春風至，中庭桃李映瑣窗。',64,'全唐诗/poet.tang.12000.json','["憶得去年春風至，中庭桃李映瑣窗。", "美人挾瑟對芳樹，玉顏亭亭與花雙。", "今年新花如舊時，去年美人不在茲。", "借問離居恨深淺，祗應獨有庭花知。"]'),
('b85c4c4a-f589-49a8-a7cb-c31467ce625c','和題藤架','獨孤及','唐','唐诗','tang','','[]','䔿䔿葉成幄，璀璀花落架。',56,'全唐诗/poet.tang.12000.json','["䔿䔿葉成幄，璀璀花落架。", "花前離心苦，愁至無日夜。", "人去藤花千里強，藤花無主爲誰芳。", "相思歷亂何由盡，春日迢迢如線長。"]'),
('3060b96f-1373-4ab8-b5cd-e602ce9b4151','江上代書寄裴使君','獨孤及','唐','唐诗','tang','','[]','何地離念劇，江臯風雪時。',48,'全唐诗/poet.tang.12000.json','["何地離念劇，江臯風雪時。", "艱難傷遠道，老大怯前期。", "疇昔行藏計，祗將力命推。", "能令書信數，猶足緩相思。"]'),
('9a6006f8-1767-4d21-b631-fdeb28721ec8','詣開悟禪師問心法次第寄韓郎中','獨孤及','唐','唐诗','tang','','[]','障深聞道晚，根鈍出塵難。',48,'全唐诗/poet.tang.12000.json','["障深聞道晚，根鈍出塵難。", "濁劫相從慣，迷途自謂安。", "得知身垢妄，始喜額珠完。", "欲識真如理，君嘗法味看。"]'),
('58fbfdb2-6dc9-4ba8-ba75-827a3c78c4d3','登後湖傷春懷京師故舊','獨孤及','唐','唐诗','tang','','[]','昨日看搖落，驚秋方怨咨。',48,'全唐诗/poet.tang.12000.json','["昨日看搖落，驚秋方怨咨。", "幾經開口笑，復及看花時。", "世事空名束，生涯素髮知。", "山山春草滿，何處不相思。"]'),
('c80e4104-8e5e-491f-97d2-9beb82d5802c','暮春於山谷寺上方遇恩命加官賜服詶皇甫侍御見賀之作','獨孤及','唐','唐诗','tang','','[]','天書到法堂，朽質被榮光。',48,'全唐诗/poet.tang.12000.json','["天書到法堂，朽質被榮光。", "自笑無功德，殊恩謬激揚。", "還登建禮署，猶忝會稽章。", "佳句慙相及，稱仁豈易當。"]'),
('e502aa21-de65-4abd-99ab-ba4773dfbf7e','荅李滁州題庭前石竹花見寄','獨孤及','唐','唐诗','tang','','[]','殷疑曙霞染，巧類匣刀裁。',48,'全唐诗/poet.tang.12000.json','["殷疑曙霞染，巧類匣刀裁。", "不怕南風熱，能迎小暑開。", "遊蜂憐色好，思婦感年催。", "覽贈添離恨，愁腸日幾廻。"]'),
('007e3153-8214-4631-a64e-49c8f2e00a6b','得李滁州書以玉潭莊見託因書春思以詩代荅','獨孤及','唐','唐诗','tang','','[]','春物行將老，懷君意詎堪。',48,'全唐诗/poet.tang.12000.json','["春物行將老，懷君意詎堪。", "朱顏因酒強，白髮對花慙。", "日日思瓊樹，書書話玉潭。", "知同百口累，曷日辦抽簪。"]'),
('9c35c1f4-6edd-4626-976d-59bc295d93e3','荅李滁州憶玉潭新居見寄','獨孤及','唐','唐诗','tang','','[]','從來招隱地，未有剖符人。',48,'全唐诗/poet.tang.12000.json','["從來招隱地，未有剖符人。", "山水能成癖，巢夷擬獨親。", "猪肝無足累，馬首敢辭勤。", "掃灑潭中月，他時望德鄰。"]'),
('0fe49699-594f-4b6e-807f-020a98bc4eff','將赴京答李紓贈別','獨孤及','唐','唐诗','tang','','[]','膠漆常投分，荆蠻各倦遊。',48,'全唐诗/poet.tang.12000.json','["膠漆常投分，荆蠻各倦遊。", "帝鄉今獨往，溝水便分流。", "甘作遠行客，深慙不繫舟。", "思君帶將緩，豈直日三秋。"]'),
('ff9ada12-e2d1-4ac7-87b0-faf835b9b730','和張大夫秋日有懷呈院中諸公','獨孤及','唐','唐诗','tang','','[]','至公無暇日，高閣閉秋天。',48,'全唐诗/poet.tang.12000.json','["至公無暇日，高閣閉秋天。", "肘印拘王事，籬花思長年。", "績成心不有，慮澹物猶牽。", "竊效泉魚躍，因聞郢曲妍。"]'),
('e706dda5-841a-4397-a760-5ad1edaee1a2','和大夫秋夜書情即事','獨孤及','唐','唐诗','tang','','[]','上略當分閫，高情善閉關。',48,'全唐诗/poet.tang.12000.json','["上略當分閫，高情善閉關。", "忘機羣動息，無戰五兵閑。", "鈴閣風傳漏，書窗月滿山。", "方知秋興作，非惜二毛斑。"]'),
('dd1a92df-e874-48ad-ae81-3ba96fa08dac','送虢州王錄事之任','獨孤及','唐','唐诗','tang','','[]','謂子文章達，當年羽翼高。',48,'全唐诗/poet.tang.12000.json','["謂子文章達，當年羽翼高。", "一經俄白首，三命尚青袍。", "未遇須藏器，安卑莫告勞。", "盤根儻相值，試用發硎刀。"]'),
('415110b9-d043-4d70-aaaa-c738d2e79f2d','送長孫將軍拜歙州之任','獨孤及','唐','唐诗','tang','','[]','臨難敢橫行，遭時取盛名。',48,'全唐诗/poet.tang.12000.json','["臨難敢橫行，遭時取盛名。", "五兵常典校，四十又專城。", "浪逐樓船破，風從虎竹生。", "島夷今可料，繫頸有長纓。"]'),
('d8fbb630-1b97-47a2-951e-0e11e8ce2758','送何員外使湖南','獨孤及','唐','唐诗','tang','','[]','夙昔皆黃綬，差池復瑣闈。',48,'全唐诗/poet.tang.12000.json','["夙昔皆黃綬，差池復瑣闈。", "上田無晚熟，逸翮果先飛。", "前路舟休繫，故山雲不歸。", "王程儻未復，莫遣鯉書稀。"]'),
('dfbedb71-d49c-4452-9863-177aca5e81ae','送江陵全少卿赴府任','獨孤及','唐','唐诗','tang','','[]','冢司方眘選，劇縣得英髦。',48,'全唐诗/poet.tang.12000.json','["冢司方眘選，劇縣得英髦。", "固是攀雲漸，何嗟趨府勞。", "楚山迎驛路，漢水漲秋濤。", "騫翥方茲始，看君六翮高。"]'),
('bb747f2c-dbcc-43ec-a73e-e3ee70eaeaca','送虞秀才擢第歸長沙','獨孤及','唐','唐诗','tang','','[]','充賦名今遂，安親事不違。',48,'全唐诗/poet.tang.12000.json','["充賦名今遂，安親事不違。", "甲科文比玉，歸路錦爲衣。", "海運同鵾化，風帆若鳥飛。", "知君到三逕，松菊有光輝。"]'),
('9a39a30e-316a-4cc7-bc7e-857aabde0eb4','送陽翟張主簿之任','獨孤及','唐','唐诗','tang','','[]','舊聞陽翟縣，西接鳳高山。',48,'全唐诗/poet.tang.12000.json','["舊聞陽翟縣，西接鳳高山。", "作吏同山隱，知君處劇閑。", "少年當効用，遠道豈辭艱。", "遲子揚名後，方期綵服還。"]'),
('2ec9dd01-04f7-4713-93f4-5113ff4a5d9f','送游員外赴淮西','獨孤及','唐','唐诗','tang','','[]','多君有奇略，投筆佐元戎。',48,'全唐诗/poet.tang.12000.json','["多君有奇略，投筆佐元戎。", "已佩郎官印，兼乘御史驄。", "使星隨驛騎，歸路有秋風。", "莫道無書札，他年懷袖空。"]'),
('3444a2ca-ee8d-4537-a1af-d0060bb80ea1','送馬鄭州','獨孤及','唐','唐诗','tang','','[]','使君朱兩轓，春日整東轅。',48,'全唐诗/poet.tang.12000.json','["使君朱兩轓，春日整東轅。", "芳草成臯路，青山涼水源。", "勉修循吏跡，以謝主人恩。", "當使仁風動，遙聽輿頌諠。"]'),
('270864c0-5af6-4afc-ad50-a8352f533854','送義烏韋明府','獨孤及','唐','唐诗','tang','','[]','妙年能致身，陳力復安親。',48,'全唐诗/poet.tang.12000.json','["妙年能致身，陳力復安親。", "不憚關山遠，寧辭簿領勤。", "過江雲滿路，到縣海爲鄰。", "每歎違心賞，吳門正早春。"]'),
('d8258bd2-118c-4db1-8ee8-02ba00bf5430','送陳王府張長史還京','獨孤及','唐','唐诗','tang','','[]','論齒弟兄列，爲邦前後差。',48,'全唐诗/poet.tang.12000.json','["論齒弟兄列，爲邦前後差。", "十年方一見，此別復何嗟。", "極目故關道，傷心南浦花。", "少時相憶處，招手望行車。"]'),
('3e761c18-6176-4adc-b1dc-42d297995958','水西館泛舟送王員外','獨孤及','唐','唐诗','tang','','[]','單醪敢獻酢，曲沼荷經過。',48,'全唐诗/poet.tang.12000.json','["單醪敢獻酢，曲沼荷經過。", "泛覽親魚鳥，夤緣涉芰荷。", "劇談增惠愛，美景借清和。", "明日汀洲草，依依奈別何。"]'),
('42f61ca0-8a41-470d-8fe8-d5de63db5ac0','李卿東池夜宴得池字','獨孤及','唐','唐诗','tang','','[]','政成機不擾，心愜宴忘疲。',48,'全唐诗/poet.tang.12000.json','["政成機不擾，心愜宴忘疲。", "去燭延高月，傾罍就小池。", "舞盤廻雪動，弦奏躍魚隨。", "自是山公興，誰令下士知。"]'),
('9a41dbd6-e1d7-462d-9e71-8259ec5e7061','九月九日李蘇州東樓宴','獨孤及','唐','唐诗','tang','','[]','是菊花開日，當君乘興秋。',48,'全唐诗/poet.tang.12000.json','["是菊花開日，當君乘興秋。", "風前孟嘉帽，月下庾公樓。", "酒解留征客，歌能破別愁。", "醉歸無以贈，祗奉萬年酬。"]'),
('a3db26dd-97dc-480a-a07f-521d91c2c72d','蕭文學山池宴集','獨孤及','唐','唐诗','tang','','[]','檀欒千畝綠，知是辟疆園。',48,'全唐诗/poet.tang.12000.json','["檀欒千畝綠，知是辟疆園。", "遠岫當庭戶，諸花覆水源。", "主人邀盡醉，林鳥助狂言。", "莫問愁多少，今皆付酒樽。"]'),
('6dbc7bc5-67e6-4648-b376-b0bd6f809b98','與韓侍御同尋李七舍人不遇題壁留贈','獨孤及','唐','唐诗','tang','','[]','三徑何寂寂，主人山上山。',48,'全唐诗/poet.tang.12000.json','["三徑何寂寂，主人山上山。", "亭空簷月在，水落釣磯閑。", "藥院雞犬靜，酒壚苔蘚班。", "知君少機事，當待暮雲還。"]'),
('29caf0d7-6d84-4b60-975d-d2acce3b89e4','喜辱韓十四郎中書兼封近詩示代書題贈','獨孤及','唐','唐诗','tang','','[]','各牽于役間遊遨，獨坐相思正鬱陶。',64,'全唐诗/poet.tang.12000.json','["各牽于役間遊遨，獨坐相思正鬱陶。", "長跪讀書心蹔緩，短章投我曲何高。", "宦情緣木知非願，王事敦人敢告勞。", "所歎在官成遠別，徒言岏水纔容舠。"]'),
('7cb201dc-c6ee-45c2-a3e8-55f422fe789b','早發龍沮館舟中寄東海徐司倉鄭司戶','獨孤及','唐','唐诗','tang','','[]','沙禽相呼曙色分，漁浦鳴桹十里聞。',64,'全唐诗/poet.tang.12000.json','["沙禽相呼曙色分，漁浦鳴桹十里聞。", "正當秋風渡楚水，況值遠道傷離羣。", "津頭却望後湖岸，別處已隔東山雲。", "停艫目送北歸翼，惜無瑤華持寄君。"]'),
('26d26522-f5d4-402c-9be6-2d9019d4f1a2','詶常郿縣見贈','獨孤及','唐','唐诗','tang','','[]','愛君修政若修身，鰥寡來歸乳雉馴。',64,'全唐诗/poet.tang.12000.json','["愛君修政若修身，鰥寡來歸乳雉馴。", "堂上五弦銷暇日，邑中千室有陽春。", "謂乘鳧舄朝天子，却愧猪肝累主人。", "辭後讀君懷縣作，定知三歲字猶新。"]'),
('065d04e0-474e-41be-8f82-e5e47f41112d','登山谷寺上方答皇甫侍御臥疾闕陪車騎之後','獨孤及','唐','唐诗','tang','','[]','梵宮香閣攀霞上，天柱孤峯指掌看。',64,'全唐诗/poet.tang.12000.json','["梵宮香閣攀霞上，天柱孤峯指掌看。", "漢主馬蹤成蔓草，法王身相示空棺。", "雲扶踴塔青霄庳，松蔭禪庭白日寒。", "不見戴逵心莫展，賴將新贈比琅玕。"]'),
('6827814b-c6e3-4c66-884f-42d714338fa1','答皇甫十六侍御北歸留別作','獨孤及','唐','唐诗','tang','','[]','正當楚客傷春地，豈是騷人道別時。',64,'全唐诗/poet.tang.12000.json','["正當楚客傷春地，豈是騷人道別時。", "俱徇空名嗟欲老，況將行役料前期。", "勞生多故應同病，羸馬單車莫自悲。", "明日相望隔雲水，解顔唯有袖中詩。"]'),
('abf81fb1-69da-456b-b5db-b2048c8a2868','答李滁州見寄','獨孤及','唐','唐诗','tang','','[]','相逢遽歎別離牽，三見江臯惠草鮮。',64,'全唐诗/poet.tang.12000.json','["相逢遽歎別離牽，三見江臯惠草鮮。", "白髮俱生歡未再，滄州獨往意何堅。", "愁看郡內花將歇，忍過山中月屢圓。", "終日望君休汝騎，愧無堪報起予篇。"]'),
('dfaaaf11-9ead-4921-a71e-1f60be94af03','得柳員外書封寄近詩書中兼報新主行營兵馬因代書戲答','獨孤及','唐','唐诗','tang','','[]','郎官作掾心非好，儒服臨戎政已聞。',64,'全唐诗/poet.tang.12000.json','["郎官作掾心非好，儒服臨戎政已聞。", "說劒嘗宗漆園吏，戒嚴應笑棘門軍。", "遙知抵掌論皇道，時復吟詩向白雲。", "百越待君言即敘，相思不敢愴離羣。"]'),
('7b29732f-3ca8-45c3-a894-c1caaa21622e','同皇甫侍御齋中春望見示之作','獨孤及','唐','唐诗','tang','','[]','望遠思歸心易傷，況將衰鬢偶年光。',64,'全唐诗/poet.tang.12000.json','["望遠思歸心易傷，況將衰鬢偶年光。", "時攀芳樹愁花盡，晝掩高齋厭日長。", "甘比流波辭舊浦，忍看新草遍橫塘。", "因君贈我江楓詠，春思如今未易量。"]'),
('e9f0c9ff-9301-4ad3-99f5-7283edd3aa6d','傷春贈遠','獨孤及','唐','唐诗','tang','','[]','去水流年日並馳，年光客思兩相隨。',64,'全唐诗/poet.tang.12000.json','["去水流年日並馳，年光客思兩相隨。", "咨嗟斑鬢今承弁，慙愧新荷又發池。", "楊柳逶迤愁遠道，鷓鴣啁哳怨南枝。", "憶君何啻同瓊樹，但向春風送別離。"]'),
('832e48cf-3779-446c-80ec-b233f37fc140','奉和中書常舍人晚秋集賢院即事寄贈徐薛二侍御','獨孤及','唐','唐诗','tang','','[]','漢家金馬署，帝座紫微郎。',144,'全唐诗/poet.tang.13000.json','["漢家金馬署，帝座紫微郎。", "圖籍淩羣玉，歌詩冠柏梁。", "陰陰萬年樹，肅肅五經堂。", "揮翰忘朝食，研精待夕陽。", "晴空露盤迥，秋月瑣窗涼。", "遠興生斑鬢，高情寄縹囊。", "葳蕤雙鸑鷟，夙昔並翱翔。", "汲冢同刊謬，蓬山共補亡。", "差池摧羽翮，流落限江湘。", "禁省一分袂，昊天三雨霜。", "石渠遺跡滿，水國暮雲長。", "早晚朝宣室，歸時道路光。"]'),
('61db6a81-c908-43d0-881f-39f3f84a3461','江寧詶鄭縣劉少府兄贈別作','獨孤及','唐','唐诗','tang','','[]','往年脫縫掖，接武仕關西。',96,'全唐诗/poet.tang.13000.json','["往年脫縫掖，接武仕關西。", "結綬腰章並，趨堦手板齊。", "仙山不用買，朋酒日相攜。", "抵掌誇潭壑，忘情向組珪。", "事遷時既往，年長跡逾暌。", "何爲青雲器，猶嗟濁水泥。", "役牽方遠別，道在或先迷。", "莫見良田晚，遭時亦杖藜。"]'),
('be0153d0-60a7-4035-a5d9-a01497bdb9c0','送李賓客荆南迎親','獨孤及','唐','唐诗','tang','','[]','宗室劉中壘，文場謝客兒。',72,'全唐诗/poet.tang.13000.json','["宗室劉中壘，文場謝客兒。", "當爲天北斗，曾使海西陲。", "毛節精誠著，銅樓羽翼施。", "還申供帳別，言赴倚門期。", "恩渥霑行李，晨昏在路岐。", "君親兩報遂，不敢議傷離。"]'),
('41747bf8-cf9f-4631-944c-e1a6f0ebfdd5','題玉潭','獨孤及','唐','唐诗','tang','','[]','碧玉徒強名，冰壺難比德。',24,'全唐诗/poet.tang.13000.json','["碧玉徒強名，冰壺難比德。", "唯當寂照心，可並奫淪色。"]'),
('d51cdcbf-e375-4c64-bc0f-9759b137879c','海上懷華中舊遊寄鄭縣劉少府造渭南王少府崟','獨孤及','唐','唐诗','tang','','[]','涼風臺上三峯月，不夜城邊萬里沙。',32,'全唐诗/poet.tang.13000.json','["涼風臺上三峯月，不夜城邊萬里沙。", "離別莫言關塞遠，夢魂長在子真家。"]'),
('36bb241a-a915-45e0-9b78-b35e3565f255','和虞部韋郎中尋楊駙馬不遇','獨孤及','唐','唐诗','tang','','[]','金屋瓊臺蕭史家，暮春三月渭州花。',32,'全唐诗/poet.tang.13000.json','["金屋瓊臺蕭史家，暮春三月渭州花。", "到君仙洞不相見，謂已吹簫乘早霞。"]'),
('ad4a7b6b-cd6e-4b4a-a3e1-f58c25911dc6','李張皇甫閻權等數公並有送別之作見寄因答','獨孤及','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭正波蘋葉衰，豈是秦吳遠別時。',32,'全唐诗/poet.tang.13000.json','["洞庭正波蘋葉衰，豈是秦吳遠別時。", "謝君篋中綺端贈，何以報之長相思。"]'),
('125a3c91-2481-42b4-8cdb-e1116d5b22df','將還越留別豫章諸公','獨孤及','唐','唐诗','tang','','[]','客鳥倦飛思舊林，裴徊猶戀衆花陰。',32,'全唐诗/poet.tang.13000.json','["客鳥倦飛思舊林，裴徊猶戀衆花陰。", "他時相憶雙航葦，莫問吳江深不深。"]'),
('eb3aa535-b4a9-4a3c-abe3-0a8217c51513','送別荆南張判官','獨孤及','唐','唐诗','tang','','[]','輶車駱馬往從誰，夢浦蘭臺日更遲。',32,'全唐诗/poet.tang.13000.json','["輶車駱馬往從誰，夢浦蘭臺日更遲。", "欲識桃花最多處，前程問取武陵兒。"]'),
('7a2f4ad1-f9dd-474c-978b-2a5f2aac14ab','陪王員外北樓宴待月','獨孤及','唐','唐诗','tang','','[]','勸酒論心夜不疲，含情有待問誰思。',32,'全唐诗/poet.tang.13000.json','["勸酒論心夜不疲，含情有待問誰思。", "佇看晴月澄澄影，來照江樓酩酊時。"]'),
('401da7ba-8be2-4e91-93c1-fdf06a263095','垂花塢醉後戲題','獨孤及','唐','唐诗','tang','','[]','紫蔓青條拂酒壺，落花時與竹風俱。',32,'全唐诗/poet.tang.13000.json','["紫蔓青條拂酒壺，落花時與竹風俱。", "歸時自負花前醉，笑向鯈魚問樂無。"]'),
('b2673236-e35c-4802-8273-f79590114b7d','題劉相公三湘圖','郎士元','唐','唐诗','tang','','[]','昔別醉衡霍，邇來憶南州。',96,'全唐诗/poet.tang.13000.json','["昔別醉衡霍，邇來憶南州。", "今朝平津邸，兼得瀟湘遊。", "稍辨郢門樹，依然芳杜洲。", "微明三巴峽，咫尺萬里流。", "飛鳥不知倦，遠帆生暮愁。", "涔陽指天末，北渚空悠悠。", "枕上見漁父，坐中常狎鷗。", "誰言魏闕下，自有東山幽。"]'),
('4352f313-6ae9-4e57-8f12-b5e3c54d24da','長安逢故人','郎士元','唐','唐诗','tang','','[]','數年音信斷，不意在長安。',48,'全唐诗/poet.tang.13000.json','["數年音信斷，不意在長安。", "馬上相逢久，人中欲認難。", "一官今嬾道，雙鬢竟羞看。", "莫問生涯事，只應持釣竿。"]'),
('9c626a7e-db6f-486b-a128-a7f5434ad1b7','送韋湛判官','郎士元','唐','唐诗','tang','','[]','高閣晴江上，重陽古戍閑。',48,'全唐诗/poet.tang.13000.json','["高閣晴江上，重陽古戍閑。", "聊因送歸客，更此望鄉山。", "惜別心能醉，經秋鬢自斑。", "臨流興不盡，惆悵水雲間。"]'),
('7d0991c7-fe35-495d-b0a7-093dfdfad29d','送長沙韋明府','郎士元','唐','唐诗','tang','','[]','秋入長沙縣，蕭條旅宦心。',48,'全唐诗/poet.tang.13000.json','["秋入長沙縣，蕭條旅宦心。", "煙波連桂水，官舍映楓林。", "雲日楚天暮，沙汀白露深。", "遙知訟堂裏，佳政在鳴琴。"]'),
('51c35019-b59c-4591-8698-27d7aac7b54d','送孫願','郎士元','唐','唐诗','tang','','[]','悠然富春客，憶與暮潮歸。',48,'全唐诗/poet.tang.13000.json','["悠然富春客，憶與暮潮歸。", "擢第人多羨，如君獨步稀。", "亂流江渡淺，遠色海山微。", "若訪新安路，嚴陵有釣磯。"]'),
('44353dc5-b941-4156-b12d-1a7e9292aa41','送林宗配雷州','郎士元','唐','唐诗','tang','','[]','昨日三峰尉，今朝萬里人。',48,'全唐诗/poet.tang.13000.json','["昨日三峰尉，今朝萬里人。", "平生任孤直，豈是不防身。", "海霧多爲瘴，山雷乍作隣。", "遙憐北戶月，與子獨相親。"]'),
('6cf729a2-07fc-4621-acb3-3a9fc74ff455','送洪州李別駕之任','郎士元','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','南去秋江遠，孤舟興自多。',48,'全唐诗/poet.tang.13000.json','["南去秋江遠，孤舟興自多。", "能將流水引，更入洞庭波。", "夏口帆初上，潯陽鴈正過。", "知音在霄漢，佐郡豈蹉跎。"]'),
('0df59c4e-610f-4bad-8ff7-6c8393ec4e4a','送楊中丞和蕃','郎士元','唐','唐诗','tang','','[]','錦車登隴日，邊草正萋萋。',48,'全唐诗/poet.tang.13000.json','["錦車登隴日，邊草正萋萋。", "舊好尋君長，新愁聽鼓鼙。", "河源飛鳥外，雪嶺大荒西。", "漢壘今猶在，遙知路不迷。"]'),
('799ce706-685f-4340-940f-21a76b7e6f15','送李將軍赴定州','郎士元','唐','唐诗','tang','','["\u9001\u522b", "\u6218\u4e89", "\u795d\u798f"]','雙旌漢飛將，萬里授橫戈。',48,'全唐诗/poet.tang.13000.json','["雙旌漢飛將，萬里授橫戈。", "春色臨邊盡，黃雲出塞多。", "鼓鼙悲絕漠，烽戍隔長河。", "莫斷陰山路，天驕已請和。"]'),
('3866facf-d8d2-4f4e-b7c4-eefbc12bfdea','關羽祠送高員外還荆州','郎士元','唐','唐诗','tang','','[]','將軍稟天姿，義勇冠今昔。',72,'全唐诗/poet.tang.13000.json','["將軍稟天姿，義勇冠今昔。", "走馬百戰場，一劍萬人敵。", "雖爲感恩者，竟是思歸客。", "流落荆巫間，裴回故鄉隔。", "離筵對祠宇，灑酒暮天碧。", "去去勿復言，銜悲向陳跡。"]'),
('28b76447-7491-4ec6-bedc-22de0ae8dd59','送張南史','郎士元','唐','唐诗','tang','','[]','雨餘深巷靜，獨酌送殘春。',48,'全唐诗/poet.tang.13000.json','["雨餘深巷靜，獨酌送殘春。", "車馬雖嫌僻，鶯花不棄貧。", "蟲絲黏戶網，鼠跡印牀塵。", "借問山陽會，如今有幾人。"]'),
('facdc456-bd32-442c-b870-3a9cd87a879d','送奚賈歸吳','郎士元','唐','唐诗','tang','','[]','東南富春渚，曾是謝公遊。',48,'全唐诗/poet.tang.13000.json','["東南富春渚，曾是謝公遊。", "今日奚生去，新安江正秋。", "水清迎過客，霜葉落行舟。", "遙想赤亭下，聞猨應夜愁。"]'),
('5f9a3697-2850-4441-877f-8c1ac378dab7','送陸員外赴潮州','郎士元','唐','唐诗','tang','','[]','含香臺上客，剖竹海邊州。',36,'全唐诗/poet.tang.13000.json','["含香臺上客，剖竹海邊州。", "楚地多歸信，閩溪足亂流。", "今朝永嘉興，重見謝公遊。"]'),
('06203cef-1dc5-4d60-9ef7-a4bf4306c730','送裴補闕入河南幕','郎士元','唐','唐诗','tang','','[]','皎然青瑣客，何事動行軒。',48,'全唐诗/poet.tang.13000.json','["皎然青瑣客，何事動行軒。", "苦節酬知己，清吟去掖垣。", "秋城臨海樹，寒月上營門。", "鄒魯詩書國，應無鼙鼓喧。"]'),
('e1fcfc7b-7b77-4775-8301-70d3beefa3e0','送韓司直路出延陵','郎士元','唐','唐诗','tang','','[]','遊吳還適越，來往任風波。',48,'全唐诗/poet.tang.13000.json','["遊吳還適越，來往任風波。", "復送王孫去，其如春草何。", "岸明殘雪在，潮滿夕陽多。", "季子留遺廟，停舟試一過。"]'),
('67d2ba1b-92a3-4fdd-8bb6-491b279a4b47','盩厔縣鄭礒宅送錢大','郎士元','唐','唐诗','tang','','[]','暮蟬不可聽，落葉豈堪聞。',48,'全唐诗/poet.tang.13000.json','["暮蟬不可聽，落葉豈堪聞。", "共是悲秋客，那知此路分。", "荒城背流水，遠鴈入寒雲。", "陶令門前菊，餘花可贈君。"]'),
('ba215b86-2100-483d-8bb8-58abf31709ab','送元詵還丹陽別業','郎士元','唐','唐诗','tang','','[]','已知成傲吏，復見解朝衣。',48,'全唐诗/poet.tang.13000.json','["已知成傲吏，復見解朝衣。", "應向丹陽郭，秋山獨掩扉。", "草堂連古寺，江日動晴暉。", "一別滄州遠，蘭橈幾歲歸。"]'),
('ed6c7722-14bb-40ea-a754-b8ac46534678','送崔侍御往容州宣慰','郎士元','唐','唐诗','tang','','[]','秦原獨立望湘川，擊隼南飛向楚天。',64,'全唐诗/poet.tang.13000.json','["秦原獨立望湘川，擊隼南飛向楚天。", "奉詔不言空問俗，清時因得訪遺賢。", "荆門曉色兼梅雨，桂水春風過客船。", "疇昔常聞陸賈說，故人今日豈徒然。"]'),
('4b02442f-be4c-4965-a763-503d3f99023a','朱方南郭留別皇甫冉','郎士元','唐','唐诗','tang','','[]','縈迴楓葉岸，留滯木蘭橈。',48,'全唐诗/poet.tang.13000.json','["縈迴楓葉岸，留滯木蘭橈。", "吳岫新經雨，江天正落潮。", "故人勞見愛，行客自無憀。", "若問前程事，孤雲入剡遙。"]'),
('914b38c9-9904-4894-a10a-a5d9803c9d83','贈張五諲歸濠州別業','郎士元','唐','唐诗','tang','','[]','常知罷官意，果與世人疎。',48,'全唐诗/poet.tang.13000.json','["常知罷官意，果與世人疎。", "復此涼風起，仍聞濠上居。", "故山期採菊，秋水憶觀魚。", "一去蓬蒿徑，羨君閑有餘。"]'),
('6d4cca5d-f01c-48c8-afd0-ddd6cf7c3e1f','送王司馬赴潤州','郎士元','唐','唐诗','tang','','[]','暫屈文爲吏，聊將祿代耕。',48,'全唐诗/poet.tang.13000.json','["暫屈文爲吏，聊將祿代耕。", "金陵且不遠，山水復多名。", "楚塞因高出，寒潮入夜生。", "離心逐春草，直到建康城。"]'),
('5d300505-0b4a-460a-8131-e4a414dadd6d','留盧秦卿','郎士元','唐','唐诗','tang','','["\u9001\u522b"]','知有前期在，歡如此夜中。',24,'全唐诗/poet.tang.13000.json','["知有前期在，歡如此夜中。", "無將故人酒，不及古淳風。"]'),
('15757ed7-bb83-49be-9336-db817939006c','贈強山人','郎士元','唐','唐诗','tang','','[]','或掉輕舟或杖藜。',32,'全唐诗/poet.tang.13000.json','["或掉輕舟或杖藜。", "尋常適意釣前溪，草堂竹逕在何處。", "落日孤煙寒渚西。"]'),
('97ebb4c2-6e32-43ac-b721-dda9be7dabd9','贈韋司直','郎士元','唐','唐诗','tang','','[]','聞君感歎二毛初，舊友相依萬里餘。',64,'全唐诗/poet.tang.13000.json','["聞君感歎二毛初，舊友相依萬里餘。", "烽火有時驚暫定，甲兵無處可安居。", "客來吳地星霜久，家在平陵音信疎。", "昨日風光還入戶，登山臨水意何如。"]'),
('48ca87c0-1499-4530-94e1-144e1683b4b8','石城館酬王將軍','郎士元','唐','唐诗','tang','','[]','誰能繡衣客，肯駐木蘭舟。',48,'全唐诗/poet.tang.13000.json','["誰能繡衣客，肯駐木蘭舟。", "連雁沙邊至，孤城江上秋。", "歸帆背南浦，楚塞入西樓。", "何處看離思，滄波日夜流。"]'),
('b19965c5-9574-43ff-9158-2f61b6a3fde7','酬王季友題半日村別業兼呈李明府','郎士元','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u51ac\u5929"]','村映寒原日已斜，煙生密竹早歸鴉。',64,'全唐诗/poet.tang.13000.json','["村映寒原日已斜，煙生密竹早歸鴉。", "長溪南路當羣岫，半景東隣照數家。", "門通小徑連芳草，馬飲春泉踏淺沙。", "欲待主人林上月，還思潘岳縣中花。"]'),
('b1b2a614-15f4-44f8-a2b8-4227751cfadc','酬二十八秀才見寄','郎士元','唐','唐诗','tang','','["\u6000\u4eba", "\u591c\u665a", "\u6708\u4eae"]','昨夜山月好，故人果相思。',36,'全唐诗/poet.tang.13000.json','["昨夜山月好，故人果相思。", "清光到枕上，嫋嫋涼風時。", "永意能在我，惜無攜手期。"]'),
('f1251d11-7f7a-4b19-8e2b-eb0df33c004f','冬夕寄青龍寺源公','郎士元','唐','唐诗','tang','','["\u5199\u666f", "\u51ac\u5929"]','歛屨入寒竹，安禪過漏聲。',48,'全唐诗/poet.tang.13000.json','["歛屨入寒竹，安禪過漏聲。", "高松殘子落，深井凍痕生。", "罷磬風枝動，懸燈雪屋明。", "何當招我宿，乘月上方行。"]'),
('bad3309f-985c-4852-8bba-d6ef2a5ebc11','塞下曲','郎士元','唐','唐诗','tang','','[]','寶刀塞下兒，身經百戰曾百勝。',54,'全唐诗/poet.tang.13000.json','["寶刀塞下兒，身經百戰曾百勝。", "壯心竟未嫖姚知，白草山頭日初沒。", "黃沙戍下悲歌發，蕭條夜靜邊風吹，獨倚營門望秋月。"]'),
('952b7249-b535-4d68-b2b7-feb2623a414d','柏林寺南望','郎士元','唐','唐诗','tang','','["\u5199\u5c71", "\u5bfa\u5e99", "\u63cf\u5199\u5c71"]','溪上遙聞精舍鐘，泊舟微徑度深松。',32,'全唐诗/poet.tang.13000.json','["溪上遙聞精舍鐘，泊舟微徑度深松。", "青山霽後雲猶在，畫出東南四五峰。"]'),
('7bbcafe3-b343-4428-9a88-0b961af72d26','宿杜判官江樓','郎士元','唐','唐诗','tang','','[]','適楚豈吾願，思歸秋向深。',48,'全唐诗/poet.tang.13000.json','["適楚豈吾願，思歸秋向深。", "故人江樓月，永夜千里心。", "葉落覺鄉夢，鳥啼驚越吟。", "寥寥更何有，斷續空城砧。"]'),
('91cc371b-f47e-4e0c-b611-134d953616c4','春宴王補闕城東別業','郎士元','唐','唐诗','tang','','[]','柳陌乍隨州勢轉，花源忽傍竹陰開。',64,'全唐诗/poet.tang.13000.json','["柳陌乍隨州勢轉，花源忽傍竹陰開。", "能將瀑水清人境，直取流鶯送酒杯。", "山下古松當綺席，簷前片雨滴春苔。", "地主同聲復同舍，留歡不畏夕陽催。"]'),
('a51dd970-bcea-4dc2-8de1-d0a31dc7c95c','郢城西樓吟','郎士元','唐','唐诗','tang','','[]','連山盡處水縈迴，山上戍門臨水開。',64,'全唐诗/poet.tang.13000.json','["連山盡處水縈迴，山上戍門臨水開。", "朱欄直下一百丈，日暖遊鱗自相向。", "昔人愛險閉層城，今日愛閑江復清。", "沙洲楓岸無來客，草綠花紅山鳥鳴。"]'),
('6a93b0ca-ca2c-40b8-998a-39850248bc99','聽鄰家吹笙','郎士元','唐','唐诗','tang','','[]','鳳吹聲如隔綵霞，不知牆外是誰家。',32,'全唐诗/poet.tang.13000.json','["鳳吹聲如隔綵霞，不知牆外是誰家。", "重門深鎖無尋處，疑有碧桃千樹花。"]'),
('e39922da-9ec5-488a-a87a-93bfdd9d6ea6','登丹陽北樓','郎士元','唐','唐诗','tang','','[]','寒臯那可望，旅望又初還。',48,'全唐诗/poet.tang.13000.json','["寒臯那可望，旅望又初還。", "迢遰高樓上，蕭條曠野閑。", "暮晴依遠水，秋興屬連山。", "浮客時相見，霜凋動翠顏。"]'),
('35b3a0df-11b4-46ae-bc44-f58f19a51447','題精舍寺','郎士元','唐','唐诗','tang','','[]','石林精舍武溪東，夜扣禪關謁遠公。',64,'全唐诗/poet.tang.13000.json','["石林精舍武溪東，夜扣禪關謁遠公。", "月在上方諸品靜，僧持半偈萬緣空。", "秋山竟日聞猨嘯，落木寒泉聽不窮。", "惟有雙峰最高頂，此心期與故人同。"]'),
('bcea2070-7313-49ff-b095-27b364df6406','雙林寺謁傅大士','郎士元','唐','唐诗','tang','','[]','草露經前代，津梁及後人。',48,'全唐诗/poet.tang.13000.json','["草露經前代，津梁及後人。", "此方今示滅，何國更分身。", "月色空知夜，松陰不記春。", "猶憐下生日，應在一微塵。"]'),
('b23f740f-f87b-46dd-82a8-2a01423525a6','題尹真人祠','郎士元','唐','唐诗','tang','','[]','窅窅雲旗去不還，陰陰祠宇閉空山。',32,'全唐诗/poet.tang.13000.json','["窅窅雲旗去不還，陰陰祠宇閉空山。", "我來始悟丹青妙，稽首如逢冰雪顏。"]'),
('06e1562f-9efe-497c-b540-7bd7031022e0','山中即事','郎士元','唐','唐诗','tang','','[]','入谷多春興，乘舟棹碧潯。',24,'全唐诗/poet.tang.13000.json','["入谷多春興，乘舟棹碧潯。", "山雲昨夜雨，溪水曉來深。"]'),
('7ba844f7-b593-42d1-95f1-ebfe27f2a077','湘夫人二首 一','郎士元','唐','唐诗','tang','','[]','蛾眉對湘水，遙哭蒼梧山。',36,'全唐诗/poet.tang.13000.json','["蛾眉對湘水，遙哭蒼梧山。", "萬乘既已歿，孤舟誰忍還。", "至今楚竹上，猶有淚痕斑。"]'),
('25be9870-8794-4702-bdb9-8ed2a7df8051','湘夫人二首 二','郎士元','唐','唐诗','tang','','[]','南有涔陽路，渺渺多新愁。',36,'全唐诗/poet.tang.13000.json','["南有涔陽路，渺渺多新愁。", "桂酒神降時，迴風江上秋。", "彩雲忽無處，碧水空安流。"]'),
('45cd0d5e-957f-4ee4-bf93-35b8935f526c','蓋少府新除江南尉問風俗','郎士元','唐','唐诗','tang','','[]','聞君作尉向江潭，吳越風煙到自諳。',64,'全唐诗/poet.tang.13000.json','["聞君作尉向江潭，吳越風煙到自諳。", "客路尋常隨竹影，人家大底傍山嵐。", "緣溪花木偏宜遠，避地衣冠盡向南。", "惟有夜猨啼海樹，思鄉望國意難堪。"]'),
('75bd5871-849f-4d90-9931-4eb7e033abff','春宴張舍人宅','郎士元','唐','唐诗','tang','','[]','嬾尋芳草徑，來接侍臣筵。',48,'全唐诗/poet.tang.13000.json','["嬾尋芳草徑，來接侍臣筵。", "山色知殘雨，牆陰覺暮天。", "鶯啼漢宮柳，花隔杜陵煙。", "地與東城接，春光醉目前。"]'),
('8367b4a1-da94-463e-9ccf-5417a0cb5735','寄李袁州桑落酒','郎士元','唐','唐诗','tang','','[]','色比瓊漿猶嫩，香同甘露仍春。',28,'全唐诗/poet.tang.13000.json','["色比瓊漿猶嫩，香同甘露仍春。", "十千提攜一斗，遠送瀟湘故人。"]'),
('b1cb1f50-691a-4546-b23b-71c7084c58ef','贈萬生下第還吳','郎士元','唐','唐诗','tang','','[]','直道多不偶，美才應息機。',48,'全唐诗/poet.tang.13000.json','["直道多不偶，美才應息機。", "灞陵春欲暮，雲海獨言歸。", "爲客成白首，入門嗟布衣。", "蓴羹若可憶，慙出掩柴扉。"]'),
('2de75be6-b6a5-44ce-b263-459a14d6d20b','送大德講時河東徐明府招','郎士元','唐','唐诗','tang','','[]','遠近作人天，王城指日邊。',48,'全唐诗/poet.tang.13000.json','["遠近作人天，王城指日邊。", "宰君迎說法，童子伴隨緣。", "到處花爲雨，行時杖出泉。", "今宵松月下，開閣想安禪。"]'),
('e6fd205b-a5b4-415a-87f4-ad87b918ebbb','赴無錫別靈一上人','郎士元','唐','唐诗','tang','','[]','高僧本姓竺，開士舊名林。',48,'全唐诗/poet.tang.13000.json','["高僧本姓竺，開士舊名林。", "一入春山裏，千峰不可尋。", "新年芳草徧，度日白雲深。", "欲問微官去，懸知訝此心。"]'),
('fe072a84-b2e7-41a4-8045-54607d073e09','送粲上人兼寄梁鎮員外','郎士元','唐','唐诗','tang','','[]','季月還鄉獨未能，林行溪宿厭層冰。',64,'全唐诗/poet.tang.13000.json','["季月還鄉獨未能，林行溪宿厭層冰。", "尺素欲傳三署客，雪山愁送五天僧。", "連空朔氣橫秦苑，滿目寒雲隔灞陵。", "借問從來香積寺，何時攜手更同登。"]'),
('17f33bdc-0ce3-4527-960c-69cd20198276','送韋逸人歸鍾山','郎士元','唐','唐诗','tang','','[]','逸人歸路遠，弟子出山迎。',48,'全唐诗/poet.tang.13000.json','["逸人歸路遠，弟子出山迎。", "服藥顏猶駐，耽書癖已成。", "柴扉多歲月，藜杖見公卿。", "更作儒林傳，應須載姓名。"]'),
('202ec2f2-f2a3-41f5-a9f0-b4ecd577f38b','登無錫北樓','郎士元','唐','唐诗','tang','','[]','秋興因危堞，歸心過遠山。',48,'全唐诗/poet.tang.13000.json','["秋興因危堞，歸心過遠山。", "風霜征鴈早，江海旅人還。", "驛樹寒仍密，漁舟晚更閑。", "仲宣何所賦，秪欲滯柴關。"]'),
('9fb8dfe5-540c-4e2e-b12a-085273a6cf99','和王相公題中書叢竹寄上元相公','郎士元','唐','唐诗','tang','','[]','多時仙掖裏，色並翠琅玕。',48,'全唐诗/poet.tang.13000.json','["多時仙掖裏，色並翠琅玕。", "幽意含煙月，清陰庇蕙蘭。", "枝繁宜露重，葉老愛天寒。", "竟日雙鸞止，孤吟爲一看。"]'),
('32ddf299-92d9-437e-b92a-266fe1091086','酬蕭二十七侍御初秋言懷','郎士元','唐','唐诗','tang','','[]','楚客秋多興，江林月漸生。',48,'全唐诗/poet.tang.13000.json','["楚客秋多興，江林月漸生。", "細枝涼葉動，極浦早鴻聲。", "勝賞睽前夕，新詩報遠情。", "曲高慙和者，惆悵閉寒城。"]'),
('2ca536e1-2a86-411f-a29a-99353ae5f202','奉和杜相公益昌路作','郎士元','唐','唐诗','tang','','[]','春半梁山正落花，台衡受律向天涯。',64,'全唐诗/poet.tang.13000.json','["春半梁山正落花，台衡受律向天涯。", "南去猨聲傍雙節，西來江色遶千家。", "風吹畫角孤城曉，林映蛾眉片月斜。", "已見廟謨能喻蜀，新文更喜報金華。"]'),
('a8f9fd2f-e6d6-4e29-b10f-b50072e676fc','賦得長洲苑送李惠','郎士元','唐','唐诗','tang','','[]','草深那可訪，地久阻相傳。',48,'全唐诗/poet.tang.13000.json','["草深那可訪，地久阻相傳。", "散漫三秋雨，疎蕪萬里煙。", "都迷採蘭處，強記館娃年。", "客有遊吳者，臨風思眇然。"]'),
('8e1808a4-793f-4410-a2fb-9a537bae879c','別房士清','郎士元','唐','唐诗','tang','','[]','世路還相見，偏堪淚滿衣。',48,'全唐诗/poet.tang.13000.json','["世路還相見，偏堪淚滿衣。", "那能郢門別，獨向鄴城歸。", "平楚看蓬轉，連山望鳥飛。", "蒼蒼歲陰暮，況復惜馳暉。"]'),
('3e3fdefb-adbd-4caa-a860-765af1cfd941','送彭偃房由赴朝因寄錢大郎中李十七舍人','郎士元','唐','唐诗','tang','','[]','衰病已經年，西峰望楚天。',48,'全唐诗/poet.tang.13000.json','["衰病已經年，西峰望楚天。", "風光欺鬢髮，秋色換山川。", "寂寞浮雲外，支離漢水邊。", "平生故人遠，君去話潸然。"]'),
('33e38478-98e6-4836-addf-14101678d2a4','送李遂之越','郎士元','唐','唐诗','tang','','[]','未習風波事，初爲東越遊。',48,'全唐诗/poet.tang.13000.json','["未習風波事，初爲東越遊。", "露霑湖草晚，月照海山秋。", "梅市門何處，蘭亭水向流。", "西興待潮信，落日滿孤舟。"]'),
('9d50e67d-f380-4e9d-9fe4-826a985dfd54','送鄭正則徐州行營','郎士元','唐','唐诗','tang','','[]','從軍非隴頭，師在古徐州。',48,'全唐诗/poet.tang.13000.json','["從軍非隴頭，師在古徐州。", "氣勁三河卒，功全萬戶侯。", "元戎閫外略，才子握中籌。", "莫聽關山曲，還生塞上愁。"]'),
('b6210ab6-af10-41ce-b847-ad41e94aaf8a','送錢拾遺歸兼寄劉校書','郎士元','唐','唐诗','tang','','[]','墟落歲陰暮，桑榆煙景昏。',48,'全唐诗/poet.tang.13000.json','["墟落歲陰暮，桑榆煙景昏。", "蟬聲靜空館，雨色隔秋原。", "歸客不可望，悠然林外村。", "終當報芸閣，攜手醉柴門。"]'),
('fbccad2c-0218-4e85-8b44-16128ba951de','送郴縣裴明府之任兼充宣慰','郎士元','唐','唐诗','tang','','[]','白蘋楚水三湘遠，芳草秦城二月初。',64,'全唐诗/poet.tang.13000.json','["白蘋楚水三湘遠，芳草秦城二月初。", "連鴈北飛看欲盡，孤舟南去意何如。", "渡江野老思求瘼，候館郴人憶下車。", "別後天涯何所寄，故交惟有袖中書。"]'),
('e7c2c954-dd46-4b72-8609-ff75bef665c1','送李敖湖南書記','郎士元','唐','唐诗','tang','','[]','憐君才與阮家同，掌記能資亞相雄。',64,'全唐诗/poet.tang.13000.json','["憐君才與阮家同，掌記能資亞相雄。", "入楚豈忘看淚竹，泊舟應自愛江楓。", "誠知客夢煙波裏，肯厭猨鳴夜雨中。", "莫信衡湘書不到，年年秋鴈過巴東。"]'),
('fe59eb75-1737-4f12-be68-af8876fd47ff','送麴司直','郎士元','唐','唐诗','tang','','[]','曙雪蒼蒼兼曙雲，朔風煙鴈不堪聞。',32,'全唐诗/poet.tang.13000.json','["曙雪蒼蒼兼曙雲，朔風煙鴈不堪聞。", "貧交此別無他贈，唯有青山遠送君。"]'),
('703f40c7-74fc-4155-972b-673b8742b5df','送別','郎士元','唐','唐诗','tang','','[]','穆陵關上秋雲起，安陸城邊遠行子。',32,'全唐诗/poet.tang.13000.json','["穆陵關上秋雲起，安陸城邊遠行子。", "薄暮寒蟬三兩聲，迴頭故鄉千萬里。"]'),
('028b4cb8-66a0-4935-b7f5-b75760a688a1','咸陽西樓別竇審','郎士元','唐','唐诗','tang','','[]','西樓迴起寒原上，霽日遙分萬井間。',64,'全唐诗/poet.tang.13000.json','["西樓迴起寒原上，霽日遙分萬井間。", "小苑城隅連渭水，離宮曙色近京關。", "亭臯寂寞傷孤客，雲雪蕭條滿衆山。", "時命如今猶未偶，辭君擬欲拂衣還。"]'),
('b6d6ce47-371d-43d0-a96c-ffe83083892c','聞蟬寄友人','郎士元','唐','唐诗','tang','','[]','昨日始聞鶯，今朝蟬又鳴。',48,'全唐诗/poet.tang.13000.json','["昨日始聞鶯，今朝蟬又鳴。", "朱顏向華髮，定是幾年程。", "故國白雲遠，閑居青草生。", "因垂數行淚，書寄十年兄。"]'),
('dd8425fc-1637-4f3d-8af1-c13dc740c6f8','送李騎曹之靈武寧侍','郎士元','唐','唐诗','tang','','[]','一歲一歸寧，涼天數騎行。',48,'全唐诗/poet.tang.13000.json','["一歲一歸寧，涼天數騎行。", "河來當塞曲，山遠與沙平。", "縱獵旗風卷，聽笳帳月生。", "新鴻引寒色，迴日滿京城。"]'),
('3edd1919-8eaa-4a85-b05e-97f6f10a2d19','馮翊西樓','郎士元','唐','唐诗','tang','','[]','城上西樓倚暮天，樓中歸望正淒然。',64,'全唐诗/poet.tang.13000.json','["城上西樓倚暮天，樓中歸望正淒然。", "近郭亂山橫古渡，野莊喬木帶新煙。", "北風吹鴈聲能苦，遠客辭家月再圓。", "陶令好文常對酒，相招一和白雲篇。"]'),
('bc565d9d-ab21-4e86-8a65-c222a0d21eb5','郢城秋望','郎士元','唐','唐诗','tang','','[]','白首思歸歸不得，空山聞鴈鴈聲哀。',32,'全唐诗/poet.tang.13000.json','["白首思歸歸不得，空山聞鴈鴈聲哀。", "高城落日望西北，又見秋風逐水來。"]'),
('cc1cee37-7c51-4168-bdfa-62f2a968c12f','夜泊湘江','郎士元','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湘山木落洞庭波，湘水連雲秋鴈多。',32,'全唐诗/poet.tang.13000.json','["湘山木落洞庭波，湘水連雲秋鴈多。", "寂寞舟中誰借問，月明只自聽漁歌。"]'),
('c03d44ee-9791-45a2-a9e7-f42e42065b2b','留別常著','郎士元','唐','唐诗','tang','','[]','歲晏蒼郊蓬轉時，遊人相見說歸期。',32,'全唐诗/poet.tang.13000.json','["歲晏蒼郊蓬轉時，遊人相見說歸期。", "宓君堂上能留客，明日還家應未遲。"]'),
('1e1541d8-c0ef-4732-8d77-3a87cc06b4fe','送張光歸吳','郎士元','唐','唐诗','tang','','[]','看取庭蕪白露新，勸君不用久風塵。',32,'全唐诗/poet.tang.13000.json','["看取庭蕪白露新，勸君不用久風塵。", "秋來多見長安客，解愛鱸魚能幾人。"]'),
('16dbc4d3-1930-4f57-8d30-c358ec7ba315','聞吹楊葉者二首 一','郎士元','唐','唐诗','tang','','[]','妙吹楊葉動悲笳，胡馬迎風起恨賒。',32,'全唐诗/poet.tang.13000.json','["妙吹楊葉動悲笳，胡馬迎風起恨賒。", "若是鴈門寒月夜，此時應卷盡驚沙。"]'),
('3d5c77d4-1ce5-458f-bf76-648539c0a0b2','聞吹楊葉者二首 二','郎士元','唐','唐诗','tang','','[]','天生一藝更無倫，寥亮幽音妙入神。',32,'全唐诗/poet.tang.13000.json','["天生一藝更無倫，寥亮幽音妙入神。", "吹向別離攀折處，當應合有斷腸人。"]'),
('39daba5b-8a7e-44f7-9f72-e2aa77337e3f','潤州南郭留別','皇甫冉','唐','唐诗','tang','','[]','縈迴楓葉岸，留滯木蘭橈。',48,'全唐诗/poet.tang.13000.json','["縈迴楓葉岸，留滯木蘭橈。", "吳岫新經雨，江天正落潮。", "故人勞見愛，行客自無聊。", "君問前程事，孤雲入剡遙。"]'),
('5c0f4002-028c-4f2a-981a-44f1c13326a4','祭張公洞二首 一','皇甫冉','唐','唐诗','tang','','[]','堯心知稼穡，精意遶山川。',48,'全唐诗/poet.tang.13000.json','["堯心知稼穡，精意遶山川。", "風雨神祇應，笙鏞詔命傳。", "沐蘭秪掃地，酌桂佇靈仙。", "拂霧陳金策，焚香拜玉筵。"]'),
('c20c82da-8b24-4a6a-8594-e57bbcdf5bba','祭張公洞二首 二','皇甫冉','唐','唐诗','tang','','[]','雲開小有洞，日出大羅天。',48,'全唐诗/poet.tang.13000.json','["雲開小有洞，日出大羅天。", "三鳥隨王母，雙童翊子先。", "何時種核桃，幾度看桑田。", "倏忽煙霞散，空巖騎吏旋。"]'),
('7fc442f0-cd4d-44c9-bfe9-009f2df80640','臨平道贈同舟人','皇甫冉','唐','唐诗','tang','','[]','遠山誰辨江南北，長路空隨樹淺深。',32,'全唐诗/poet.tang.13000.json','["遠山誰辨江南北，長路空隨樹淺深。", "流蕩飄颻此何極，唯應行客共知心。"]'),
('ac2c6ee1-d73d-44cb-a0ad-c54aacc1a4c6','巫山峽','皇甫冉','唐','唐诗','tang','','[]','巫峽見巴東，迢迢出半空。',48,'全唐诗/poet.tang.13000.json','["巫峽見巴東，迢迢出半空。", "雲藏神女館，雨到楚王宮。", "朝暮泉聲落，寒暄樹色同。", "清猿不可聽，偏在九秋中。"]'),
('251010ed-b2b6-4170-959e-58b4de7fb5a3','長安路','皇甫冉','唐','唐诗','tang','','[]','長安九城路，戚里五侯家。',48,'全唐诗/poet.tang.13000.json','["長安九城路，戚里五侯家。", "結束趨平樂，聯翩抵狹斜。", "高樓臨遠水，複道出繁花。", "唯見相如宅，蓬門度歲華。"]'),
('d61b1601-9208-47f8-8478-79da59ab09c0','送朱逸人','皇甫冉','唐','唐诗','tang','','[]','時人多不見，出入五湖間。',48,'全唐诗/poet.tang.13000.json','["時人多不見，出入五湖間。", "寄酒全吾道，移家愛遠山。", "更看秋草暮，欲共白雲還。", "雖在風塵裹，陶潛身自閑。"]'),
('38bd81f9-fb49-462f-a0be-035ca1619183','西陵寄靈一上人','皇甫冉','唐','唐诗','tang','','[]','西陵遇風處，自古是通津。',48,'全唐诗/poet.tang.13000.json','["西陵遇風處，自古是通津。", "終日空江上，雲山若待人。", "汀洲寒事早，魚鳥興情新。", "迴望山陰路，心中有所親。"]'),
('95a51837-2d7d-471e-8b98-fc0a61ef13e3','赴無錫寄別靈一淨虛二上人雲門所居','皇甫冉','唐','唐诗','tang','','[]','高僧本姓竺，開士舊名林。',48,'全唐诗/poet.tang.13000.json','["高僧本姓竺，開士舊名林。", "一入春山裏，千峰不可尋。", "新年芳草徧，終日白雲深。", "欲徇微官去，懸知訝此心。"]'),
('7a220432-9c40-4633-8366-b88899114fc7','舟中送李八','皇甫冉','唐','唐诗','tang','','[]','詞客金門未有媒，遊吳適越任舟迴。',32,'全唐诗/poet.tang.13000.json','["詞客金門未有媒，遊吳適越任舟迴。", "遠水迢迢分手去，天邊山色待人來。"]'),
('7552cc24-70f8-4885-8ff2-f5265e6391c4','與張補闕王鍊師自徐方清路同舟南下於臺頭寺留別趙員外裴補闕同賦雜題一首','皇甫冉','唐','唐诗','tang','','[]','朝朝春事晚，泛泛行舟遠。',84,'全唐诗/poet.tang.13000.json','["朝朝春事晚，泛泛行舟遠。", "淮海思無窮，悠揚煙景中。", "幸將仙子去，復與故人同。", "高枕隨流水，輕帆任遠風。", "鐘聲野寺逈，草色故城空。", "送別高臺上，裴回共惆悵。", "懸知白日斜，定是猶相望。"]'),
('06a36892-9b3b-4d19-a3fa-092096ccd1e5','酬張二仲彝','皇甫冉','唐','唐诗','tang','','[]','吳洲見芳草，楚客動歸心。',72,'全唐诗/poet.tang.13000.json','["吳洲見芳草，楚客動歸心。", "屈宋鄉山古，荆衡煙雨深。", "艱難十載別，羈旅四愁侵。", "澧月通沅水，湘雲入桂林。", "已看生白髮，當爲乏黃金。", "江海時相見，唯聞梁甫吟。"]'),
('a656ee4a-a803-40a8-a06c-a935d5c630d4','三月三日義興李明府後亭泛舟','皇甫冉','唐','唐诗','tang','','[]','江南煙景復如何，聞道新亭更可過。',64,'全唐诗/poet.tang.13000.json','["江南煙景復如何，聞道新亭更可過。", "處處蓻蘭春浦綠，萋萋藉草遠山多。", "壺觴須就陶彭澤，時俗猶傳晉永和。", "更使輕橈徐轉去，微風落日水增波。"]'),
('cb1ff5ce-b5ff-475f-a307-b9c7740169d7','少室山韋鍊師昇仙歌','皇甫冉','唐','唐诗','tang','','[]','紅霞紫氣晝氳氳，絳節青幢迎少君。',32,'全唐诗/poet.tang.13000.json','["紅霞紫氣晝氳氳，絳節青幢迎少君。", "忽從林下昇天去，空使時人禮白雲。"]'),
('edf798b9-3594-4320-bcbd-dfd9f6ef22b6','獨孤中丞筵陪餞韋君赴昇州','皇甫冉','唐','唐诗','tang','','["\u957f\u6c5f"]','中司龍節貴，上客虎符新。',48,'全唐诗/poet.tang.13000.json','["中司龍節貴，上客虎符新。", "地控吳襟帶，才高漢縉紳。", "泛舟應度臘，入境便行春。", "處處歌來暮，長江建業人。"]'),
('f1befe2e-2e4d-4220-aa06-5fae1d3a1a04','送王緒剡中','皇甫冉','唐','唐诗','tang','','[]','不見關山去，何時到郯中。',48,'全唐诗/poet.tang.13000.json','["不見關山去，何時到郯中。", "已聞成竹木，更道長兒童。", "籬落雲常聚，村墟水自通。", "朝朝憶玄度，非是對清風。"]'),
('b4df1827-8d5d-4cbb-ba7e-e5d7cf1a787d','詶李郎中侍御秋夜登福州城樓見寄','皇甫冉','唐','唐诗','tang','','[]','辛勤萬里道，簫索九秋殘。',48,'全唐诗/poet.tang.13000.json','["辛勤萬里道，簫索九秋殘。", "月照閩中夜，天凝海上寒。", "王程無地遠，主意在人安。", "遙寄登樓作，空知行路難。"]'),
('7ac7a41b-3f34-4af0-8b38-d16be263c2c9','同李司直諸公暑夜南餘館','皇甫冉','唐','唐诗','tang','','[]','何處多明月，津亭暑夜深。',48,'全唐诗/poet.tang.13000.json','["何處多明月，津亭暑夜深。", "煙霞不可望，雲樹更沈沈。", "好是吳中隱，仍爲洛下吟。", "微官朝復夕，牽強亦何心。"]'),
('35d74803-47e5-41c2-9631-a9ef240491e0','贈普門上人','皇甫冉','唐','唐诗','tang','','[]','支公身欲老，長在沃州多。',48,'全唐诗/poet.tang.13000.json','["支公身欲老，長在沃州多。", "慧力堪傳敎，禪功久伏魔。", "山雲隨坐夏，江草伴頭陀。", "借問迴心後，賢愚去幾何。"]'),
('5a9f059d-a423-47f4-a818-47a708dd2cf6','與諸公同登無錫北樓','皇甫冉','唐','唐诗','tang','','[]','秋興因危堞，歸心過遠山。',48,'全唐诗/poet.tang.13000.json','["秋興因危堞，歸心過遠山。", "風霜征雁早，江海旅人閑。", "驛樹寒仍密，漁舟晚自還。", "仲宣何所賦，秪歎在荆蠻。"]'),
('f411dd36-1eb8-492e-845a-9c933e4ad5a9','同李蘇州傷美人','皇甫冉','唐','唐诗','tang','','[]','玉佩石榴裙，當年嫁使君。',48,'全唐诗/poet.tang.13000.json','["玉佩石榴裙，當年嫁使君。", "專房猶見寵，傾國衆皆聞。", "歌舞常無對，幽明忽此分。", "陽臺千萬里，何處作朝雲。"]'),
('c83ab760-cd85-407c-8bb5-e5344a2754d3','送李錄事赴饒州','皇甫冉','唐','唐诗','tang','','[]','北人南去雪紛紛，雁叫汀沙不可聞。',64,'全唐诗/poet.tang.13000.json','["北人南去雪紛紛，雁叫汀沙不可聞。", "積水長天隨遠客，荒城極浦足寒雲。", "山從建業千峰出，江至潯陽九派分。", "借問督郵纔弱冠，府中年少不如君。"]'),
('974d7215-4150-44b0-9a5f-f519ff1a048d','同諸公有懷絕句','皇甫冉','唐','唐诗','tang','','[]','舊國迷江樹，他鄉近海門。',24,'全唐诗/poet.tang.13000.json','["舊國迷江樹，他鄉近海門。", "移家南渡久，童稚解方言。"]'),
('cc6e2ebd-2648-49f9-8c2c-944b83fb212e','題魏仲光淮山所居','皇甫冉','唐','唐诗','tang','','[]','人群不相見，乃在白雲間。',48,'全唐诗/poet.tang.13000.json','["人群不相見，乃在白雲間。", "問我將何適，羨君今獨閑。", "朝朝汲淮水，暮暮上龜山。", "幸已安貧定，當從鬢髮斑。"]'),
('eada0234-be9a-4e8a-ac91-fef409a4a9cb','送鄭判官赴徐州','皇甫冉','唐','唐诗','tang','','[]','從軍非隴頭，師在古徐州。',48,'全唐诗/poet.tang.13000.json','["從軍非隴頭，師在古徐州。", "氣勁三河卒，功多萬里侯。", "元戎閫外令，才子幄中籌。", "莫聽關山曲，還生出塞愁。"]'),
('1d1043ef-c463-450c-96ca-73567acef3b6','送顧萇往新安','皇甫冉','唐','唐诗','tang','','[]','由來山水客，復道向新安。',48,'全唐诗/poet.tang.13000.json','["由來山水客，復道向新安。", "半是乘潮便，全非行路難。", "晨裝林月在，野飯浦沙寒。", "嚴子千年後，何人釣舊灘。"]'),
('6fc239af-e267-4a89-a804-330cf037dcb5','秋夜有懷高三十五兼呈空和尚','皇甫冉','唐','唐诗','tang','','[]','晚節聞君趨道深，結茅栽樹近東林。',64,'全唐诗/poet.tang.13000.json','["晚節聞君趨道深，結茅栽樹近東林。", "大師幾度曾摩頂，高士何年遂發心。", "北渚三更聞過雁，西城萬里動寒砧。", "不見支公與玄度，相思擁膝坐長吟。"]'),
('b497a5f2-7762-43d6-b788-c6a1d7f20bed','途中送權三兄弟','皇甫冉','唐','唐诗','tang','','[]','淮海風濤起，江關憂思長。',48,'全唐诗/poet.tang.13000.json','["淮海風濤起，江關憂思長。", "同悲鵲遶樹，獨作雁隨陽。", "山晚雲初雪，汀寒月照霜。", "由來濯纓處，漁父愛滄浪。"]'),
('8954ab80-1480-4de3-abdb-06121c8493b2','送裴闡','皇甫冉','唐','唐诗','tang','','[]','道向毗陵豈是歸，客中誰與換春衣。',32,'全唐诗/poet.tang.13000.json','["道向毗陵豈是歸，客中誰與換春衣。", "今夜孤舟行近遠，子荆零雨正霏霏。"]'),
('e4a1f615-2b63-4797-8b7a-3ea3708722df','雜言湖山歌送許鳴謙','皇甫冉','唐','唐诗','tang','','[]','湖中之山兮波上青，桂颯颯兮雨冥冥。',100,'全唐诗/poet.tang.13000.json','["湖中之山兮波上青，桂颯颯兮雨冥冥。", "君歸兮春早，滿山兮碧草。", "晨舂暮汲兮心何求，澗戶巖扉兮身自老。", "東嶺西峰兮同白雲，雞鳴犬吠兮時相聞。", "幽芳媚景兮當嘉月，踐石捫蘿兮恣超忽。", "空山寂寂兮潁陽人，旦夕孤雲隨一身。"]'),
('23c94e20-704b-42b2-a2e8-bc9f8a851232','雜言迎神詞二首 迎神','皇甫冉','唐','唐诗','tang','','[]','啓庭戶，列芳鮮，目眇眇，心綿綿，因風託雨降瓊筵。',40,'全唐诗/poet.tang.13000.json','["啓庭戶，列芳鮮，目眇眇，心綿綿，因風託雨降瓊筵。", "紛下拜，屢加籩，人心望歲祈豐年。"]'),
('ea87f475-1d06-4516-9a65-bd30c39813eb','雜言迎神詞二首 送神','皇甫冉','唐','唐诗','tang','','[]','露霑衣，月隱壁，氣淒淒，人寂寂，風迴雨度虛瑤席。',40,'全唐诗/poet.tang.13000.json','["露霑衣，月隱壁，氣淒淒，人寂寂，風迴雨度虛瑤席。", "來無聲，去無跡，神心降和福遠客。"]'),
('03c89a38-5646-48b3-ad64-0b936125b979','屏風上各賦一物得攜琴客','皇甫冉','唐','唐诗','tang','','[]','不是向空林，應當就磐石。',36,'全唐诗/poet.tang.13000.json','["不是向空林，應當就磐石。", "白雲知隱處，芳草迷行跡。", "如何秪役心，見爾攜琴客。"]'),
('ae58610a-ba60-4fa4-8d76-97478b3ee43d','江草歌送盧判官','皇甫冉','唐','唐诗','tang','','[]','江臯兮春早，江上兮芳草。',137,'全唐诗/poet.tang.13000.json','["江臯兮春早，江上兮芳草。", "雜蘼蕪兮杜蘅，作叢秀兮欲羅生。", "被遙隰兮經長衍，雨中深兮煙中淺。", "目眇眇兮增愁，步遲遲兮堪搴。", "澧之浦兮湘之濱，思夫君兮送美人。", "吳洲曲兮楚鄉路，遠孤城兮依獨戎。", "新月能分裛露時，夕陽照見連天處。", "問君行邁將何之，淹泊沿洄風日遲。", "處處汀洲有芳草，王孫詎肯念歸期。"]'),
('c4d8ac50-fbb4-4823-aa34-efd17ca1970d','題畫帳二首 山水','皇甫冉','唐','唐诗','tang','','[]','桂水饒楓杉，荆南足煙雨。',24,'全唐诗/poet.tang.13000.json','["桂水饒楓杉，荆南足煙雨。", "猶疑黛色中，復是雒陽岨。"]'),
('62830474-3427-4338-9a08-5812d7532c7f','題畫帳二首 遠帆','皇甫冉','唐','唐诗','tang','','[]','朝見巴江客，暮見巴江客。',24,'全唐诗/poet.tang.13000.json','["朝見巴江客，暮見巴江客。", "雲帆儻暫停，中路陽臺夕。"]'),
('8090d749-4cf1-4d08-8d13-52eb93687fc7','落第後東遊留別','皇甫冉','唐','唐诗','tang','','[]','功成方自得，何事學干求。',48,'全唐诗/poet.tang.13000.json','["功成方自得，何事學干求。", "果以浮名誤，深貽達士羞。", "九江連漲海，萬里任虛舟。", "歲晚同懷客，相思波上鷗。"]'),
('c31b402f-fafa-40e4-af3b-a6f82d3801df','雜言月洲歌送趙冽還襄陽','皇甫冉','唐','唐诗','tang','','[]','漢之廣矣中有洲，洲如月兮水環流。',124,'全唐诗/poet.tang.13000.json','["漢之廣矣中有洲，洲如月兮水環流。", "流聒聒兮湍與瀨，草青青兮春更秋。", "苦竹林，香楓樹，樵子罛師幾家住。", "萬山飛雨一川來，巴客歸船傍洲去。", "歸人不可遲，芳杜滿洲時。", "無限風煙皆自悲，莫辭貧賤阻心期。", "家住洲頭定近遠，朝泛輕橈暮當返。", "不能隨爾臥芳洲，自念天機一何淺。"]'),
('663600d9-fbb8-4336-96b3-5bf5cad96945','寄劉八山中','皇甫冉','唐','唐诗','tang','','[]','東臯若近遠，苦雨隔還期。',48,'全唐诗/poet.tang.13000.json','["東臯若近遠，苦雨隔還期。", "閨歲風霜晚，山田收穫遲。", "茅簷燕去後，樵路菊黃時。", "平子遊都久，知君坐見嗤。"]'),
('e06dea87-6b5e-4f85-9f18-a4cfa4a53401','答張諲劉方平兼呈賀蘭廣','皇甫冉','唐','唐诗','tang','','[]','野性難馴狎，荒郊自閉門。',72,'全唐诗/poet.tang.13000.json','["野性難馴狎，荒郊自閉門。", "心閑同海鳥，日夕戀山村。", "屢枉瓊瑤贈，如今道術存。", "遠峯時振策，春雨耐香源。", "復有故人在，寧聞廬鵲喧。", "青青草色綠，終是待王孫。"]'),
('a1255e7f-9db9-45a3-85cf-ad00559a3e58','灃水送鄭鄠縣讀書','皇甫冉','唐','唐诗','tang','','[]','麥秋中夏涼風起，送君西郊及灃水。',64,'全唐诗/poet.tang.13000.json','["麥秋中夏涼風起，送君西郊及灃水。", "孤煙遠樹動離心，隔岸江流若千里。", "早年江海謝浮名，此路雲山愜爾情。", "上古全經皆在口，秦人如見濟南生。"]'),
('1626b02f-b09d-4620-89a6-ffb8edef5190','九日寄鄭豐','皇甫冉','唐','唐诗','tang','','[]','重陽秋已晚，千里信仍稀。',48,'全唐诗/poet.tang.13000.json','["重陽秋已晚，千里信仍稀。", "何處登高望，知君正憶歸。", "還當採時菊，定未授寒衣。", "欲識離居恨，郊園正掩扉。"]'),
('f20774d3-7cb2-4ce2-aa36-32d90b50413e','酬包評事壁畫山水見寄','皇甫冉','唐','唐诗','tang','','[]','一官知所傲，本意在雲泉。',84,'全唐诗/poet.tang.13000.json','["一官知所傲，本意在雲泉。", "濡翰生新興，群峰忽眼前。", "黛中分遠近，筆下起風煙。", "巖翠深樵路，湖光出釣船。", "寒侵赤城頂，日照武陵川。", "若覽名山誌，仍聞招隱篇。", "遂令江海客，惆悵憶閑田。"]'),
('9e2db41a-d15e-46b7-9a04-b9ab1e467d64','渡汝水向太和山','皇甫冉','唐','唐诗','tang','','[]','落日事搴陟，西南投一峯。',24,'全唐诗/poet.tang.13000.json','["落日事搴陟，西南投一峯。", "誠知秋水淺，但怯無人蹤。"]'),
('1ca96236-f393-4f2b-9a76-9691af094b99','秋怨','皇甫冉','唐','唐诗','tang','','[]','長信多秋氣，昭陽借月華。',24,'全唐诗/poet.tang.13000.json','["長信多秋氣，昭陽借月華。", "那堪閉永巷，聞道選良家。"]'),
('53540760-0c98-4266-b4e2-e6e39b49ca0c','贈鄭山人','皇甫冉','唐','唐诗','tang','','[]','白首滄洲客，陶然得此生。',120,'全唐诗/poet.tang.13000.json','["白首滄洲客，陶然得此生。", "龐公採藥去，萊氏與妻行。", "乍見還州里，全非隱姓名。", "枉帆臨海嶠，貰酒秣陵城。", "伐木吳山曉，持竿越水清。", "家人恣貧賤，物外任衰榮。", "忽爾辭林壑，高歌至上京。", "避喧心已慣，念遠夢頻成。", "石路寒花發，江田臘雪明。", "玄纁倘有命，何以遂躬耕。"]'),
('e8c0f1c2-a2f3-4278-a666-80404d0fdd26','劉方平西齋對雪','皇甫冉','唐','唐诗','tang','','[]','對酒閑齋晚，開軒臘雪時。',48,'全唐诗/poet.tang.13000.json','["對酒閑齋晚，開軒臘雪時。", "花飄疑節候，色淨潤簾帷。", "委樹寒枝弱，縈空去雁遲。", "自然堪訪戴，無復四愁詩。"]'),
('43aa9830-55bf-4565-8ca1-38658b6ed048','福先寺尋湛然寺主不見','皇甫冉','唐','唐诗','tang','','[]','寂然空佇立，往往報疎鐘。',48,'全唐诗/poet.tang.13000.json','["寂然空佇立，往往報疎鐘。", "高館誰留客，東南二室峰。", "川原通霽色，田野變春容。", "惆悵層城暮，猶言歸路逢。"]'),
('9b72ab3f-89d3-4673-91a5-616aeb967f02','河南鄭少尹城南亭送鄭判官還河東','皇甫冉','唐','唐诗','tang','','[]','使臣懷餞席，亞尹有前溪。',72,'全唐诗/poet.tang.13000.json','["使臣懷餞席，亞尹有前溪。", "客是仙舟裏，途從御苑西。", "泉聲喧暗竹，草色引長堤。", "故絳青山在，新田綠樹齊。", "天秋聞別鵠，關曉待鳴雞。", "應歎沈冥者，年年津路迷。"]'),
('c2aa6bd9-7433-4336-9561-81f7d7bdb067','登玄元廟','皇甫冉','唐','唐诗','tang','','[]','古廟川原迥，重門禁籞連。',72,'全唐诗/poet.tang.13000.json','["古廟川原迥，重門禁籞連。", "海童紛翠蓋，羽客事瓊筵。", "御路分疎柳，離宮出苑田。", "興新無向背，望久辨山川。", "物外將遺老，區中誓絕緣。", "函關若遠近，紫氣獨依然。"]'),
('b6d20c68-6a13-491d-b88c-6f25bcd154b8','冬夜集賦得寒漏','皇甫冉','唐','唐诗','tang','','[]','清冬洛陽客，寒漏建章臺。',60,'全唐诗/poet.tang.13000.json','["清冬洛陽客，寒漏建章臺。", "出禁因風徹，縈窗共月來。", "偏將殘瀨雜，乍與遠鴻哀。", "遙夜重城警，流年滴水催。", "閑齋堪坐聽，況有故人杯。"]'),
('34f418f5-5f0c-4db3-9352-a2aea84eb414','玄元觀送李源李風還奉先華陰','皇甫冉','唐','唐诗','tang','','[]','此去那知道路遙，寒原紫府上迢迢。',64,'全唐诗/poet.tang.13000.json','["此去那知道路遙，寒原紫府上迢迢。", "莫辭別酒和瓊液，乍唱離歌和鳳簫。", "遠水東流浮落景，繚垣西轉失行鑣。", "華山秦塞長相憶，無使音塵頓寂寥。"]'),
('a5a57a4f-3095-4a5e-a9a4-6e2548104d43','劉方平壁畫山','皇甫冉','唐','唐诗','tang','','[]','墨妙無前，性生筆先。',40,'全唐诗/poet.tang.13000.json','["墨妙無前，性生筆先。", "迴溪已失，遠嶂猶連。", "側徑樵客，長林野煙。", "青峰之外，何處雲天。"]'),
('9130928b-e65e-421d-90d4-b8f2fc52bddf','登山歌','皇甫冉','唐','唐诗','tang','','[]','青山前，青山後，登高望兩處。',32,'全唐诗/poet.tang.13000.json','["青山前，青山後，登高望兩處。", "兩處今何有？", "煙景滿川原，離人堪白首。"]'),
('79497342-fc67-40d5-a09b-3fa21a1927af','和鄭少尹祭中岳寺北訪蕭居士越上方','皇甫冉','唐','唐诗','tang','','[]','肅寺祠靈境，尋真到隱居。',96,'全唐诗/poet.tang.13000.json','["肅寺祠靈境，尋真到隱居。", "夤緣幽谷遠，蕭散白雲餘。", "晚節持僧律，他年著道書。", "海邊曾狎鳥，濠上正觀魚。", "寂靜求無相，淳和覩太初。", "一峰綿歲月，萬性任盈虛。", "籬隔溪鐘度，窗臨澗木疎。", "謝公懷舊壑，迴駕復何如。"]'),
('9d69bbb1-6f02-4bdb-9b4c-1f3db7a985d1','秋夜寄所思','皇甫冉','唐','唐诗','tang','','[]','寂寞坐遙夜，清風何處來？',48,'全唐诗/poet.tang.13000.json','["寂寞坐遙夜，清風何處來？", "天高散騎省，月冷建章臺。", "鄰笛哀聲急，城砧朔氣催。", "芙蓉已委絕，誰復可爲媒。"]'),
('e67d398e-1ed0-4f1e-915e-e646dea8af66','賦得郢路悲猨','皇甫冉','唐','唐诗','tang','','[]','悲猨何處發？郢路第三聲。',48,'全唐诗/poet.tang.13000.json','["悲猨何處發？郢路第三聲。", "遠客知秋暮，空山益夜清。", "啾啾深衆木，嗷嗷入孤城。", "坐覺盈心耳，翛然適楚情。"]'),
('6e0488e2-d817-4e8d-a2dc-641a84bda578','雜言無錫惠山寺流泉歌','皇甫冉','唐','唐诗','tang','','[]','寺有泉兮泉在山，鏘金鳴玉兮長潺潺。',161,'全唐诗/poet.tang.13000.json','["寺有泉兮泉在山，鏘金鳴玉兮長潺潺。", "作潭鏡兮澄寺內，泛巖花兮到人間。", "土膏脉動知春早，隈隩陰深長苔草。", "處處縈迴石磴喧，朝朝盥漱山僧老。", "僧自老，松自新，流活活，無冬春。", "任疏鑿兮與汲引，若有意兮山中人。", "偏依佛界通仙境，明滅玲瓏媚林嶺。", "宛如太室臨九潭，詎減天台望三井。", "我來結綬未經秋，已厭微官憶舊遊。", "且復遲迴猶未去，此心秪爲靈泉留。"]'),
('00ec6f0d-71fd-4eb2-b460-f95cecab414f','清明日青龍寺上方賦得多字','皇甫冉','唐','唐诗','tang','','[]','上方偏可適。',48,'全唐诗/poet.tang.13000.json','["上方偏可適。", "季月況堪過，遠近水聲至。", "東西山色多，夕陽留徑草。", "新葉變庭柯，已度清明節。", "春秋如客何。"]'),
('3cc2682b-faa5-40c7-8af2-f73ba04ace91','與張諲宿劉八城東莊','皇甫冉','唐','唐诗','tang','','[]','人閑當歲暮，田野尚逢迎。',48,'全唐诗/poet.tang.13000.json','["人閑當歲暮，田野尚逢迎。", "萊子多嘉慶，陶公得此生。", "寒蕪連古渡，雲樹近嚴城。", "雞黍無辭薄，貧交但貴情。"]'),
('65f3a99f-b10f-4470-bd4a-f69de67a4607','寄劉方平','皇甫冉','唐','唐诗','tang','','[]','坐憶山中人，窮棲事南畝。',72,'全唐诗/poet.tang.13000.json','["坐憶山中人，窮棲事南畝。", "煙霞相親外，墟落今何有。", "潘郎作賦年，陶令辭官後。", "達生遺自適，良願固無負。", "田取潁水流，樹入陽城口。", "歲暮憂思盈，離居不堪久。"]'),
('d2e1c844-d9ad-4345-80b9-c3329d9ea2f2','曾東遊以詩寄之','皇甫冉','唐','唐诗','tang','','[]','出郭離言多，迴車始知遠。',216,'全唐诗/poet.tang.13000.json','["出郭離言多，迴車始知遠。", "寂然層城暮，更念前山轉。", "總轡越成臯，浮舟背梁苑。", "朝朝勞延首，往住若在眼。", "落日孤雲還，邊愁迷楚關。", "如何漵花發，復對遊子顏。", "古寺杉栝裏，連檣洲渚間。", "煙生海西岸，雲見吳南山。", "驚風掃蘆荻，翻浪連天白。", "正是揚帆時，偏逢江上客。", "由來許佳句，況乃愜所適。", "嵯峨天姥峰，翠色春更碧。", "氣淒湖上雨，月淨剡中夕。", "釣艇或相逢，江蘺又堪摘。", "迢迢始寧墅，蕪沒謝公宅。", "朱槿列摧墉，蒼苔徧幽石。", "顧予任疎懶，期爾振羽翮。", "滄洲未可行，須售金門策。"]'),
('9ccdfb1d-5f1c-4f71-9f96-affa24afacbb','適荆州途次南陽贈何明府','皇甫冉','唐','唐诗','tang','','[]','千里獨遊日，有懷誰與同。',96,'全唐诗/poet.tang.13000.json','["千里獨遊日，有懷誰與同。", "言過細陽令，一遇郎陵公。", "清節邁多士，斯文傳古風。", "閭閻知俗變，原野識年豐。", "吾道方在此，前程殊未窮。", "江天經峴北，客思滿巴東。", "夢渚夕愁遠，山丘晴望通。", "應嗟出處異，流蕩楚雲中。"]'),
('4e0e59a3-9d95-4a22-849a-fdc25fc2e3d8','秋夜戲題劉方平壁','皇甫冉','唐','唐诗','tang','','[]','鴻悲月白時將謝，正可招尋惜遙夜。',32,'全唐诗/poet.tang.13000.json','["鴻悲月白時將謝，正可招尋惜遙夜。", "翠帳蘭房曲且深，寧知戶外清霜下。"]'),
('9fcb6791-4b0f-4a32-84f9-fbebc30dd9c5','問正上人疾','皇甫冉','唐','唐诗','tang','','[]','醫王猶有疾，妙理競難窮。',48,'全唐诗/poet.tang.13000.json','["醫王猶有疾，妙理競難窮。", "餌藥應隨病，觀身轉悟空。", "地閑花欲雨，窗冷竹生風。", "幾日東林去，門人待遠公。"]'),
('02139bd5-8e74-47f9-9ec3-5d13163bb1d0','山中五詠 門柳','皇甫冉','唐','唐诗','tang','','[]','接影武昌城，分行漢南道。',24,'全唐诗/poet.tang.13000.json','["接影武昌城，分行漢南道。", "何事閑門外，空對青山老。"]'),
('5a40f694-3066-46ab-b2fd-2f87bd1eedb0','山中五詠 遠山','皇甫冉','唐','唐诗','tang','','[]','少室盡西峯，鳴臯隱南面。',24,'全唐诗/poet.tang.13000.json','["少室盡西峯，鳴臯隱南面。", "柴門縱復關，終日窗中見。"]'),
('6ce12fb9-715f-482d-80eb-5e8946ea2e8f','山中五詠 南澗','皇甫冉','唐','唐诗','tang','','[]','上路各乘軒，高明盡鳴玉。',24,'全唐诗/poet.tang.13000.json','["上路各乘軒，高明盡鳴玉。", "寧知澗下人，自愛輕波淥。"]'),
('d8cef360-6346-46e5-acd2-5c7c1ed7fced','山中五詠 春早','皇甫冉','唐','唐诗','tang','','[]','草徧潁陽山，花開武陵水。',24,'全唐诗/poet.tang.13000.json','["草徧潁陽山，花開武陵水。", "春色既已同，人心亦相似。"]'),
('2ab17641-f626-47a7-a8e3-c59a43000649','山中五詠 山館','皇甫冉','唐','唐诗','tang','','[]','山館長寂寂，閑雲朝夕來。',24,'全唐诗/poet.tang.13000.json','["山館長寂寂，閑雲朝夕來。", "空庭復何有，落日照青苔。"]'),
('4b39f42b-3d8c-4c15-ad4c-b9ed2b9a88a2','送竇十九叔向赴京','皇甫冉','唐','唐诗','tang','','[]','冰結楊柳津，從吳去入秦。',48,'全唐诗/poet.tang.13000.json','["冰結楊柳津，從吳去入秦。", "徒云還上國，誰爲作中人。", "驛樹同霜霰，漁舟伴苦辛。", "相如求一謁，詞賦遠隨身。"]'),
('972879b8-36c2-409a-9d02-14b1253b1cde','登石城戍望海寄諸暨嚴少府','皇甫冉','唐','唐诗','tang','','[]','平明登古戍，徙倚待寒潮。',48,'全唐诗/poet.tang.13000.json','["平明登古戍，徙倚待寒潮。", "江海方回合，雲林自寂寥。", "詎能知遠近，徒見蕩煙霄。", "即此滄洲路，嗟君久折腰。"]'),
('62ef0ed0-68f0-428b-9056-48a65c9c7a3c','和樊潤州秋日登城樓','皇甫冉','唐','唐诗','tang','','[]','露冕臨平楚，寒城帶早霜。',48,'全唐诗/poet.tang.13000.json','["露冕臨平楚，寒城帶早霜。", "時同借河內，人是臥淮陽。", "積水澄天塹，連山入帝鄉。", "因高欲見下，非是愛秋光。"]'),
('f29c187a-cae6-47be-bd85-ccdaee98f422','寄江東李判官','皇甫冉','唐','唐诗','tang','','[]','遠懷不可道，歷稔倦離憂。',96,'全唐诗/poet.tang.13000.json','["遠懷不可道，歷稔倦離憂。", "洛下聞新雁，江南想暮秋。", "澄清佐八使，綱紀案諸侯。", "地識吳平久，才當晉用求。", "時賢幾殂謝，摛藻繼風流。", "更有西陵作，還成北固遊。", "歸途限尺牘，王事在扁舟。", "山色臨湖盡，猿聲入夢愁。"]'),
('071e72e6-de40-4aa0-add7-7eed7e63ac4c','送蔣評事往福州','皇甫冉','唐','唐诗','tang','','[]','江上春常早，閩中客去稀。',48,'全唐诗/poet.tang.13000.json','["江上春常早，閩中客去稀。", "登山怨迢遞，臨水惜芳菲。", "煙樹何時盡，風帆幾日歸。", "還看復命處，盛府有光輝。"]'),
('70072726-2a11-4aa0-8814-3affe5ba0097','送從弟豫貶遠州','皇甫冉','唐','唐诗','tang','','[]','何事成遷客，思歸不見鄉。',72,'全唐诗/poet.tang.13000.json','["何事成遷客，思歸不見鄉。", "遊吳經萬里，弔屈過三湘。", "水與荆巫接，山通鄢郢長。", "名嗟黃綬繫，才是白眉良。", "獨結南枝恨，應思北雁行。", "憂來沽楚酒，玄鬢莫凝霜。"]'),
('5f2258ac-7c5b-42fd-951e-5e904383259e','送錢唐路少府赴制舉','皇甫冉','唐','唐诗','tang','','[]','公車待詔赴長安，客裏新正阻舊歡。',64,'全唐诗/poet.tang.13000.json','["公車待詔赴長安，客裏新正阻舊歡。", "遲日未能銷野雪，晴花偏自犯江寒。", "東溟道路通秦塞，北闕威儀識漢官。", "共許郄詵工射策，恩榮請向一枝看。"]'),
('8920421d-07a1-40d8-8776-aef2212f6681','賦得荆溪夜湍送蔣逸人歸義興山','皇甫冉','唐','唐诗','tang','','[]','驚湍流不極，夜度識雲岑。',60,'全唐诗/poet.tang.13000.json','["驚湍流不極，夜度識雲岑。", "長帶溪沙淺，時因山雨深。", "方同七里路，更遂五湖心。", "揭厲朝將夕，潺湲古至今。", "花源君若許，雖遠亦相尋。"]'),
('503b3e6f-a832-43df-bf4b-20bbfcef0769','送孔黨赴舉','皇甫冉','唐','唐诗','tang','','[]','入貢列諸生，詩書業早成。',48,'全唐诗/poet.tang.13000.json','["入貢列諸生，詩書業早成。", "家承孔聖後，身有魯儒名。", "楚水通滎浦，春山擁漢京。", "愛君方弱冠，爲賦少年行。"]'),
('740ca256-d62c-4cb8-96f9-7a62d39c398c','齊郎中筵賦得的的帆向浦留別','皇甫冉','唐','唐诗','tang','','[]','一帆何處去，正在望中微。',48,'全唐诗/poet.tang.13000.json','["一帆何處去，正在望中微。", "浦迥搖空色，汀迴見落暉。", "每爭高鳥度，能送遠人歸。", "偏似南浮客，悠揚無所依。"]'),
('dd40f188-e63b-48e7-9418-7e8e667b7308','送陸鴻漸棲霞寺採茶','皇甫冉','唐','唐诗','tang','','[]','採茶非採菉，遠遠上層崖。',48,'全唐诗/poet.tang.13000.json','["採茶非採菉，遠遠上層崖。", "布葉春風暖，盈筐白日斜。", "舊知山寺路，時宿野人家。", "借問王孫草，何時泛椀花。"]'),
('585e6c66-799d-477b-bc45-c1f3b201c6cc','泊丹陽與諸人同舟至馬林溪遇雨','皇甫冉','唐','唐诗','tang','','[]','雲林不可望，溪水更悠悠。',48,'全唐诗/poet.tang.13000.json','["雲林不可望，溪水更悠悠。", "共載人皆客，離家春是秋。", "遠山方對枕，細雨莫迴舟。", "來往南徐路，多爲芳草留。"]'),
('db3fdf10-9280-4d80-a33d-9c4ac579eab0','太常魏博士遠出賊庭江外相逢因敘其事','皇甫冉','唐','唐诗','tang','','[]','烽火驚戎塞，豺狼犯帝畿。',144,'全唐诗/poet.tang.13000.json','["烽火驚戎塞，豺狼犯帝畿。", "川原無稼穡，日月翳光輝。", "里社枌榆毀，宮城騎吏非。", "羣生被慘毒，雜虜耀輕肥。", "多士從芳餌，唯君識禍機。", "心同合浦葉，命寄首陽薇。", "耻作纖鱗喣，方隨高鳥飛。", "山經商嶺出，水泛漢池歸。", "離別霜凝鬢，逢迎淚迸衣。", "京華長路絕，江海故人稀。", "秉節身常苦，求仁志不違。", "秪應窮野外，耕種且相依。"]'),
('318cdefe-d46b-4f4c-b462-5f9337aa0fa7','送包佶賦得天津橋','皇甫冉','唐','唐诗','tang','','[]','洛陽歲暮作征客，囗囗囗囗囗囗囗。',96,'全唐诗/poet.tang.13000.json','["洛陽歲暮作征客，囗囗囗囗囗囗囗。", "相望依然一水間，相思已如千年隔。", "晴煙霽景滿天津，鳳閣龍樓暎水濱。", "豈無朝夕軒車度，其奈相逢非所親。", "鞏樹甘陵愁遠道，他鄉一望人堪老。", "君報還期在早春，橋邊日日看芳草。"]'),
('7a5a5d83-7614-4415-a36b-c9a198e65c25','上禮部楊侍郎','皇甫冉','唐','唐诗','tang','','[]','郢匠掄材日，轅輪必盡呈。',144,'全唐诗/poet.tang.13000.json','["郢匠掄材日，轅輪必盡呈。", "敢言當一幹，徒欲隸諸生。", "末學慙鄒魯，深仁錄弟兄。", "餘波知可挹，弱植更求榮。", "績媿他年敗，功期此日成。", "方因舊桃李，猶冀載飛鳴。", "道淺猶懷分，時移但自驚。", "關門驚暮節，林壑廢春畊。", "十里嵩峯近，千秋潁水清。", "煙花迷戍谷，墟落接陽城。", "渺默思鄉夢，遲迴知己情。", "勞歌終此曲，還是苦辛行。"]'),
('ccd8a531-9e74-476b-9345-6824427f4cec','宿嚴維宅送包七','皇甫冉','唐','唐诗','tang','','[]','江湖同避地，分手自依依。',72,'全唐诗/poet.tang.13000.json','["江湖同避地，分手自依依。", "盡室今爲客，經秋空念歸。", "歲儲無別墅，寒服羨鄰機。", "草色村橋晚，蟬聲江樹稀。", "夜涼宜共醉，時難惜相違。", "何事隨陽侶，汀洲忽背飛。"]'),
('8fd9291b-9201-4e56-9214-3aa3c4c29e37','同張侍御詠興寧寺經藏院海石榴花','皇甫冉','唐','唐诗','tang','','[]','嫩葉生初茂，殘花少更鮮。',24,'全唐诗/poet.tang.13000.json','["嫩葉生初茂，殘花少更鮮。", "結根龍藏側，故欲並青蓮。"]'),
('a9f0993f-d2b7-4b8e-a8dc-ad05daacf472','崔十四宅各賦一物得簷柳','皇甫冉','唐','唐诗','tang','','[]','官渡老風烟，潯陽媚雲日。',36,'全唐诗/poet.tang.13000.json','["官渡老風烟，潯陽媚雲日。", "漢將營前見，胡笳曲中出。", "復在此簷端，垂陰仲長室。"]'),
('f5ecea89-11af-496d-b707-bf20aad90219','送段明府','皇甫冉','唐','唐诗','tang','','[]','遙夜此何其，霜空殘杳靄。',60,'全唐诗/poet.tang.13000.json','["遙夜此何其，霜空殘杳靄。", "方嗟異鄉別，蹔是同公會。", "海林秋更疎，野水寒猶大。", "離人轉吳岫，旅雁從燕塞。", "日夕望前期，勞心白雲外。"]'),
('6626bd00-c5f7-4983-98b3-6a2eb60c9154','送王司直','皇甫冉','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u53cb\u60c5"]','西塞雲山遠，東風道路長。',24,'全唐诗/poet.tang.13000.json','["西塞雲山遠，東風道路長。", "人心勝潮水，相送過潯陽。"]'),
('5daf7602-90c9-4846-b0b3-cd49a6aa6964','婕妤春怨','皇甫冉','唐','唐诗','tang','','[]','花枝出建章，鳳管發昭陽。',24,'全唐诗/poet.tang.13000.json','["花枝出建章，鳳管發昭陽。", "借問承恩者，雙蛾幾許長。"]'),
('c335b1db-440a-4038-affe-15a07e5842b2','送魏十六還蘇州','皇甫冉','唐','唐诗','tang','','["\u53cb\u60c5", "\u9001\u522b", "\u7559\u604b", "\u60c6\u6005"]','秋夜深深北送君，陰蟲切切不堪聞。',32,'全唐诗/poet.tang.13000.json','["秋夜深深北送君，陰蟲切切不堪聞。", "歸舟明日毗陵道，迴首姑蘇是白雲。"]'),
('196ed93c-6344-40f4-a254-31fe62925bb6','婕妤怨','皇甫冉','唐','唐诗','tang','','[]','由來詠團扇，今已值秋風。',48,'全唐诗/poet.tang.13000.json','["由來詠團扇，今已值秋風。", "事逐時皆徃，恩無日再中。", "早鴻聞上苑，寒露下深宮。", "顏色年年謝，相如賦豈工。"]'),
('5d125924-4073-47eb-b947-d0f164f33ac1','送客','皇甫冉','唐','唐诗','tang','','[]','旗鼓軍威重，關山客路賒。',48,'全唐诗/poet.tang.13000.json','["旗鼓軍威重，關山客路賒。", "待封甘度隴，回首不思家。", "城下春山路，營中瀚海沙。", "河源雖萬里，音信寄來查。"]'),
('12cb80fd-66ac-4f0c-ad95-c0cec8bff9ce','秋日東郊作','皇甫冉','唐','唐诗','tang','','[]','閑看秋水心無事，臥對寒松手自栽。',64,'全唐诗/poet.tang.13000.json','["閑看秋水心無事，臥對寒松手自栽。", "廬岳高僧留偈別，茅山道士寄書來。", "燕知社日辭巢去，菊爲重陽冒雨開。", "淺薄將何稱獻納，臨岐終日自遲迴。"]'),
('8a9be6a9-bfdc-44f6-90ac-cd08abd71c1a','秋夜宿嚴維宅','皇甫冉','唐','唐诗','tang','','[]','昔聞玄度宅，門向會稽峯。',48,'全唐诗/poet.tang.13000.json','["昔聞玄度宅，門向會稽峯。", "君住東湖下，清風繼舊踪。", "秋深臨水月，夜半隔山鐘。", "世故多離別，良宵詎可逢。"]'),
('fdb1e943-f2a7-4f1a-b173-0f6d1e1637d5','見諸姬學玉臺體','皇甫冉','唐','唐诗','tang','','[]','豔唱召燕姬，清弦待盧女。',60,'全唐诗/poet.tang.13000.json','["豔唱召燕姬，清弦待盧女。", "由來道姓秦，誰不知家楚。", "傳盃見目成，結帶明心許。", "寧辭玉輦迎，自堪金屋貯。", "朝朝作行雲，襄王迷處所。"]'),
('4dd5692e-2e4e-46a3-9e61-15a4e395a5d8','酬張二倉曹揚子所居見寄兼呈韓郎中','皇甫冉','唐','唐诗','tang','','[]','孤雲獨鶴自悠悠，別後經年尚泊舟。',64,'全唐诗/poet.tang.13000.json','["孤雲獨鶴自悠悠，別後經年尚泊舟。", "漁父置詞相借問，郎官能賦許依投。", "折芳遠寄三春草，乘興閑看萬里流。", "莫怪杜門頻乞假，不堪扶病拜龍樓。"]'),
('335f6bc2-5379-466f-8553-d7d5ec4a9ed1','送安律師','皇甫冉','唐','唐诗','tang','','[]','出家童子歲，愛此雪山人。',48,'全唐诗/poet.tang.13000.json','["出家童子歲，愛此雪山人。", "長路經千里，孤雲伴一身。", "水中應見月，草上豈傷春。", "永日空林下，心將何物親。"]'),
('96baaba3-9551-4e43-b43d-38acba9b88f8','題盧十一所居','皇甫冉','唐','唐诗','tang','','[]','春風來幾日，先入辟疆園。',24,'全唐诗/poet.tang.13000.json','["春風來幾日，先入辟疆園。", "身外無餘事，閑吟晝閉門。"]'),
('969f9af7-e7ac-46f8-8a73-7898e72b72d2','送陸[澧]郭鄖','皇甫冉','唐','唐诗','tang','','[]','纔見吳洲百草春，已聞燕雁一聲新。',32,'全唐诗/poet.tang.13000.json','["纔見吳洲百草春，已聞燕雁一聲新。", "秋風何處催年急，偏逐山行水宿人。"]'),
('91e5ec11-b403-4ede-9d5b-c1854706739b','山中橫雲','皇甫冉','唐','唐诗','tang','','[]','湘水風日滿，楚山朝夕空。',24,'全唐诗/poet.tang.13000.json','["湘水風日滿，楚山朝夕空。", "連峰雖已見，猶念長雲中。"]'),
('cde212e6-2e8d-4c74-aa0f-d8e8cb9835a4','題裴二十一新園','皇甫冉','唐','唐诗','tang','','[]','東郭訪先生，西郊尋隱路。',84,'全唐诗/poet.tang.13000.json','["東郭訪先生，西郊尋隱路。", "久爲江南客，自有雲陽樹。", "已得閑園心，不知公府步。", "開門白日晚，倚杖青山暮。", "果熟任霜封，籬疎從水度。", "窮年無牽綴，往事惜淪悞。", "唯見耦耕人，朝朝自來去。"]'),
('de28c365-7d67-4513-a2d5-5dec1ff3c795','寄高雲','皇甫冉','唐','唐诗','tang','','[]','南徐風日好，悵望毘陵道。',84,'全唐诗/poet.tang.13000.json','["南徐風日好，悵望毘陵道。", "毘陵有故人，一見恨無因。", "獨戀青山久，唯令白髮新。", "每嫌持手板，時見著頭巾。", "煙景臨寒食，農桑接仲春。", "家貧仍嗜酒，生事今何有。", "芳草遍江南，勞心憶攜手。"]'),
('d382e9b0-da98-4eae-9c97-aca770dcbb90','溫泉即事','皇甫冉','唐','唐诗','tang','','[]','天仗星辰轉，霜冬景氣和。',48,'全唐诗/poet.tang.13000.json','["天仗星辰轉，霜冬景氣和。", "樹含溫液潤，山入繚垣多。", "丞相金錢賜，平陽玉輦過。", "魯儒求一謁，無路獨如何。"]'),
('5db1e935-601d-4258-a93c-bf840d7c4655','送張南史','皇甫冉','唐','唐诗','tang','','[]','馬卿工詞賦，位下年將暮。',72,'全唐诗/poet.tang.13000.json','["馬卿工詞賦，位下年將暮。", "謝客愛雲山，家貧身不閑。", "風波杳未極，幾處逢相識。", "富貴人皆變，誰能念貧賤。", "岸有經霜草，林有故年枝。", "俱應待春色，獨使客心悲。"]'),
('346fa139-195f-40dc-b3e2-3758a5dd01ff','廬山歌送至弘法師兼呈薛江州','皇甫冉','唐','唐诗','tang','','["\u5e90\u5c71"]','釋子去兮訪名山，禪舟容與兮住仍前。',97,'全唐诗/poet.tang.13000.json','["釋子去兮訪名山，禪舟容與兮住仍前。", "猿啾啾兮怨月，江渺渺兮多煙。", "東林西林兮入何處，上方下方兮通石路。", "連湘接楚饒桂花，事久年深無杏樹。", "使君愛人兼愛山，時引雙旌萬木間。", "政成人野皆不擾，遂令法侶性安閑。"]'),
('9d22d9e5-04ad-42f1-b88c-7c4b07f012c1','送薛秀才','皇甫冉','唐','唐诗','tang','','[]','雖是尋山客，還同慢世人。',48,'全唐诗/poet.tang.13000.json','["雖是尋山客，還同慢世人。", "讀書惟務靜，無褐不憂貧。", "野色春冬樹，雞聲遠近鄰。", "郄公即吾友，合與爾相親。"]'),
('b8f2904e-a113-40f7-8ca2-c92304a7a44b','使往壽州淮路寄劉長卿','皇甫冉','唐','唐诗','tang','','[]','榛草荒涼村落空，驅馳卒歲亦何功。',64,'全唐诗/poet.tang.13000.json','["榛草荒涼村落空，驅馳卒歲亦何功。", "蒹葭曙色蒼蒼遠，蟋蟀秋聲處處同。", "鄉路遙知淮浦外，故人多在楚雲東。", "日夕煙霜那可道，壽陽西去水無窮。"]'),
('4ea18a01-5287-449f-bba4-38c6193b85ce','酬李司兵直夜見寄','皇甫冉','唐','唐诗','tang','','[]','江城聞鼓角，旅宿復何如。',48,'全唐诗/poet.tang.13000.json','["江城聞鼓角，旅宿復何如。", "寒月此宵半，春風舊歲餘。", "徒云資薄祿，未必勝閑居。", "見欲扁舟去，誰能畏簡書。"]'),
('bc969e2f-a03d-4893-bf53-14dcc38d3a26','送薛判官之越','皇甫冉','唐','唐诗','tang','','[]','時難自多務，職小亦求賢。',36,'全唐诗/poet.tang.13000.json','["時難自多務，職小亦求賢。", "道路無辭遠，雲山併在前。", "樟亭待潮處，已是越人烟。"]'),
('ef2f2701-dd8d-4482-b004-217944deac48','同溫丹徒登萬歲樓','皇甫冉','唐','唐诗','tang','','[]','高樓獨立思依依，極浦遙山合翠微。',64,'全唐诗/poet.tang.13000.json','["高樓獨立思依依，極浦遙山合翠微。", "江客不堪頻北顧，塞鴻何事復南飛。", "丹陽古渡寒煙積，瓜步空洲遠樹稀。", "聞道王師猶轉戰，誰能談笑解重圍。"]'),
('0a621e1c-a9ba-4690-a735-b83877917ab0','賦得簷燕','皇甫冉','唐','唐诗','tang','','[]','拂水競何忙，傍簷如有意。',36,'全唐诗/poet.tang.13000.json','["拂水競何忙，傍簷如有意。", "翻風去每遠，帶雨歸偏駛。", "令君裁杏梁，更欲年年去。"]'),
('58d54c7d-1683-4225-af61-23db20d99fc2','送李萬州赴饒州覲省','皇甫冉','唐','唐诗','tang','','[]','前程觀拜慶，舊館惜招攜。',72,'全唐诗/poet.tang.13000.json','["前程觀拜慶，舊館惜招攜。", "荀氏風流遠，胡家清白齊。", "川迴吳岫失，塞闊楚雲低。", "舉目親魚鳥，驚心怯鼓鼙。", "人稀漁浦外，灘淺定山西。", "無限青青草，王孫去不迷。"]'),
('976df39d-63c3-4d04-bb8c-4845154f3137','送鄒判官赴河南','皇甫冉','唐','唐诗','tang','','[]','看君發原隰，四牡去皇皇。',72,'全唐诗/poet.tang.13000.json','["看君發原隰，四牡去皇皇。", "始罷滄江吏，還隨粉署郎。", "海沂軍未息，河畔歲仍荒。", "征稅人全少，榛蕪虜近亡。", "所行知宋遠，相隔歎淮長。", "早晚裁書寄，銀鉤佇八行。"]'),
('555dca9c-3114-454a-895e-37d014f73753','宿淮陰南樓酬常伯能','皇甫冉','唐','唐诗','tang','','[]','淮陰日落上南樓，喬木荒城古渡頭。',64,'全唐诗/poet.tang.13000.json','["淮陰日落上南樓，喬木荒城古渡頭。", "浦外野風初入戶，窗中海月早知秋。", "滄波一望通千里，畫角三聲起百憂。", "佇立分宵絕來客，煩君步屐忽相求。"]'),
('03b8aaf4-9827-470b-ab77-9666b6e11f4c','送歸中丞使新羅','皇甫冉','唐','唐诗','tang','','[]','詔使殊方遠，朝儀舊典行。',72,'全唐诗/poet.tang.13000.json','["詔使殊方遠，朝儀舊典行。", "浮天無盡處，望日計前程。", "暫喜孤山出，長愁積水平。", "野風飄疊鼓，海雨濕危旌。", "異俗知文敎，通儒有令名。", "還將大戴禮，方外授諸生。"]'),
('2a288f33-b3b9-4fbd-8250-811fed3348ed','小江懷靈一上人','皇甫冉','唐','唐诗','tang','','[]','江上年年春早，津頭日日人行。',28,'全唐诗/poet.tang.13000.json','["江上年年春早，津頭日日人行。", "借問山陰遠近，猶聞薄暮鐘聲。"]'),
('07d90e86-6dd8-4773-a0f8-c2cb6b66580f','送唐別駕赴郢州','皇甫冉','唐','唐诗','tang','','[]','莫歎辭家遠，方看佐郡榮。',48,'全唐诗/poet.tang.13000.json','["莫歎辭家遠，方看佐郡榮。", "長林通楚塞，高嶺見秦城。", "雪向嶢關下，人從郢路迎。", "翩翩駿馬去，自是少年行。"]'),
('7bac3aea-d9e6-4e74-bf5a-b44345ce829f','送魏中丞還河北','皇甫冉','唐','唐诗','tang','','[]','寧知貴公子，本是魯諸生。',36,'全唐诗/poet.tang.13000.json','["寧知貴公子，本是魯諸生。", "上國風塵舊，中司印綬榮。", "辛勤戎旅事，雪下護羗營。"]'),
('5781e2ed-dc49-4d3e-8e7f-ab5d0b078187','送李使君赴邵州','皇甫冉','唐','唐诗','tang','','[]','出送東方騎，行安南楚人。',48,'全唐诗/poet.tang.13000.json','["出送東方騎，行安南楚人。", "城池春足雨，風俗夜迎神。", "郢路逢歸客，湘川問去津。", "爭看使君度，皂蓋雪中新。"]'),
('bd2c15e5-7297-4ae8-93f9-943605c6e30f','寄振上人無碍寺所居','皇甫冉','唐','唐诗','tang','','[]','戀親時見在人羣，多在東山就白雲。',32,'全唐诗/poet.tang.13000.json','["戀親時見在人羣，多在東山就白雲。", "獨坐焚香誦經處，深山古寺雪紛紛。"]'),
('56acd535-6744-4d16-b59e-f897f591544b','酬李補闕','皇甫冉','唐','唐诗','tang','','[]','十年歸客但心傷，三徑無人已自荒。',64,'全唐诗/poet.tang.13000.json','["十年歸客但心傷，三徑無人已自荒。", "夕宿靈臺伴煙月，晨趨建禮逐衣裳。", "偶因麋鹿隨豐草，謬荷鴛鸞借末行。", "縱有諫書猶未獻，春風拂地日空長。"]'),
('bc4f9adf-294c-47ac-9c99-cfe10866acb7','故齊王贈承天皇帝挽歌','皇甫冉','唐','唐诗','tang','','[]','禮盛追崇日，人知友悌恩。',48,'全唐诗/poet.tang.13000.json','["禮盛追崇日，人知友悌恩。", "舊居從代邸，新隴入文園。", "鴻寶仙書祕，龍旂帝服尊。", "蒼蒼松裏月，萬古此高原。"]'),
('d1c4ba64-a500-4b4a-8b5d-2a141ff29d57','贈恭順皇后挽歌','皇甫冉','唐','唐诗','tang','','[]','徂謝年方久，哀榮事獨稀。',48,'全唐诗/poet.tang.13000.json','["徂謝年方久，哀榮事獨稀。", "雖殊百兩迓，同是九泉歸。", "詔使歸金策，神人送玉衣。", "空山竟不從，寧肯學湘妃。"]'),
('da41166c-15b3-454a-8abb-da16b0661591','病中對石竹花','皇甫冉','唐','唐诗','tang','','[]','散點空堦下，閑凝細雨中。',24,'全唐诗/poet.tang.13000.json','["散點空堦下，閑凝細雨中。", "那能久相伴，嗟爾殢秋風。"]'),
('81b905b4-aac5-4509-ba20-0826d15e9272','寄鄭二侍御歸新鄭無礙寺所居','皇甫冉','唐','唐诗','tang','','[]','何事休官早，歸來作鄭人。',48,'全唐诗/poet.tang.13000.json','["何事休官早，歸來作鄭人。", "雲山隨伴侶，伏臘見鄉親。", "南畝無三徑，東林寄一身。", "誰當便靜者，莫使甑生塵。"]'),
('4ac5a760-055d-4c66-bf4c-9baf38b78e2c','送廬山人歸林慮山','皇甫冉','唐','唐诗','tang','','["\u5e90\u5c71"]','無論行遠近，歸向舊煙林。',36,'全唐诗/poet.tang.13000.json','["無論行遠近，歸向舊煙林。", "寥落人家少，青冥鳥道深。", "白雲長滿目，芳草自知心。"]'),
('8a3ccf99-4d66-4826-bad5-5f177c3cec45','送榮別駕赴華州','皇甫冉','唐','唐诗','tang','','[]','直到羣峯下，應無累日程。',48,'全唐诗/poet.tang.13000.json','["直到羣峯下，應無累日程。", "高車入郡舍，流水出關城。", "草色田家迥，槐陰府吏迎。", "還將海沂詠，籍甚漢公卿。"]'),
('8a2b2ac0-78ed-4a7c-adde-31d2a3b2824b','送常大夫加散騎常侍赴朔方','皇甫冉','唐','唐诗','tang','','[]','故壘煙塵後，新軍河塞間。',48,'全唐诗/poet.tang.13000.json','["故壘煙塵後，新軍河塞間。", "金貂寵漢將，玉節度蕭關。", "澶漫沙中雪，依稀漢口山。", "人知竇車騎，計日勒銘還。"]'),
('b0ee63fe-7459-4ada-889d-ac3e5da55486','送王翁信還剡中舊居','皇甫冉','唐','唐诗','tang','','[]','海岸耕殘雪，溪沙釣夕陽。',24,'全唐诗/poet.tang.13000.json','["海岸耕殘雪，溪沙釣夕陽。", "客中何所有，春草漸看長。"]'),
('1e1df6b8-2a20-4b7a-b609-26b897944436','酬張繼','皇甫冉','唐','唐诗','tang','','[]','悵望南徐登北固，迢遙西塞恨東關。',32,'全唐诗/poet.tang.13000.json','["悵望南徐登北固，迢遙西塞恨東關。", "落日臨川問音信，寒潮唯帶夕陽還。"]'),
('2ec75ddb-6cce-4775-b934-7a7995bc9a04','送柳八員外赴江西','皇甫冉','唐','唐诗','tang','','["\u957f\u6c5f"]','岐路窮無極，長江九派分。',48,'全唐诗/poet.tang.13000.json','["岐路窮無極，長江九派分。", "行人隨旅雁，楚樹入湘雲。", "久在征南役，何殊薊北勳。", "離心不可問，歲暮雪紛紛。"]'),
('71571867-b9ca-417e-bf05-b27816d2d277','賦長道一絕送陸邃潛夫','皇甫冉','唐','唐诗','tang','','[]','高山迥欲登，遠水深難渡。',24,'全唐诗/poet.tang.13000.json','["高山迥欲登，遠水深難渡。", "杳杳復漫漫，行人別家去。"]'),
('e34aa8fc-aa37-4d16-bc86-1c9cc6362d68','又得雲字','皇甫冉','唐','唐诗','tang','','[]','何事千年遇聖君，坐令雙鬢老如雲。',32,'全唐诗/poet.tang.13000.json','["何事千年遇聖君，坐令雙鬢老如雲。", "南行更入深山淺，岐路悠悠水自分。"]'),
('6e07e347-b04c-47ba-b08b-50290aabe618','送陸潛夫往茅山賦得華陽洞','皇甫冉','唐','唐诗','tang','','[]','游仙洞兮訪真官，奠瑤席兮禮石壇。',58,'全唐诗/poet.tang.13000.json','["游仙洞兮訪真官，奠瑤席兮禮石壇。", "忽髣髴兮雲擾，杳陰深兮夏寒。", "欲迴頭兮揮手，便辭家兮可否。", "有婚嫁兮嬰纏，綿歸來兮已久。"]'),
('fc2775b4-198d-4e97-8308-2ccf925ef5b0','又送陸潛夫茅山尋友','皇甫冉','唐','唐诗','tang','','[]','登山自補屐，訪友不齎糧。',48,'全唐诗/poet.tang.13000.json','["登山自補屐，訪友不齎糧。", "坐嘯青楓晚，行吟白日長。", "人烟隔水見，草氣入林香。", "誰作招尋侶，清齋宿紫陽。"]'),
('a5b63e56-a8be-4d2b-9d3e-c1d6fc1fce8d','賦得越山三韻','皇甫冉','唐','唐诗','tang','','[]','西陵猶隔水，北岸已春山。',36,'全唐诗/poet.tang.13000.json','["西陵猶隔水，北岸已春山。", "獨鳥連天去，孤雲伴客還。", "秪應結茅宇，出入石林間。"]'),
('a306145a-5a45-49e4-bcd7-4070546a0400','送盧郎中使君赴京','皇甫冉','唐','唐诗','tang','','[]','三年期上國，萬里自東溟。',48,'全唐诗/poet.tang.13000.json','["三年期上國，萬里自東溟。", "曲蓋遵長道，油幢憩短亭。", "楚雲山隱隱，淮雨草青青。", "康樂多新興，題詩紀所經。"]'),
('e2630a36-69b2-4b0f-9073-592eb2540143','楊氏林亭探得古槎','皇甫冉','唐','唐诗','tang','','[]','千年古貌多，八月秋濤晚。',24,'全唐诗/poet.tang.13000.json','["千年古貌多，八月秋濤晚。", "偶被主人留，那知來近遠。"]'),
('9f4be0d8-c1e8-41c6-8908-14f061329e8c','送鄭二之茅山','皇甫冉','唐','唐诗','tang','','[]','水流絕澗終日，草長深山暮春。',28,'全唐诗/poet.tang.13000.json','["水流絕澗終日，草長深山暮春。", "犬吠雞鳴幾處，條桑種杏何人。"]'),
('b6c590ce-9357-4a67-85bb-29a2402d9c33','和王給事禁省梨花詠','皇甫冉','唐','唐诗','tang','','[]','巧解逢人笑，還能亂蝶飛。',24,'全唐诗/poet.tang.13000.json','["巧解逢人笑，還能亂蝶飛。", "春時風入戶，幾片落朝衣。"]'),
('d92e5356-f7a6-4068-b44e-1e7b87fb3977','送鄭員外入茅山居','皇甫冉','唐','唐诗','tang','','[]','但見全家去，寧知幾日還。',48,'全唐诗/poet.tang.13000.json','["但見全家去，寧知幾日還。", "白雲迎谷口，流水出人間。", "冠冕情遺世，神仙事滿山。", "其中應有物，豈貴一身閑。"]'),
('221ebe63-3aa2-4662-9c8e-f303d99700bb','送志彌師往淮南','皇甫冉','唐','唐诗','tang','','[]','已能持律藏，復去禮禪亭。',48,'全唐诗/poet.tang.13000.json','["已能持律藏，復去禮禪亭。", "長老偏摩頂，時流尚誦經。", "獨行寒野曠，旅宿遠山青。", "眷屬空相望，鴻飛已杳冥。"]'),
('86a4b0c2-fd29-4877-ae66-d5ee191930b9','謝韋大夫柳栽','皇甫冉','唐','唐诗','tang','','[]','本在胡笳曲，今從漢將營。',48,'全唐诗/poet.tang.13000.json','["本在胡笳曲，今從漢將營。", "濃陰方待庇，弱植豈無情。", "比雪花應吐，藏烏葉未成。", "五株蒙遠賜，應使號先生。"]'),
('2c7dba62-fe55-41e2-a39b-baa1a128bcd8','問李二司直所居雲山','皇甫冉','唐','唐诗','tang','','[]','門外水流何處，天邊樹遶誰家。',28,'全唐诗/poet.tang.13000.json','["門外水流何處，天邊樹遶誰家。", "山色東西多少，朝朝幾度雲遮。"]'),
('8da812ff-6e3d-4dc8-aff1-132b9ca701f7','劉侍御朝命許停官歸侍','皇甫冉','唐','唐诗','tang','','[]','孟孫唯問孝，萊子復辭官。',72,'全唐诗/poet.tang.13000.json','["孟孫唯問孝，萊子復辭官。", "幸遂溫凊願，其甘稼穡難。", "採芝供上藥，拾槿奉晨餐。", "棟裏雲藏雨，山中暑帶寒。", "非時應有筍，閑地盡生蘭。", "賜告承優詔，長筵永日歡。"]'),
('fc4fd7fb-829d-4d74-ab63-36071c7608fe','送陸鴻漸赴越','皇甫冉','唐','唐诗','tang','','[]','行隨新樹深，夢隔重江遠。',24,'全唐诗/poet.tang.13000.json','["行隨新樹深，夢隔重江遠。", "迢遞風日間，蒼茫洲渚晚。"]'),
('fde03de2-0282-4563-8c84-b3611dfa199e','送竇叔向','皇甫冉','唐','唐诗','tang','','[]','楚客怨逢秋，閑吟興非一。',60,'全唐诗/poet.tang.13000.json','["楚客怨逢秋，閑吟興非一。", "棄官守貧病，作賦推文律。", "樵徑未經霜，茅簷初負日。", "今看泛月去，偶見乘潮出。", "卜地會爲隣，還依仲長室。"]'),
('5c647e0b-f398-4dd3-817d-0c9fe9b45e76','題蔣道士房','皇甫冉','唐','唐诗','tang','','[]','軒窗縹緲起烟霞，誦訣存思白日斜。',32,'全唐诗/poet.tang.13000.json','["軒窗縹緲起烟霞，誦訣存思白日斜。", "聞道崑崙有仙籍，何時青鳥送丹砂。"]'),
('ca19ac56-15aa-4e6b-8577-787e9aa92ffd','夜集張諲所居','皇甫冉','唐','唐诗','tang','','[]','江南成久客，門館日蕭條。',60,'全唐诗/poet.tang.13000.json','["江南成久客，門館日蕭條。", "惟有圖書在，多傷鬢髮凋。", "諸生陪講誦，稚子給漁樵。", "虛室寒燈靜，空堦落葉飄。", "滄洲自有趣，誰道隱須招。"]'),
('bf5e55e2-a107-4a1b-8ce7-5e4b8204fe2d','酬權器','皇甫冉','唐','唐诗','tang','','[]','南望江南滿山雪，此情惆悵將誰說。',96,'全唐诗/poet.tang.13000.json','["南望江南滿山雪，此情惆悵將誰說。", "徒隨羣吏不曾閑，顧與諸生爲久別。", "聞君靜坐轉耽書，種樹葺茅還舊居。", "終日白雲應自足，明年芳草又何如。", "人生有懷若不展，出入公門猶未免。", "迴舟朝夕待春風，先報華陽洞深淺。"]'),
('080a9610-9c99-4c53-88ad-b299396e09cc','寄劉方平大谷田家','皇甫冉','唐','唐诗','tang','','[]','故山聞獨往，樵路憶相從。',48,'全唐诗/poet.tang.13000.json','["故山聞獨往，樵路憶相從。", "冰結泉聲絕，霜清野翠濃。", "籬邊潁陽道，竹外少姨峯。", "日夕田家務，寒煙隔幾重。"]'),
('d11197ba-a106-4b45-832d-7445f702bb7f','送雲陽少府','皇甫冉','唐','唐诗','tang','','[]','渭曲春光無遠近，池陽谷口倍芳菲。',32,'全唐诗/poet.tang.13000.json','["渭曲春光無遠近，池陽谷口倍芳菲。", "官舍村橋來幾日，殘花寥落待君歸。"]'),
('0acac9e5-60e9-42cf-a8dc-f667520717a5','魯山送別','皇甫冉','唐','唐诗','tang','','[]','淒淒遊子若飄蓬，明月清罇秪暫同。',32,'全唐诗/poet.tang.13000.json','["淒淒遊子若飄蓬，明月清罇秪暫同。", "南望千山如黛色，愁君客路在其中。"]'),
('44b128d9-264f-48b0-83e9-751db7dbb08e','題高雲客舍','皇甫冉','唐','唐诗','tang','','[]','孤興日自深，浮雲非所仰。',120,'全唐诗/poet.tang.13000.json','["孤興日自深，浮雲非所仰。", "窗中西城峻，樹外東川廣。", "晏起簪葛巾，閑吟倚藜杖。", "阮公道在醉，莊子生常養。", "五柳轉扶疎，千峰恣來往。", "清秋香秔穫，白露寒菜長。", "吳國滯風煙，平陵延夢想。", "時人趨纓弁，高鳥違羅網。", "世事徒亂紛，吾心方浩蕩。", "唯將山與水，處處諧真賞。"]'),
('d8364f1e-c63c-4df1-8772-e856094fef55','臺頭寺願上人院古松下有小松裁毫末新生與纖草不辨重其有凌雲干霄之志與趙八員外裴十補闕同賦之','皇甫冉','唐','唐诗','tang','','[]','細草亦全高，秋毫乍堪比。',24,'全唐诗/poet.tang.13000.json','["細草亦全高，秋毫乍堪比。", "及至干霄日，何人復居此。"]'),
('55328a4d-e257-41c4-a83d-73c11be06e62','漁子溝寄趙員外裴補闕','皇甫冉','唐','唐诗','tang','','[]','欲逐淮潮上，暫停漁子溝。',24,'全唐诗/poet.tang.13000.json','["欲逐淮潮上，暫停漁子溝。", "相望知不見，終是屢迴頭。"]'),
('5a8f040e-f5ba-40a9-b3ef-d1837281540c','送崔使君赴壽州','皇甫冉','唐','唐诗','tang','','[]','列郡專城分國憂，彤幨皂蓋古諸侯。',64,'全唐诗/poet.tang.13000.json','["列郡專城分國憂，彤幨皂蓋古諸侯。", "仲華遇主年猶少，公瑾論兵位已酬。", "草色青青宜建隼，蟬聲處處雜鳴騶。", "千里相思如可見，淮南木落早驚秋。"]'),
('152b72c8-0e20-4cf2-9877-c843aeab9cd0','送謝十二判官','皇甫冉','唐','唐诗','tang','','[]','四牡驅馳千里餘，越山稠疊海林疎。',32,'全唐诗/poet.tang.13000.json','["四牡驅馳千里餘，越山稠疊海林疎。", "不辭終日離家遠，應爲劉公一紙書。"]'),
('9ab25516-bd98-4407-964a-0292fef55d0f','送處州裴使君赴京','皇甫冉','唐','唐诗','tang','','[]','使君朝北闕，車騎發東方。',72,'全唐诗/poet.tang.13000.json','["使君朝北闕，車騎發東方。", "別喜天書召，寧憂地脉長。", "山行朝復夕，水宿露爲霜。", "秋草連秦塞，孤帆落漢陽。", "新銜趨建禮，舊位識文昌。", "唯有東歸客，應隨南雁翔。"]'),
('a2597fae-4bb7-4c37-9c3a-ab09606f06a5','送田濟之揚州赴選','皇甫冉','唐','唐诗','tang','','[]','家貧不自給，求祿爲荒年。',48,'全唐诗/poet.tang.13000.json','["家貧不自給，求祿爲荒年。", "調補無高位，卑棲屈此賢。", "江山欲霜雪，吳楚接風煙。", "相去誠非遠，離心亦渺然。"]'),
('b0766c4f-76e3-405a-958c-b4476ab23e3d','送袁郎中破賊北歸','皇甫冉','唐','唐诗','tang','','[]','優詔親賢時獨稀，中途紫紱（一作「綬」）換征衣。',78,'全唐诗/poet.tang.13000.json','["優詔親賢時獨稀，中途紫紱（一作「綬」）換征衣。", "黃香省闥登朝去，楊僕樓船振旅歸。", "萬里長聞隨戰角，十年不得掩（一作「偃」）郊扉。", "囗囗囗囗囗囗囗，但將詞賦奉恩輝。"]'),
('b62d9973-ad95-4f49-8221-bd3805be0a15','同李萬晚望南岳寺懷普門上人','皇甫冉','唐','唐诗','tang','','[]','釋子身心無垢紛，獨將衣鉢去人羣。',32,'全唐诗/poet.tang.13000.json','["釋子身心無垢紛，獨將衣鉢去人羣。", "相思晚望松林寺，唯有鐘聲出白雲。"]'),
('36117dc6-7425-4fea-a2b2-738bbfadd40d','奉和獨孤中丞遊法華寺','皇甫冉','唐','唐诗','tang','','[]','謝君臨郡府，越國舊山川。',132,'全唐诗/poet.tang.13000.json','["謝君臨郡府，越國舊山川。", "訪道三千界，當仁五百年。", "巖空騶馭響，樹密斾旌連。", "閣影凌空壁，松聲助亂泉。", "開門得初地，伏檻接諸天。", "向背春光滿，樓臺古制全。", "羣峰爭彩翠，百谷會風煙。", "香象隨僧久，祥烏報客先。", "清心乘暇日，稽首慕良緣。", "法證無生偈，詩成大雅篇。", "蒼生望已久，迴駕獨依然。"]'),
('a5e7530f-9d5c-474b-b032-44c063c6b4b8','之京留別劉方平','皇甫冉','唐','唐诗','tang','','[]','客子慕儔侶，含悽整晨裝。',72,'全唐诗/poet.tang.13000.json','["客子慕儔侶，含悽整晨裝。", "邀歡日不足，況乃前期長。", "離袂惜嘉月，遠還勞折芳。", "遲迴越二陵，迴首但蒼茫。", "喬木清宿雨，故關愁夕陽。", "人言長安樂，其奈緬相望。"]'),
('e0ccd05d-1251-403b-8e43-8586d08d43bf','出塞','皇甫冉','唐','唐诗','tang','','[]','吹角出塞門，前瞻即胡地。',48,'全唐诗/poet.tang.13000.json','["吹角出塞門，前瞻即胡地。", "三軍盡迴首，皆洒望鄉淚。", "轉念關山長，行看風景異。", "由來征戍客，負得輕生義。"]'),
('9c6318c4-f7d2-4bc8-b136-bd84d6a744c8','赴李少府莊失路','皇甫冉','唐','唐诗','tang','','[]','君家南郭白雲連，正待情人弄石泉。',32,'全唐诗/poet.tang.13000.json','["君家南郭白雲連，正待情人弄石泉。", "月照煙花迷客路，蒼蒼何處是伊川。"]'),
('ec5ff5a6-546b-45fc-8812-6ab998d2aa6b','雨雪','皇甫冉','唐','唐诗','tang','','[]','風沙悲久戍，雨雪更勞師。',48,'全唐诗/poet.tang.13000.json','["風沙悲久戍，雨雪更勞師。", "絕漠無人境，將軍苦戰時。", "山川迷向背，氛霧失旌旗。", "徒念天涯隔，中人芳草期。"]'),
('bd66da21-8b24-4c95-85ea-0a303f8c644f','館陶李丞舊居','皇甫冉','唐','唐诗','tang','','[]','盛名天下挹餘芳，棄置終身不拜郎。',64,'全唐诗/poet.tang.13000.json','["盛名天下挹餘芳，棄置終身不拜郎。", "詞藻世傳平子賦，園林人比鄭公鄉。", "門前墜葉浮秋水，籬外寒臯帶夕陽。", "日日青松成古木，秪應來者爲心傷。"]'),
('80b2e218-b707-4c23-8836-61e38c4071c0','送劉兵曹還隴山居','皇甫冉','唐','唐诗','tang','','[]','離堂徒讌語，行子但悲辛。',48,'全唐诗/poet.tang.13000.json','["離堂徒讌語，行子但悲辛。", "雖是還家路，終爲隴上人。", "先秋雪已滿，近夏草初新。", "唯有聞羌笛，梅花曲裏春。"]'),
('e39702ba-5835-461f-ae4f-4fc597c65478','同李三月夜作','皇甫冉','唐','唐诗','tang','','[]','霜風驚度雁，月露皓疎林。',24,'全唐诗/poet.tang.13000.json','["霜風驚度雁，月露皓疎林。", "處處砧聲發，星河秋夜深。"]'),
('8a25e64b-b1b8-48ec-9f95-4a76f6dd3ff2','同裴少府安居寺對雨','皇甫冉','唐','唐诗','tang','','[]','共結尋真會，還當退食初。',48,'全唐诗/poet.tang.13000.json','["共結尋真會，還當退食初。", "爐煙雲氣合，林葉雨聲餘。", "溽暑銷珍簟，浮涼入綺疏。", "歸心從念遠，懷此復何如。"]'),
('1d101812-9feb-4523-aa14-dd96caf5fd5d','送元晟歸潛山所居','皇甫冉','唐','唐诗','tang','','[]','深山秋事早，君去復何如。',48,'全唐诗/poet.tang.13000.json','["深山秋事早，君去復何如。", "裛露收新稼，迎寒葺舊廬。", "題詩即招隱，作賦是閑居。", "別後空相憶，嵇康懶寄書。"]'),
('24060346-883e-4d15-9007-9121b5a10eff','送康判官徃新安賦得江路西南永','皇甫冉','唐','唐诗','tang','','[]','不向新安去，那知江路長。',48,'全唐诗/poet.tang.13000.json','["不向新安去，那知江路長。", "猿聲比廬霍，水色勝瀟湘。", "驛樹收殘雨，漁家帶夕陽。", "何須愁旅泊，使者有輝光。"]'),
('1822c0b1-b888-4feb-a745-192eef167303','宿洞靈觀','皇甫冉','唐','唐诗','tang','','[]','孤煙靈洞遠，積雪滿山寒。',48,'全唐诗/poet.tang.13000.json','["孤煙靈洞遠，積雪滿山寒。", "松柏凌高殿，莓苔封古壇。", "客來清夜久，仙去白雲殘。", "明日開金籙，焚香更沐蘭。"]'),
('e525dc74-ca9f-4989-b18d-d0934171f5e7','酬盧十一過宿','皇甫冉','唐','唐诗','tang','','[]','乞還方未遂，日夕望雲林。',48,'全唐诗/poet.tang.13000.json','["乞還方未遂，日夕望雲林。", "況復逢春草，何勞問此心。", "閉門公務散，枉策故情深。", "遙夜他鄉酒，同君梁甫吟。"]'),
('87562913-27dd-49a5-9710-b0c9f64452eb','酬裴十四','皇甫冉','唐','唐诗','tang','','[]','淮海各聯翩，三年方一見。',48,'全唐诗/poet.tang.13000.json','["淮海各聯翩，三年方一見。", "素心終不易，玄髮何須變。", "舊國想平陵，春山滿陽羨。", "隣雞莫遽唱，共惜良夜晏。"]'),
('4b3d5e66-eee6-4e65-b79c-1089a5c74b6b','彭祖井','皇甫冉','唐','唐诗','tang','','[]','上公旌節在徐方，舊井莓苔近寢堂。',64,'全唐诗/poet.tang.13000.json','["上公旌節在徐方，舊井莓苔近寢堂。", "訪古因知彭祖宅，得仙何必葛洪鄉。", "清虛不共春池竟，盥漱偏宜夏日長。", "聞道延年如玉液，欲將調鼎獻明光。"]'),
('67cb665f-b8db-47ed-a098-da4898307a88','奉和對雪','皇甫冉','唐','唐诗','tang','','[]','春雪偏當夜，暄風却變寒。',48,'全唐诗/poet.tang.13000.json','["春雪偏當夜，暄風却變寒。", "庭深不復掃，城曉更宜看。", "命酒閑令酌，披蓑晚未冠。", "連營鼓角動，忽似戰桑乾。"]'),
('2f92806c-9ee2-45a3-a49e-622a79dc64c3','送蕭獻士','皇甫冉','唐','唐诗','tang','','[]','惆悵煙郊晚，依然此送君。',48,'全唐诗/poet.tang.13000.json','["惆悵煙郊晚，依然此送君。", "長河隔旅夢，浮客伴孤雲。", "淇上春山直，黎陽大道分。", "西陵倘一弔，應有士衡文。"]'),
('108c29ef-0144-49b3-a8e4-5e6b04bf29f8','賣藥人處得南陽朱山人書','皇甫冉','唐','唐诗','tang','','[]','賣藥何爲者，逃名市井居。',48,'全唐诗/poet.tang.13000.json','["賣藥何爲者，逃名市井居。", "唯通遠山信，因致逸人書。", "已報還丹効，全將世事疎。", "秋風景溪裏，蕭散寄樵漁。"]'),
('0db71c2b-dba6-4622-8382-70f0aea43c85','初出沅江夜入湖','皇甫冉','唐','唐诗','tang','','[]','放溜出江口，迴瞻松栝深。',24,'全唐诗/poet.tang.13000.json','["放溜出江口，迴瞻松栝深。", "不知舟中月，更引湖間心。"]'),
('0aa0e86a-df58-49e9-bba2-35b7eeef4b33','送裴員外往江南','皇甫冉','唐','唐诗','tang','','[]','分務江南遠，留歡幕下榮。',48,'全唐诗/poet.tang.13000.json','["分務江南遠，留歡幕下榮。", "楓林縈楚塞，水驛到湓城。", "岸草知春晚，沙禽好夜驚。", "風帆幾泊處，處處暮潮清。"]'),
('9969339c-9e80-49bf-89f7-0237a863da08','奉和王相公早春登徐州城','皇甫冉','唐','唐诗','tang','','[]','落日憑危堞，春風似故鄉。',48,'全唐诗/poet.tang.13000.json','["落日憑危堞，春風似故鄉。", "川流通楚塞，山色遶徐方。", "壁壘依寒草，旌旗動夕陽。", "元戎資上策，南畝起耕桑。"]'),
('c612488c-7df4-4769-8be5-d708a26d7a17','奉和對山僧','皇甫冉','唐','唐诗','tang','','[]','吏散重門掩，僧來閉閣閑。',48,'全唐诗/poet.tang.13000.json','["吏散重門掩，僧來閉閣閑。", "遠心馳北闕，春興寄東山。", "草長風光裏，鶯喧靜默間。", "芳辰不可住，惆悵暮禽還。"]'),
('dafa92f3-7a8a-48ef-9b5a-fb02ebd9100e','奉和待勤照上人不至','皇甫冉','唐','唐诗','tang','','[]','東洛居賢相，南方待本師。',48,'全唐诗/poet.tang.13000.json','["東洛居賢相，南方待本師。", "旌麾儼欲動，杯錫杳仍遲。", "積雪迷何處，驚風泊幾時。", "大臣能護法，況有故山期。"]'),
('5ebfd744-60e2-4fa9-aa54-23f3f1b0e7ca','奉和漢祖廟下之作','皇甫冉','唐','唐诗','tang','','[]','古廟風煙積，春城車騎過。',48,'全唐诗/poet.tang.13000.json','["古廟風煙積，春城車騎過。", "方修漢祖祀，更使沛童歌。", "寢帳巢禽出，香煙水霧和。", "神心降福處，應在故鄉多。"]'),
('fb3d8dc7-29bf-49d0-a109-ef9cfa7f20e1','和朝郎中揚子翫雪寄山陰嚴維','皇甫冉','唐','唐诗','tang','','[]','凝陰晦長箔，積雪滿通川。',48,'全唐诗/poet.tang.13000.json','["凝陰晦長箔，積雪滿通川。", "征客寒猶去，愁人晝更眠。", "謝家興詠日，漢將出師年。", "聞有招尋興，隨君訪戴船。"]'),
('e36794e1-c8aa-43e4-88ab-350d79324e6c','閑居作','皇甫冉','唐','唐诗','tang','','[]','多病辭官罷，閑居作賦成。',120,'全唐诗/poet.tang.13000.json','["多病辭官罷，閑居作賦成。", "圖書唯藥籙，飲食止藜羹。", "學謝淹中術，詩無鄴下名。", "不堪趨建禮，詎是厭承明。", "已輟金門步，方從石路行。", "遠山期道士，高柳覓先生。", "性懶尤因疾，家貧自省營。", "種苗雖尚短，穀價幸全輕。", "篇詠投康樂，壺觴就步兵。", "何人肯相訪，開戶一逢迎。"]'),
('9e52513d-af49-40cf-92d8-f8d239122e0d','歸渡洛水','皇甫冉','唐','唐诗','tang','','[]','暝色赴春愁，歸人南渡頭。',48,'全唐诗/poet.tang.13000.json','["暝色赴春愁，歸人南渡頭。", "渚煙空翠合，灘月碎光流。", "澧浦饒芳草，滄浪有釣舟。", "誰知放歌客，此意正悠悠。"]'),
('f76fe3df-fb0e-4d06-bd55-9e726ef336ca','送鄭二員外','皇甫冉','唐','唐诗','tang','','[]','置酒竟長宵，送君登遠道。',72,'全唐诗/poet.tang.13000.json','["置酒竟長宵，送君登遠道。", "羇心看旅雁，晚泊依秋草。", "秋草尚芊芊，離憂亦渺然。", "元戎辟才彥，行子犯風煙。", "風煙積惆悵，淮海殊飄蕩。", "明日是重陽，登高遠相望。"]'),
('8b33f522-6586-4fb7-95ea-782bc0c7699d','酬崔侍御期籍道士不至兼寄','皇甫冉','唐','唐诗','tang','','[]','一心求妙道，幾歲候真師。',48,'全唐诗/poet.tang.13000.json','["一心求妙道，幾歲候真師。", "丹竈今何在，白雲無定期。", "崑崙煙景絕，汗漫徃還遲。", "君但焚香待，人間到有時。"]'),
('f925ab31-9181-424a-b450-06933382fd4d','送裴陟歸常州','皇甫冉','唐','唐诗','tang','','[]','夜雨須停棹，秋風暗入衣。',24,'全唐诗/poet.tang.13000.json','["夜雨須停棹，秋風暗入衣。", "見君嘗北望，何事却南歸。"]'),
('392fb0df-c212-454b-a99c-fb5c64479e29','贈別','皇甫冉','唐','唐诗','tang','','[]','南橋春日暮，楊柳帶青渠。',24,'全唐诗/poet.tang.13000.json','["南橋春日暮，楊柳帶青渠。", "不得同攜手，空成意有餘。"]'),
('3fe69e18-fe22-4ea1-92b1-98ecf305d7dc','和袁郎中破賊後經剡中山水','皇甫冉','唐','唐诗','tang','','[]','武庫分帷幄，儒衣事鼓鼙。',72,'全唐诗/poet.tang.13000.json','["武庫分帷幄，儒衣事鼓鼙。", "兵連越徼外，寇盡海門西。", "節比全疎勒，功當雪會稽。", "旌旗迴剡嶺，士馬濯耶溪。", "受律梅初發，班師草未齊。", "行看佩金印，豈得訪丹梯。"]'),
('7f2e77fa-3093-46bd-837e-08dc3934ada6','徐州送丘侍御之越','皇甫冉','唐','唐诗','tang','','[]','時鳥催春色，離人惜歲華。',48,'全唐诗/poet.tang.13000.json','["時鳥催春色，離人惜歲華。", "遠山隨擁傳，芳草引還家。", "北固潮當闊，西陵路稍斜。", "縱令寒食過，猶有鏡中花。"]'),
('7b205910-b529-4b37-9cf0-b7587247f582','閑居','皇甫冉','唐','唐诗','tang','','["\u7530\u56ed"]','桃紅復含宿雨，柳綠更帶春煙。',28,'全唐诗/poet.tang.13000.json','["桃紅復含宿雨，柳綠更帶春煙。", "花落家童未掃，鶯啼山客猶眠。"]'),
('77588ed6-70a6-465e-bb2f-3f7d27fc4640','送延陵陳法師赴上元','皇甫冉','唐','唐诗','tang','','[]','延陵初罷講，建業去隨緣。',48,'全唐诗/poet.tang.13000.json','["延陵初罷講，建業去隨緣。", "翻譯推多學，壇場最少年。", "浣衣逢野水，乞食向人煙。", "遍禮南朝寺，焚香古像前。"]'),
('ec010d67-8a54-4e4e-a830-40b8e4bb9e6a','賦得海邊樹','皇甫冉','唐','唐诗','tang','','[]','歷歷緣荒岸，溟溟入遠天。',48,'全唐诗/poet.tang.13000.json','["歷歷緣荒岸，溟溟入遠天。", "每同沙草發，長共水雲連。", "搖落潮風早，離披海雨偏。", "故傷遊子意，多在客舟前。"]'),
('d3974504-f89f-4aa0-9400-ef0ef6de1e55','題昭上人房','皇甫冉','唐','唐诗','tang','','[]','沃州傳敎後，百衲老空林。',48,'全唐诗/poet.tang.13000.json','["沃州傳敎後，百衲老空林。", "慮盡朝昏磬，禪隨坐臥心。", "鶴飛湖草迥，門閉野雲深。", "地與天台接，中峯早晚尋。"]'),
('024e0857-25ec-40a8-8218-8dda78d89c77','送李使君赴撫州','皇甫冉','唐','唐诗','tang','','[]','遠送臨川守，還同康樂侯。',48,'全唐诗/poet.tang.13000.json','["遠送臨川守，還同康樂侯。", "歲時徒改易，今古接風流。", "五馬嘶長道，雙旌向本州。", "鄉心寄西北，應上郡城樓。"]'),
('8bbd3aaa-c910-4c4a-89d5-bc04a6ec6ca7','同樊潤州遊郡東山','皇甫冉','唐','唐诗','tang','','["\u957f\u6c5f"]','北固多陳迹，東山復盛遊。',48,'全唐诗/poet.tang.13000.json','["北固多陳迹，東山復盛遊。", "鐃聲發大道，草色引行騶。", "此地何時有，長江自古流。", "頻隨公府步，南客寄徐州。"]'),
('134b31c7-78cc-460d-b338-6994da4cbaad','酬楊侍御寺中見招','皇甫冉','唐','唐诗','tang','','[]','貧居依柳市，閑步在蓮宮。',36,'全唐诗/poet.tang.13000.json','["貧居依柳市，閑步在蓮宮。", "高閣宜春雨，長廊好嘯風。", "誠如雙樹下，豈比一丘中。"]'),
('95161070-6601-4b08-89ad-b4b3f9444e6e','重陽日酬李觀','皇甫冉','唐','唐诗','tang','','[]','不見白衣來送酒，但令黃菊自開花。',32,'全唐诗/poet.tang.13000.json','["不見白衣來送酒，但令黃菊自開花。", "愁看日晚良辰過，步步行尋陶令家。"]'),
('0a39188e-47fd-4e3f-9b87-3754a672273d','寄權器','皇甫冉','唐','唐诗','tang','','[]','露濕青蕪時欲晚，水流黃葉意無窮。',32,'全唐诗/poet.tang.13000.json','["露濕青蕪時欲晚，水流黃葉意無窮。", "節近重陽念歸否，眼前籬菊帶秋風。"]'),
('bc6d74a4-9808-4fed-8678-d1ea19674690','酬李判官度梨嶺見寄','皇甫冉','唐','唐诗','tang','','[]','隴首怨西征，嶺南雁北顧。',24,'全唐诗/poet.tang.13000.json','["隴首怨西征，嶺南雁北顧。", "行人與流水，共向閩中去。"]'),
('f1f199d7-7965-4a66-8c47-613420d00749','送魏六侍御葬','皇甫冉','唐','唐诗','tang','','[]','哭葬寒郊外，行將何所從。',120,'全唐诗/poet.tang.13000.json','["哭葬寒郊外，行將何所從。", "盛曹徒列柏，新墓已栽松。", "海月同千古，江雲覆幾重。", "舊書曾諫獵，遺草議登封。", "疇昔輕三事，嘗期老一峯。", "門臨商嶺道，窗引洛城鐘。", "應積泉中恨，無因世上逢。", "招尋偏見厚，疎慢亦相容。", "張范唯通夢，求羊永絕蹤。", "誰知長卿疾，歌賦不還邛。"]'),
('1e23c830-7db2-4780-96e5-a4940d1b8ed3','送張道士歸茅山謁李尊師','皇甫冉','唐','唐诗','tang','','[]','向山獨有一人行，近洞應逢雙鶴迎。',64,'全唐诗/poet.tang.13000.json','["向山獨有一人行，近洞應逢雙鶴迎。", "嘗以素書傳弟子，還因白石號先生。", "無窮杏樹行時種，幾許芝田向月耕。", "師事少君年歲久，欲隨旄節徃層城。"]'),
('8c6eb64a-78b1-4b36-93a8-5d96cd7651d9','詶裴補闕吳寺見尋','皇甫冉','唐','唐诗','tang','','[]','東林初結構，已有晚鐘聲。',48,'全唐诗/poet.tang.13000.json','["東林初結構，已有晚鐘聲。", "窻戶背流水，房廊半架城。", "遠山重疊見，芳草淺深生。", "每與君攜手，多煩長老迎。"]'),
('867523a0-6b22-4002-84e8-655273265d11','送王相公之幽州','皇甫冉','唐','唐诗','tang','','[]','自昔蕭曹任，難兼衛霍功。',72,'全唐诗/poet.tang.13000.json','["自昔蕭曹任，難兼衛霍功。", "勤勞無遠近，旌節屢西東。", "不選三河卒，還令萬里通。", "雁行緣古塞，馬鬣起長風。", "遮虜關山靜，防秋鼓角雄。", "徒思一攀送，羸老蓽門中。"]'),
('bd80d8ef-c061-4d52-bb4e-3b364ef260b2','題竹扇贈別','皇甫冉','唐','唐诗','tang','','[]','湘竹殊堪製，齊紈且未工。',48,'全唐诗/poet.tang.13000.json','["湘竹殊堪製，齊紈且未工。", "幸親芳袖日，尤帶舊林風。", "掩笑歌筵裏，傳書臥閣中。", "竟將爲別贈，寧與合歡同。"]'),
('b459aba9-305c-4d55-966c-d80e3409ec67','歸陽羨兼送劉八長卿','皇甫冉','唐','唐诗','tang','','[]','湖上孤帆別，江南謫宦歸。',48,'全唐诗/poet.tang.13000.json','["湖上孤帆別，江南謫宦歸。", "前程愁更遠，臨水淚沾衣。", "雲夢春山徧，瀟湘過客稀。", "武陵招我隱，歲晚閉柴扉。"]'),
('3379b41f-7a57-4cee-80e9-d4028f214653','東郊迎春','皇甫冉','唐','唐诗','tang','','[]','曉見蒼龍駕，東郊春已迎。',72,'全唐诗/poet.tang.13000.json','["曉見蒼龍駕，東郊春已迎。", "綵雲天仗合，玄象太階平。", "佳氣山川秀，和風政令行。", "句陳霜騎肅，御道雨師清。", "律向韶陽變，人隨草木榮。", "遙觀上林樹，今日遇遷鶯。"]'),
('687eb62a-e2af-449a-b1d5-4a8a7c0c6f09','招隱寺送閻判官還江州','皇甫冉','唐','唐诗','tang','','["\u957f\u6c5f"]','離別那逢秋氣悲，東林更作上方期。',64,'全唐诗/poet.tang.13000.json','["離別那逢秋氣悲，東林更作上方期。", "共知客路浮雲外，暫愛僧房墜葉時。", "長江九派人歸少，寒嶺千重雁度遲。", "借問潯陽在何處，每看潮落一相思。"]'),
('4459d728-2f6a-4900-aabd-8084573056d6','送李山人還','皇甫冉','唐','唐诗','tang','','[]','從來無檢束，只欲老煙霞。',24,'全唐诗/poet.tang.13000.json','["從來無檢束，只欲老煙霞。", "雞犬聲相應，深山有幾家。"]'),
('c8d44a25-b271-4527-b767-e338e7b02217','韋中丞西廳海榴','皇甫冉','唐','唐诗','tang','','[]','海花爭讓候榴花，犯雪先開內史家。',32,'全唐诗/poet.tang.13000.json','["海花爭讓候榴花，犯雪先開內史家。", "末客朝朝鈴閣下，從公步履玩年華。"]'),
('85b6cd9a-5f4e-4289-9ee6-64807a456616','洪澤館壁見故禮部尚書題詩','皇甫冉','唐','唐诗','tang','','[]','底事洪澤壁，空留黃絹詞。',24,'全唐诗/poet.tang.13000.json','["底事洪澤壁，空留黃絹詞。", "年年淮水上，行客不勝悲。"]'),
('dcf2b41c-7c93-4b79-84f9-230503bae9d8','望南山雪懷山寺普上人','皇甫冉','唐','唐诗','tang','','[]','夜夜夢蓮宮，無由見遠公。',24,'全唐诗/poet.tang.13000.json','["夜夜夢蓮宮，無由見遠公。", "朝來出門望，知在雪山中。"]'),
('3ed91026-4513-4b2e-b04a-5536981cd00c','送夔州班使君','皇甫冉','唐','唐诗','tang','','[]','晚日照樓邊，三軍拜峽前。',48,'全唐诗/poet.tang.13000.json','["晚日照樓邊，三軍拜峽前。", "白雲隨浪散，青壁與山連。", "萬嶺岷峨雪，千家橘柚川。", "還如赴河內，天上去經年。"]'),
('45e0a4e0-4593-4778-992c-f98f0bbc1a24','尋戴處士','皇甫冉','唐','唐诗','tang','','[]','車馬長安道，誰知大隱心。',48,'全唐诗/poet.tang.13000.json','["車馬長安道，誰知大隱心。", "蠻僧留古鏡，蜀客寄新琴。", "曬藥竹齋暖，擣茶松院深。", "思君一相訪，殘雪似山陰。"]'),
('2067bcb7-fb10-4b6d-865f-aea6e59e57a1','早發中嚴寺別契上人','皇甫冉','唐','唐诗','tang','','[]','蒼蒼松桂陰，殘月半西岑。',48,'全唐诗/poet.tang.13000.json','["蒼蒼松桂陰，殘月半西岑。", "素壁寒燈暗，紅爐夜火深。", "廚開山鼠散，鐘盡嶺猿吟。", "行役方如此，逢師懶話心。"]'),
('44189a1f-e697-4697-9cd9-c570a949e5c8','華清宮','皇甫冉','唐','唐诗','tang','','[]','驪岫接新豐，岧嶢駕翠空。',72,'全唐诗/poet.tang.13000.json','["驪岫接新豐，岧嶢駕翠空。", "鑿山開祕殿，隱霧閉仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。", "溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，沈深閉綺櫳。", "東郊倚望處，瑞氣靄濛濛。"]'),
('9d974ae6-2223-4fa3-bb66-15a079adec68','送孔巢父赴河南軍','皇甫冉','唐','唐诗','tang','','[]','江城相送阻煙波，況復新秋一雁過。',64,'全唐诗/poet.tang.13000.json','["江城相送阻煙波，況復新秋一雁過。", "聞道全師征北虜，更言諸將會南河。", "邊心杳杳鄉人絕，塞草青青戰馬多。", "共許陳琳工奏記，知君名宦未蹉跎。"]'),
('f27d0c16-26f5-4c0c-9914-4fd9dbce5021','李二侍御丹陽東去新亭','皇甫冉','唐','唐诗','tang','','[]','姑蘇東望海陵間，幾度裁書信未還。',64,'全唐诗/poet.tang.13000.json','["姑蘇東望海陵間，幾度裁書信未還。", "長在府中持白簡，豈知天畔有青山。", "人歸極浦寒流廣，雁下平蕪秋野閑。", "舊日新亭更攜手，他鄉風景亦相關。"]'),
('c400192f-cbb4-41e4-8710-4713fa25784e','夜發沅江寄李潁川劉侍郎','皇甫冉','唐','唐诗','tang','','[]','半夜回舟入楚鄉，月明山水共蒼蒼。',32,'全唐诗/poet.tang.13000.json','["半夜回舟入楚鄉，月明山水共蒼蒼。", "孤猨更發秋風裏，不是愁人亦斷腸。"]'),
('2961da31-de2e-4d7a-8b6d-1f69cbd35b1a','浪淘沙二首 一','皇甫冉','唐','唐诗','tang','','[]','蠻歌荳蔻北人愁，松雨蒲風野艇秋。',32,'全唐诗/poet.tang.13000.json','["蠻歌荳蔻北人愁，松雨蒲風野艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。"]'),
('fcba4734-18a5-4d8d-8d12-9b5f4fb49be2','浪淘沙二首 二','皇甫冉','唐','唐诗','tang','','[]','瀨頭細草接疎林，惡浪罾船半欲沈。',32,'全唐诗/poet.tang.13000.json','["瀨頭細草接疎林，惡浪罾船半欲沈。", "宿鷺眠洲非舊浦，去年沙觜是江心。"]'),
('d35f583a-c20c-453c-a886-e13f98b2e4b4','春思','皇甫冉','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e03\u8a00\u5f8b\u8bd7", "\u6625\u5929", "\u5987\u5973", "\u95fa\u6028"]','鶯啼燕語報新年，馬邑龍堆路幾千。',64,'全唐诗/poet.tang.13000.json','["鶯啼燕語報新年，馬邑龍堆路幾千。", "家住秦城鄰漢苑，心隨明月到胡天。", "機中錦字論長恨，樓上花枝笑獨眠。", "爲問元戎竇車騎，何時反斾勒燕然。"]'),
('f7722e7f-beea-4b7a-8616-4e1696ae3df5','逢莊納因贈','皇甫冉','唐','唐诗','tang','','[]','世故還相見，天涯共向東。',48,'全唐诗/poet.tang.13000.json','["世故還相見，天涯共向東。", "春歸江海上，人老別離中。", "郡吏名何晚，沙鷗道自同。", "甘泉須早獻，且莫歎飄蓬。"]'),
('e5780e8f-b533-48f1-ad90-d91993d5b0df','送韋山人歸鍾山所居','皇甫冉','唐','唐诗','tang','','[]','逸人歸路遠，弟子出山迎。',48,'全唐诗/poet.tang.13000.json','["逸人歸路遠，弟子出山迎。", "服藥顏雖駐，耽書癖已成。", "柴扉度歲月，藜杖見公聊。", "更作儒林傳，還應有姓名。"]'),
('cf6fe162-a656-4325-87bd-6ca772dbf177','送普門上人','皇甫冉','唐','唐诗','tang','','[]','花宮難久別，道者憶千燈。',48,'全唐诗/poet.tang.13000.json','["花宮難久別，道者憶千燈。", "殘雪入林路，深山歸寺僧。", "日光依嫩草，泉響滴春冰。", "何用求方便，看心是一乘。"]'),
('ef30530e-dc97-47b6-9ec2-1ca6a085ad81','怨回紇歌二首 一','皇甫冉','唐','唐诗','tang','','[]','白首南朝女，愁聽異域歌。',48,'全唐诗/poet.tang.13000.json','["白首南朝女，愁聽異域歌。", "收兵頡利國，飲馬胡蘆河。", "毳布腥羶久，穹廬歲月多。", "雕巢城上宿，吹笛淚滂沱。"]'),
('79339788-9ad4-4138-babf-0a439300eeb3','怨回紇歌二首 二','皇甫冉','唐','唐诗','tang','','[]','祖席駐征櫂，開帆信候潮。',48,'全唐诗/poet.tang.13000.json','["祖席駐征櫂，開帆信候潮。", "隔煙桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。", "別離惆悵淚，江路濕紅蕉。"]'),
('34e6245a-8954-49e2-aebb-c25f7f3368ce','句','皇甫冉','唐','唐诗','tang','','[]','微官同侍蒼龍闕，直諫偏推白馬生。',16,'全唐诗/poet.tang.13000.json','["微官同侍蒼龍闕，直諫偏推白馬生。"]'),
('0e6e408e-d1fb-49a2-bcae-d31069d58ae9','代宛轉歌二首 一','劉方平','唐','唐诗','tang','','[]','星參差，明月二八燈五枝。',50,'全唐诗/poet.tang.13000.json','["星參差，明月二八燈五枝。", "黃鶴瑤琴將別去，芙蓉羽帳惜空垂。", "歌宛轉，宛轉恨無窮。", "願爲潮與浪，俱起碧流中。"]'),
('c2370a95-4199-4955-a3a6-924cf42519d4','代宛轉歌二首 二','劉方平','唐','唐诗','tang','','[]','曉將近，黃姑織女銀河盡。',50,'全唐诗/poet.tang.13000.json','["曉將近，黃姑織女銀河盡。", "九華錦衾無復情，千金寶鏡誰能引。", "歌宛轉，宛轉傷別離。", "願作楊與柳，同向玉窗垂。"]'),
('d8372fb3-059f-4356-b372-01fe81ca5941','烏栖曲二首 一','劉方平','唐','唐诗','tang','','[]','蛾眉曼臉傾城國，鳴環動佩新相識。',32,'全唐诗/poet.tang.13000.json','["蛾眉曼臉傾城國，鳴環動佩新相識。", "銀漢斜臨白玉堂，芙蓉行障掩燈光。"]'),
('a69904fe-40ee-44b5-b848-63c1c74307c4','烏栖曲二首 二','劉方平','唐','唐诗','tang','','[]','畫舸雙艚錦爲纜，芙蓉花發蓮葉暗。',32,'全唐诗/poet.tang.13000.json','["畫舸雙艚錦爲纜，芙蓉花發蓮葉暗。", "門前月色映橫塘，感郎中夜度瀟湘。"]'),
('bc6de100-0c6d-4f48-a2ed-f738e4098069','巫山高','劉方平','唐','唐诗','tang','','[]','楚國巫山秀，清猨日夜啼。',48,'全唐诗/poet.tang.13000.json','["楚國巫山秀，清猨日夜啼。", "萬重春樹合，十二碧峰齊。", "峽出朝雲下，江來暮雨西。", "陽臺歸路直，不畏向家迷。"]'),
('19f32e8e-e866-48c8-a870-a759265945ac','巫山神女','劉方平','唐','唐诗','tang','','[]','神女藏難識，巫山秀莫羣。',48,'全唐诗/poet.tang.13000.json','["神女藏難識，巫山秀莫羣。", "今宵爲大雨，昨日作孤雲。", "散漫愁巴峽，徘徊戀楚君。", "先王爲立廟，春樹幾氛氳。"]'),
('47b3819c-142f-41f0-ab66-dda052360a3b','梅花落','劉方平','唐','唐诗','tang','','[]','新歲芳梅樹，繁花四面同。',48,'全唐诗/poet.tang.13000.json','["新歲芳梅樹，繁花四面同。", "春風吹漸落，一夜幾枝空。", "少婦今如此，長城恨不窮。", "莫將遼海雪，來比後庭中。"]'),
('144809d9-f96f-4005-8390-7181bf9e4542','銅雀妓','劉方平','唐','唐诗','tang','','[]','遺令奉君王，嚬蛾強一妝。',48,'全唐诗/poet.tang.13000.json','["遺令奉君王，嚬蛾強一妝。", "歲移陵樹色，恩在舞衣香。", "玉座生秋氣，銅臺下夕陽。", "淚痕霑井榦，舞袖爲誰長。"]'),
('c2a0356b-afaf-434f-aa72-9d20a9c14eeb','秋夜思','劉方平','唐','唐诗','tang','','[]','旅夢何時盡，征途望每賒。',48,'全唐诗/poet.tang.13000.json','["旅夢何時盡，征途望每賒。", "晚秋淮上水，新月楚人家。", "猨嘯空山近，鴻飛極浦斜。", "明朝南岸去，言折桂枝花。"]'),
('65e3a77a-16bf-4493-ba3a-579310ca4115','秋夜泛舟','劉方平','唐','唐诗','tang','','[]','林塘夜發舟，蟲響荻颼颼。',48,'全唐诗/poet.tang.13000.json','["林塘夜發舟，蟲響荻颼颼。", "萬影皆因月，千聲各爲秋。", "歲華空復晚，鄉思不堪愁。", "西北浮雲外，伊川何處流。"]'),
('75a175a4-d16a-43d3-9230-9541b5817fdb','折楊枝','劉方平','唐','唐诗','tang','','[]','官渡初楊柳，風來亦動搖。',48,'全唐诗/poet.tang.13000.json','["官渡初楊柳，風來亦動搖。", "武昌行路好，應爲最長條。", "葉映黃鸝夕，花繁白雪朝。", "年年攀折意，流恨入纖腰。"]'),
('e810fc2a-2af1-40f2-bf48-aee1bb90c305','班婕妤','劉方平','唐','唐诗','tang','','[]','夕殿別君王，宮深月似霜。',48,'全唐诗/poet.tang.13000.json','["夕殿別君王，宮深月似霜。", "人幽在長信，螢出向昭陽。", "露浥紅蘭濕，秋凋碧樹傷。", "惟當合歡扇，從此篋中藏。"]'),
('d980038f-486c-4784-970e-59ed6a95dafd','新春','劉方平','唐','唐诗','tang','','[]','南陌春風早，東隣曙色斜。',48,'全唐诗/poet.tang.13000.json','["南陌春風早，東隣曙色斜。", "一花開楚國，雙燕入盧家。", "眠罷梳雪髻，妝成上錦車。", "誰知如昔日，更浣越溪紗。"]'),
('ed8956d2-37e9-487b-822f-fdaac68570d5','寄嚴八判官','劉方平','唐','唐诗','tang','','[]','洛陽新月動秋砧，瀚海沙場天半陰。',64,'全唐诗/poet.tang.13000.json','["洛陽新月動秋砧，瀚海沙場天半陰。", "出塞能全仲叔策，安親更切老萊心。", "漢家宮裏風雲曉，羌笛聲中雨雪深。", "懷袖未傳三歲字，相思空作隴頭吟。"]'),
('b108a510-8ab7-455a-bf9c-f7883f9960b7','秋夜寄皇甫冉鄭豐','劉方平','唐','唐诗','tang','','[]','洛陽清夜白雲歸，城裏長河列宿稀。',64,'全唐诗/poet.tang.13000.json','["洛陽清夜白雲歸，城裏長河列宿稀。", "秋後見飛千里鴈，月中聞搗萬家衣。", "長憐西雍青門道，久別東吳黃鵠磯。", "借問客書何所寄，用心不啻兩鄉違。"]'),
('e6d87d07-0173-41b7-bd5a-52214bc1864e','寄隴右嚴判官','劉方平','唐','唐诗','tang','','[]','副相西征重，蒼生屬望晨。',192,'全唐诗/poet.tang.13000.json','["副相西征重，蒼生屬望晨。", "還同周薄伐，不取漢和親。", "虜陣摧枯易，王師決勝頻。", "高旗臨鼓角，太白靜風塵。", "赤狄爭歸化，青羌已請臣。", "遙傳閫外美，盛選幕中賓。", "玉劒光初發，冰壺色自真。", "忠貞期報主，章服豈榮身。", "邊草含風綠，征鴻過月新。", "胡笳長出塞，隴水半歸秦。", "絕漠多來往，連年厭苦辛。", "路經西漢雪，家擲後園春。", "誰念煙雲裏，深居汝潁濱。", "一叢黃菊地，九日白衣人。", "松葉疎開嶺，桃花密映津。", "縑書若有寄，爲訪許由鄰。"]'),
('1eb3241e-272e-4183-801d-b37e6beb048f','擬娼樓節怨','劉方平','唐','唐诗','tang','','[]','上苑離離鶯度，昆明冪冪蒲生。',28,'全唐诗/poet.tang.13000.json','["上苑離離鶯度，昆明冪冪蒲生。", "時光春華可惜，何須對鏡含情。"]'),
('8a4edbf7-050f-4176-87cc-a3b461ea1acf','採蓮曲','劉方平','唐','唐诗','tang','','[]','落日晴江裏，荆歌豔楚腰。',24,'全唐诗/poet.tang.13000.json','["落日晴江裏，荆歌豔楚腰。", "採蓮從小慣，十五即乘潮。"]'),
('31dac9d0-ff07-4ce9-b98c-01be1efdf739','長信宮','劉方平','唐','唐诗','tang','','[]','夢裏君王近，宮中河漢高。',24,'全唐诗/poet.tang.13000.json','["夢裏君王近，宮中河漢高。", "秋風能再熱，團扇不辭勞。"]'),
('fdfb8b8e-be3f-4928-b6ad-d418b60a3013','京兆眉','劉方平','唐','唐诗','tang','','[]','新作蛾眉樣，誰將月裏同。',24,'全唐诗/poet.tang.13000.json','["新作蛾眉樣，誰將月裏同。", "有來凡幾日，相效滿城中。"]'),
('56863b6d-0025-48ab-a1a3-76dafc6bf99b','春雪','劉方平','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea"]','飛雪帶春風，裴回亂繞空。',24,'全唐诗/poet.tang.13000.json','["飛雪帶春風，裴回亂繞空。", "君看似花處，偏在洛陽東。"]'),
('02f6b39a-8235-4337-9e5e-294742bc3f0e','望夫石','劉方平','唐','唐诗','tang','','[]','佳人成古石，蘚駁覆花黃。',24,'全唐诗/poet.tang.13000.json','["佳人成古石，蘚駁覆花黃。", "猶有春山杏，枝枝似薄妝。"]'),
('ef544177-4d1c-4532-9ceb-aeeb4986c388','送別','劉方平','唐','唐诗','tang','','[]','華亭霽色滿今朝，雲裏檣竿去轉遙。',32,'全唐诗/poet.tang.13000.json','["華亭霽色滿今朝，雲裏檣竿去轉遙。", "莫怪山前深復淺，清淮一日兩迴潮。"]'),
('79e7ec6e-0d6c-4f95-8181-4671c42e1faf','夜月','劉方平','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6708\u4eae", "\u6625\u5929", "\u7530\u56ed", "\u4e5d\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u4e2d\u79cb"]','更深月色半人家，北斗闌干南斗斜。',32,'全唐诗/poet.tang.13000.json','["更深月色半人家，北斗闌干南斗斜。", "今夜偏知春氣暖，蟲聲新透綠窗紗。"]'),
('fc1bc01d-c281-40fd-9e0d-4c484539e4ae','春怨','劉方平','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u4e03\u8a00\u7edd\u53e5", "\u5bab\u6028"]','紗窗日落漸黃昏，金屋無人見淚痕。',32,'全唐诗/poet.tang.13000.json','["紗窗日落漸黃昏，金屋無人見淚痕。", "寂寞空庭春欲晚，梨花滿地不開門。"]'),
('09666f87-a152-4a41-a35b-8971b234cfa7','代春怨','劉方平','唐','唐诗','tang','','["\u6625\u5929", "\u95fa\u6028"]','朝日殘鶯伴妾啼，開簾只見草萋萋。',32,'全唐诗/poet.tang.13000.json','["朝日殘鶯伴妾啼，開簾只見草萋萋。", "庭前時有東風入，楊柳千條盡向西。"]'),
('80832caa-35f3-4c50-86f5-66218ec57051','宣州東峰亭各賦一物得古壁苔','劉太真','唐','唐诗','tang','','[]','苒苒溫寒泉，綿綿古危壁。',36,'全唐诗/poet.tang.13000.json','["苒苒溫寒泉，綿綿古危壁。", "光含孤翠動，色與暮雲寂。", "深淺松月間，幽人自登歷。"]'),
('6e17f84c-a6f4-4052-bd4d-452be8b4dbc2','顧十二況左遷過韋蘇州房杭州韋睦州三使君皆有郡中燕集詩辭章高麗鄙夫之所仰慕顧生既至留連笑語因亦成篇以繼三君子之風焉','劉太真','唐','唐诗','tang','','[]','寵至乃不驚，罪及非無由。',132,'全唐诗/poet.tang.13000.json','["寵至乃不驚，罪及非無由。", "奔迸歷畏途，緬貌赴偏陬。", "牧此彫弊甿，屬當賦斂秋。", "鳳興諒無補，旬暇焉敢休。", "前日懷友生，獨登城上樓。", "迢迢西北望，遠思不可收。", "今曰車騎來，曠然銷人憂。", "晨迎東齋飯，晚度南溪遊。", "以我碧流水，泊君青翰舟。", "莫將遷客程，不爲勝境留。", "飛札謝三守，斯篇希見酬。"]'),
('b66503e3-45bd-442b-9c56-85787aad2f1b','貢院寄前主司蕭尚書聽','劉太真','唐','唐诗','tang','','[]','獨坐貢闈裏，愁心芳草生。',24,'全唐诗/poet.tang.13000.json','["獨坐貢闈裏，愁心芳草生。", "山公昨夜事，應見此時情。"]'),
('56c18f2c-6e0d-49c0-9095-cc1674caaac5','東峰亭同劉太真各賦一物得垂澗藤','袁傪','唐','唐诗','tang','','[]','寒澗留不息，古藤終日垂。',36,'全唐诗/poet.tang.13000.json','["寒澗留不息，古藤終日垂。", "迎風仍未定，拂水更相宜。", "新花與舊葉，惟有幽人知。"]'),
('bd72add0-bcb6-47de-a424-65bc31397b69','喜陸侍御破石埭草寇東峰亭賦詩','袁傪','唐','唐诗','tang','','[]','古詩東峰上，登臨興有餘。',74,'全唐诗/poet.tang.13000.json','["古詩東峰上，登臨興有餘。", "同觀白簡使，新報赤囊書。", "幾處閑烽堠，千方慶里閭。", "欣欣夏木長，寂寂晚煙徐。", "戰罷言歸馬，遠師賦出車。", "因知越范蠡，湖海意[何如]。"]'),
('7bf79533-c907-461a-94b7-24bb9251e388','東峰亭各賦一物得嶺上雲','崔何','唐','唐诗','tang','','[]','佇立增遠意，中峰見孤雲。',36,'全唐诗/poet.tang.13000.json','["佇立增遠意，中峰見孤雲。", "溶溶傍危石，片片宜夕曛。", "漸向羣木盡，殘飛更氤氳。"]'),
('0cf92e7b-c033-4304-88e6-29f1ee995a6d','喜陸侍御破石埭草寇東峰亭賦詩','崔何','唐','唐诗','tang','','[]','絕景西溪寺，連延近郭山。',72,'全唐诗/poet.tang.13000.json','["絕景西溪寺，連延近郭山。", "高深清扃外，行止翠微間。", "江澈煙塵靜，川源草樹閑。", "中丞健步到，柱史捷書還。", "一戰清戎越，三吳變險艱。", "功名麟閣上，得詠入秦關。"]'),
('4047ab19-f7c0-494d-bb6c-6b75735c8380','東峰亭各賦一物得幽徑石','王緯','唐','唐诗','tang','','[]','片石東溪上，陰崖剩阻修。',36,'全唐诗/poet.tang.13000.json','["片石東溪上，陰崖剩阻修。", "雨餘青石靄，歲晚綠苔幽。", "從來不可轉，今日爲人留。"]'),
('649179e5-991e-4826-a161-35332add157e','喜陸侍御破石埭草寇東峰亭賦詩','王緯','唐','唐诗','tang','','[]','蜂蠆聚吳州，推賢奉聖憂。',72,'全唐诗/poet.tang.13000.json','["蜂蠆聚吳州，推賢奉聖憂。", "忠誠資上策，仁勇佐前籌。", "草木成鵝鸛，戈鋋復斗牛。", "戎車一戰後，殘壘五兵收。", "野靜山戎險，江平水面流。", "更憐羈旅客，從此罷葵丘。"]'),
('4c1ed3d9-0a74-4d3b-98a1-1333b945d17d','東峰亭各賦一物得臨軒桂','郭澹','唐','唐诗','tang','','[]','青青芳桂樹，幽陰在庭軒。',36,'全唐诗/poet.tang.13000.json','["青青芳桂樹，幽陰在庭軒。", "向日陰還合，從風葉乍翻。", "共看霜雪後，終不變涼暄。"]'),
('b490c7d7-9127-4c57-8e32-84d3296eaf08','喜陸侍御破石埭草寇東峰亭賦詩','郭澹','唐','唐诗','tang','','[]','介胄鷹揚出，山林蟻聚空。',72,'全唐诗/poet.tang.13000.json','["介胄鷹揚出，山林蟻聚空。", "忽聞飛簡報，曾是坐籌功。", "逈夜昏氛滅，危亭眺望雄。", "茂勳推世上，餘興寄杯中。", "喜色煙霞改，歡忻里巷同。", "幸茲尊俎末，飲至又從公。"]'),
('8830f54f-bf1c-4db2-96a5-4521e4899c00','東峰亭各賦一物得林中翠','高傪','唐','唐诗','tang','','[]','杳靄無定狀，霏微常滿林。',36,'全唐诗/poet.tang.13000.json','["杳靄無定狀，霏微常滿林。", "清風光不散，過雨色偏深。", "幽意賞難盡，終朝再招尋。"]'),
('2797a36b-cdb9-4ace-a0dc-672bf500419b','東峰亭各賦一物得棲煙鳥','李岑','唐','唐诗','tang','','[]','從來養毛羽，昔日曾飛遷。',36,'全唐诗/poet.tang.13000.json','["從來養毛羽，昔日曾飛遷。", "變轉對朝陽，差池棲夕煙。", "遇此枝葉覆，夙舉冀沖天。"]'),
('93b1a34a-825b-4b0c-912a-d978c04cdc48','東峰亭各賦一物得寒溪草','蘇寓','唐','唐诗','tang','','[]','冪䍥溪邊草，遊人不厭看。',36,'全唐诗/poet.tang.13000.json','["冪䍥溪邊草，遊人不厭看。", "餘芳幽處老，深色望中寒。", "幸得陪情興，青青賞未闌。"]'),
('913c4360-669c-4e85-ba3d-49dec96abce4','東峰亭各賦一物得陰崖竹','袁邕','唐','唐诗','tang','','[]','終歲寒苔色，寂寥幽思深。',36,'全唐诗/poet.tang.13000.json','["終歲寒苔色，寂寥幽思深。", "朝歌猶夕嵐，日永流清陰。", "龍鍾負煙雪，自有凌雲心。"]'),
('6a6d275e-0794-441d-bb22-b29972e7e7cd','唐德明興聖廟樂章 迎神','李紓','唐','唐诗','tang','','[]','元尊九德，佐堯光宅。',40,'全唐诗/poet.tang.13000.json','["元尊九德，佐堯光宅。", "烈祖太宗，方周作伯。", "響懷霜露，樂變金石。", "白雲青風，髣髴來格。"]'),
('8d74a95e-bab7-4162-8bd8-7de90b75ddcf','唐德明興聖廟樂章 登歌奠幣','李紓','唐','唐诗','tang','','[]','四時有典，百事來祭。',40,'全唐诗/poet.tang.13000.json','["四時有典，百事來祭。", "尊祖奉宗，嚴禋大帝。", "禮先蒼璧，奠備黝制。", "於萬斯年，熙成帝系。"]'),
('3ee77bdf-cd73-4f30-847b-b11394b3e630','唐德明興聖廟樂章 迎俎','李紓','唐','唐诗','tang','','[]','盛牲實俎，涓選休成。',40,'全唐诗/poet.tang.13000.json','["盛牲實俎，涓選休成。", "鼎煁陽燧，玉盥陰精。", "有飶嘉豆，既和大羹。", "侑以清樂，細齊人情。"]'),
('7139c59e-7b56-40bb-98c4-c67f0da56bca','唐德明興聖廟樂章 德明酌獻','李紓','唐','唐诗','tang','','[]','清廟弈弈，和樂雍雍。',42,'全唐诗/poet.tang.13000.json','["清廟弈弈，和樂雍雍。", "器尊犧象，禮屬宗公。", "白水方[祼]，黃流在中。", "謨明之德，萬古清風。"]'),
('1e2f5611-3d0e-4b0c-a986-b40a523a5c66','唐德明興聖廟樂章 興聖酌獻','李紓','唐','唐诗','tang','','[]','閟宮靜謐，合樂周張。',40,'全唐诗/poet.tang.13000.json','["閟宮靜謐，合樂周張。", "泰尊始獻，百末重觴。", "震澹存誠，庶幾迪嘗。", "遙源之祚，天漢靈長。"]'),
('7d59460b-b1a2-4d2b-a7c1-7d801ac8d860','唐德明興聖廟樂章 亞獻終獻','李紓','唐','唐诗','tang','','[]','惟清惟肅，靡聞靡見。',40,'全唐诗/poet.tang.13000.json','["惟清惟肅，靡聞靡見。", "舉備九成，俛終三獻。", "慶彰曼壽，胙撤嘉薦。", "瘞玉埋牲，禮神斯徧。"]'),
('62123595-e471-4263-929f-5bf84d8890c8','唐德明興聖廟樂章 送神','李紓','唐','唐诗','tang','','[]','元精回復，靈貺繁滋。',40,'全唐诗/poet.tang.13000.json','["元精回復，靈貺繁滋。", "風灑蘭路，雲搖桂旗。", "高丘緬邈，涼部逶遲。", "瞻望靡及，纏綿永思。"]'),
('768101d9-fc3c-4f85-aa98-e01ea8dea5e9','讓皇帝廟樂章 迎神','李紓','唐','唐诗','tang','','[]','皇矣天宗，德先王季。',40,'全唐诗/poet.tang.13000.json','["皇矣天宗，德先王季。", "因心則友，克讓以位。", "爰命有司，式尊前志。", "神其降靈，昭饗祀事。"]'),
('d192476f-adfa-4a7a-a1b0-78575fe4bfe1','讓皇帝廟樂章 奠幣','李紓','唐','唐诗','tang','','[]','惟帝時若，去而上仙。',40,'全唐诗/poet.tang.13000.json','["惟帝時若，去而上仙。", "祀用商武，樂備宮懸。", "白壁加薦，玄纁告虔。", "子孫拜後，承茲吉蠲。"]'),
('933e80d0-3b30-4480-bde3-1d8760341efb','讓皇帝廟樂章 迎俎','李紓','唐','唐诗','tang','','[]','祀盛體薦，禮協粢盛。',40,'全唐诗/poet.tang.13000.json','["祀盛體薦，禮協粢盛。", "方周假廟，用魯純牲。", "捧撤祗敬，擊拊和鳴。", "受釐歸胙，既戒而平。"]'),
('6134bd98-c13f-4dde-b5c5-2c61bbb2f262','讓皇帝廟樂章 酌獻','李紓','唐','唐诗','tang','','[]','八音具舉，三壽既盥。',40,'全唐诗/poet.tang.13000.json','["八音具舉，三壽既盥。", "潔茲宗彝，瑟彼圭瓚。", "蘭肴重錯，椒醑飄散。", "降祚維城，永爲藩翰。"]'),
('a47ec48a-49e4-4c2f-ab12-390dad8135cc','讓皇帝廟樂章 亞獻終獻','李紓','唐','唐诗','tang','','[]','秩禮有序，和音既同。',40,'全唐诗/poet.tang.13000.json','["秩禮有序，和音既同。", "九儀不忒，三揖將終。", "孝感藩后，相維辟公。", "四時之典，永永無窮。"]'),
('4a7abd91-b70d-4c99-b6a1-0062f312021e','讓皇帝廟樂章 送神','李紓','唐','唐诗','tang','','[]','奠獻已事，昏昕載分。',40,'全唐诗/poet.tang.13000.json','["奠獻已事，昏昕載分。", "風搖雨散，靈衛絪緼。", "龍駕帝服，已騰五雲。", "泮宮復閟，寂寞無聞。"]'),
('ca20506a-d7d5-4253-975d-1377364ea11a','釋奠武成王樂章 迎神','于邵','唐','唐诗','tang','','[]','卜畋不從，兆發非熊。',50,'全唐诗/poet.tang.13000.json','["卜畋不從，兆發非熊。", "乃傾荒政，爰佐一戎。", "盛烈載垂，命祀維崇。", "日練上戊，宿嚴閟宮。", "迎奏嘉至，感而遂通。"]'),
('d75dbae3-acc5-4b29-9a2a-02ef1c78c828','釋奠武成王樂章 奠幣登歌','于邵','唐','唐诗','tang','','[]','管罄升，壇薌集。',48,'全唐诗/poet.tang.13000.json','["管罄升，壇薌集。", "上公進，嘉幣執。", "信以通，僾如及。", "恢帝功，錫后邑。", "四維張，百度立。", "綿億載，邈難挹。"]'),
('7c7a7239-144e-4d4e-98d0-0ca472a4b4aa','釋奠武成王樂章 迎俎酌獻','于邵','唐','唐诗','tang','','[]','五齊絜，九牢碩。',48,'全唐诗/poet.tang.13000.json','["五齊絜，九牢碩。", "梡橛循，罍斝滌。", "進具物，揚鴻勣。", "和奏發，高靈寂。", "虔告終，繁祉錫。", "昭秩祀，永無易。"]'),
('2ae7016e-6614-4060-92bd-17930bed017a','釋奠武成王樂章 亞獻終獻','于邵','唐','唐诗','tang','','[]','貳觴以獻，三變其終。',50,'全唐诗/poet.tang.13000.json','["貳觴以獻，三變其終。", "顧此非馨，尚達斯衷。", "茅縮可致，神歆載融。", "始神翊周，拯溺除凶。", "時維降祐，永絕興戎。"]'),
('4973cb28-d9ab-4709-88b0-d86860495d14','釋奠武成王樂章 送神','于邵','唐','唐诗','tang','','[]','明祀方終，備樂斯闋。',40,'全唐诗/poet.tang.13000.json','["明祀方終，備樂斯闋。", "黝纁就瘞，豆籩告撤。", "肸蠁尚餘，光景云滅。", "返歸虛極，神心則悅。"]'),
('63950163-6a10-4e74-af8a-09886e4ef2a8','登鸛雀樓','王之渙','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u5c71\u6c34", "\u52b1\u5fd7", "\u5510\u8bd7\u4e09\u767e\u9996", "\u767b\u697c", "\u5199\u666f"]','白日依山盡，黃河入海流。',24,'全唐诗/poet.tang.13000.json','["白日依山盡，黃河入海流。", "欲窮千里目，更上一層樓。"]'),
('5668e19f-051f-4c3c-bd36-db966c3d7e71','送別','王之渙','唐','唐诗','tang','','["\u67f3\u6811", "\u9001\u522b", "\u79bb\u522b"]','楊柳東風樹，青青夾御河。',24,'全唐诗/poet.tang.13000.json','["楊柳東風樹，青青夾御河。", "近來攀折苦，應爲別離多。"]'),
('526d4ecc-e123-4b9d-a213-958bb947593d','涼州詞二首” 一','王之渙','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u6cb3", "\u5c71\u6c34", "\u5199\u666f", "\u4e50\u5e9c", "\u601d\u4e61"]','黃河遠上白雲間，一片孤城萬仞山。',32,'全唐诗/poet.tang.13000.json','["黃河遠上白雲間，一片孤城萬仞山。", "羌笛何須怨楊柳，春光不度玉門關。"]'),
('a7c341d2-bc57-45b0-8c7a-ef7c1740b3e8','涼州詞二首” 二','王之渙','唐','唐诗','tang','','[]','單于北望拂雲堆，殺馬登壇祭幾迴。',32,'全唐诗/poet.tang.13000.json','["單于北望拂雲堆，殺馬登壇祭幾迴。", "漢家天子今神武，不肯和親歸去來。"]'),
('750d30c4-bbe3-4d0b-8d72-e8d9b92fbdfd','宴詞','王之渙','唐','唐诗','tang','','[]','長堤春水綠悠悠，畎入漳河一道流。',32,'全唐诗/poet.tang.13000.json','["長堤春水綠悠悠，畎入漳河一道流。", "莫聽聲聲催去櫂，桃溪淺處不勝舟。"]'),
('6f24b694-4965-4999-9945-e34ef371bff3','九日送別','王之渙','唐','唐诗','tang','','["\u79bb\u522b", "\u996e\u9152", "\u91cd\u9633\u8282"]','薊庭蕭瑟故人稀，何處登高且送歸。',32,'全唐诗/poet.tang.13000.json','["薊庭蕭瑟故人稀，何處登高且送歸。", "今日暫同芳菊酒，明朝應作斷蓬飛。"]'),
('70237d74-d8e5-4acd-a62e-ba6c4b8caec3','晚秋石門禮拜','閻防','唐','唐诗','tang','','[]','輕策臨絕壁，招提謁金仙。',96,'全唐诗/poet.tang.13000.json','["輕策臨絕壁，招提謁金仙。", "舟車無由徑，巖嶠乃屬天。", "躑躅淹昃景，夷猶望新弦。", "石門變暝色，谷口生人煙。", "陽鴈叫平楚，秋風急寒川。", "馳暉苦代謝，浮脆慙貞堅。", "永欲臥丘壑，息心依梵筵。", "誓將歷劫願，無以外物牽。"]'),
('1f6ef42b-eb0a-49f8-971b-d59a58ec6239','百丈谿新理茅茨讀書','閻防','唐','唐诗','tang','','[]','浪迹棄人世，遠山自幽獨。',96,'全唐诗/poet.tang.13000.json','["浪迹棄人世，遠山自幽獨。", "始傍巢由蹤，吾其獲心曲。", "荒庭何所有，老樹半空腹。", "秋蜩鳴北林，暮鳥穿我屋。", "棲遲樂遵渚，恬曠寡所欲。", "開卦推盈虛，散帙攻節目。", "養閑度人事，達命知止足。", "不學東周儒，俟時勞伐輻。"]'),
('49e54a12-b52b-4f98-b5c9-3beb8d5a823a','宿岸道人精舍','閻防','唐','唐诗','tang','','[]','早歲參道風，放情入寥廓。',72,'全唐诗/poet.tang.13000.json','["早歲參道風，放情入寥廓。", "重因息心侶，遂果巖下諾。", "斂跡辭人間，杜門守寂寞。", "秋風翦蘭蕙，霜氣冷淙壑。", "山牖見然燈，竹房聞搗藥。", "願言捨塵事，所趣非龍蠖。"]'),
('e4b66eef-77d3-4406-9935-e3efe5e95928','夕次鹿門山作','閻防','唐','唐诗','tang','','[]','龐公嘉遯所，浪跡難追攀。',107,'全唐诗/poet.tang.13000.json','["龐公嘉遯所，浪跡難追攀。", "浮舟暝始至，抱杖聊自閑。", "雙巖開鹿門，百谷集珠灣。", "噴薄湍上水，舂容漂裏山。", "焦原不足險，梁壑未成艱。", "我行自春仲，夏鳥忽緜蠻。", "蕙草色已晚，客心殊倦還。", "遠遊非避地，訪道愛童顏。", "安能徇機巧爭奪錐刀間。"]'),
('edc46b2c-73ad-470b-9b7f-0b215c76afef','與永樂諸公夜泛黃河作','閻防','唐','唐诗','tang','','["\u9ec4\u6cb3"]','煙深載酒入，但覺暮川虛。',48,'全唐诗/poet.tang.13000.json','["煙深載酒入，但覺暮川虛。", "映水見山火，鳴榔聞夜漁。", "愛茲山水趣，忽與人世疎。", "無暇然官燭，中流有望舒。"]'),
('c2101c68-6a54-4d26-ad11-b4760a7a2770','句','閻防','唐','唐诗','tang','','[]','熊踞庭中樹，龍蒸棟裏雲。',12,'全唐诗/poet.tang.13000.json','["熊踞庭中樹，龍蒸棟裏雲。"]'),
('14d801a0-491e-45d0-9a0a-0decb86a252f','懷哉行','薛據','唐','唐诗','tang','','[]','明時無廢人，廣廈無棄材。',144,'全唐诗/poet.tang.13000.json','["明時無廢人，廣廈無棄材。", "良工不我顧，有用寧自媒。", "懷策望君門，歲晏空遲迴。", "秦城多車馬，日夕飛塵埃。", "伐鼓千門啓，鳴珂雙闕來。", "我聞雷雨施，天澤罔不該。", "何意斯人徒，棄之如死灰。", "主好臣必効，時禁權不開。", "俗流實驕矜，得志輕草萊。", "文王賴多士，漢帝資羣才。", "一言竝拜相，片善咸居台。", "夫君何不遇，爲泣黃金臺。"]'),
('8c5da0f9-17f9-4a5f-acc2-9ae3636abc57','古興','薛據','唐','唐诗','tang','','[]','日中望雙闕，軒蓋揚飛塵。',108,'全唐诗/poet.tang.13000.json','["日中望雙闕，軒蓋揚飛塵。", "鳴珮初罷朝，自言皆近臣。", "光華滿道路，意氣安可親。", "歸來宴高堂，廣筵羅八珍。", "僕妾盡綺紈，歌舞夜達晨。", "四時固相代，誰能久要津。", "已看覆前車，未見易後輪。", "丈夫須兼濟，豈能樂一身。", "君今皆得志，肯顧憔悴人。"]'),
('24423d72-188c-4ac9-bd1d-39b7aa38eb71','冬夜寓居寄儲太祝','薛據','唐','唐诗','tang','','[]','自爲洛陽客，夫子吾知音。',48,'全唐诗/poet.tang.13000.json','["自爲洛陽客，夫子吾知音。", "愛義能下士，時人無此心。", "奈何離居夜，巢鳥飛空林。", "愁坐至月上，復聞南鄰砧。"]'),
('4be0b34a-9190-4a0d-bc3e-271aa7cc2bcf','登秦望山','薛據','唐','唐诗','tang','','[]','南登秦望山，目極大海空。',96,'全唐诗/poet.tang.13000.json','["南登秦望山，目極大海空。", "朝陽半蕩漾，晃朗天水紅。", "谿壑爭噴薄，江湖遰交通。", "而多漁商客，不悟歲月窮。", "振緡迎早潮，弭櫂候長風。", "予本萍泛者，乘流任西東。", "茫茫天際帆，棲泊何時同。", "將尋會稽迹，從此訪任公。"]'),
('02880a43-5d89-4b2b-b2a9-f99228969262','西陵口觀海','薛據','唐','唐诗','tang','','["\u957f\u6c5f"]','長江漫湯湯，近海勢彌廣。',120,'全唐诗/poet.tang.13000.json','["長江漫湯湯，近海勢彌廣。", "在昔胚渾凝，融爲百川泱。", "地形失端倪，天色灒滉漾。", "東南際萬里，極目遠無象。", "山影乍浮沈，潮波忽來往。", "孤帆或不見，櫂歌猶想像。", "日暮長風起，客心空振蕩。", "浦口霞未收，潭心月初上。", "林嶼幾邅迴，亭臯時偃仰。", "歲晏訪蓬瀛，真游非外獎。"]'),
('ea82076e-44f8-4d9c-8844-a2325b642224','題鶴林寺','薛據','唐','唐诗','tang','','[]','道門隱形勝，向背臨法橋。',72,'全唐诗/poet.tang.13000.json','["道門隱形勝，向背臨法橋。", "松覆山殿冷，花藏溪路遙。", "珊珊寶幡挂，燄燄明燈燒。", "遲日半空谷，春風連上潮。", "少憑水木興，暫忝身心調。", "願謝攜手客，茲山禪侶饒。"]'),
('40bd73fb-a66f-4a4b-972c-f6cd96d4feeb','初去郡齋書懷','薛據','唐','唐诗','tang','','[]','肅徒辭汝頴，懷古獨悽然。',120,'全唐诗/poet.tang.13000.json','["肅徒辭汝頴，懷古獨悽然。", "尚想文王化，猶思巢父賢。", "時移多讒巧，大道竟誰傳。", "況是疾風起，悠悠旌斾懸。", "征鳥無返翼，歸流不停川。", "已經霜雪下，乃驗松柏堅。", "回首望城邑，迢迢間雲煙。", "志士不傷物，小人皆自妍。", "感時惟責己，在道非怨天。", "從此適樂土，東歸知幾年。"]'),
('a719764c-f6df-489f-ace4-b2ccb907bfb4','出青門往南山下別業','薛據','唐','唐诗','tang','','[]','舊居在南山，夙駕自城闕。',96,'全唐诗/poet.tang.13000.json','["舊居在南山，夙駕自城闕。", "榛莽相蔽虧，去爾漸超忽。", "散漫餘雪晴，蒼茫季冬月。", "寒風吹長林，白日原上沒。", "懷抱曠莫伸，相知阻胡越。", "弱年好棲隱，鍊藥在巖窟。", "及此離垢氛，興來亦因物。", "末路期赤松，斯言庶不伐。"]'),
('b6f3dd79-df81-4677-9b73-f5b31c53f1d9','泊震澤口','薛據','唐','唐诗','tang','','[]','日落草木陰，舟徒泊江汜。',120,'全唐诗/poet.tang.13000.json','["日落草木陰，舟徒泊江汜。", "蒼茫萬象開，合沓聞風水。", "洄沿值漁翁，䆗窱逢樵子。", "雲開天宇靜，月明照萬里。", "早鴈湖上飛，晨鐘海邊起。", "獨坐嗟遠游，登岸望孤洲。", "零落星欲盡，朣朧氣漸收。", "行藏空自秉，智識仍未周。", "伍胥既仗劒，范蠡亦乘流。", "歌竟鼓楫去，三江多客愁。"]'),
('b76ba067-1fbd-4d7f-9326-5891bdd71be2','題丹陽陶司馬廳壁','薛據','唐','唐诗','tang','','[]','高鑒清洞徹，儒風入進難。',48,'全唐诗/poet.tang.13000.json','["高鑒清洞徹，儒風入進難。", "詔書增寵命，才子益能官。", "門帶山光晚，城臨江水寒。", "唯餘好文客，時得咏幽蘭。"]'),
('08cb9e31-1ff3-46dc-926a-4f6aafe01f5a','古興','薛據','唐','唐诗','tang','','[]','投珠恐見疑，抱玉但垂泣。',24,'全唐诗/poet.tang.13000.json','["投珠恐見疑，抱玉但垂泣。", "道在君不舉，功成嘆何及。"]'),
('8d306936-bcaa-4720-b6f0-a0408d989362','早發上東門','薛據','唐','唐诗','tang','','[]','十五能文西入秦，三十無家作路人。',32,'全唐诗/poet.tang.13000.json','["十五能文西入秦，三十無家作路人。", "時命不將明主合，布衣空惹洛陽塵。"]'),
('4752947e-cd1c-4654-809c-e701e413d200','句','薛據','唐','唐诗','tang','','[]','省署開文苑，滄浪學釣翁。',24,'全唐诗/poet.tang.13000.json','["省署開文苑，滄浪學釣翁。", "窮冬時短晷，日盡西南天。"]'),
('8dd2084e-e3ef-4c63-b240-c38981eb41f1','秋夕會友','姚係','唐','唐诗','tang','','[]','倦客易相失，懽遊無良辰。',60,'全唐诗/poet.tang.13000.json','["倦客易相失，懽遊無良辰。", "忽然一夕間，稍慰闔家貧。", "白露下庭梧，孤琴始悲辛。", "迴風入幽草，蟲響滿四鄰。", "會遇更何時，持桮重殷勤。"]'),
('81c918c2-50ca-4b10-b766-0663c6fa1227','荆山獨往','姚係','唐','唐诗','tang','','[]','宿昔山水上，抱琴獨躑躅。',84,'全唐诗/poet.tang.13000.json','["宿昔山水上，抱琴獨躑躅。", "山遠去難窮，琴悲多斷續。", "巖重丹陽樹，泉咽聞陰谷。", "時下白雲中，淹留秋水曲。", "秋水石欄深，潺湲如噴玉。", "雜芳被陰岸，墜露方消綠。", "恣此平生懷，獨游還自足。"]'),
('cb8e3c11-4405-450d-ab33-af54d1dc2df0','五老峰大明觀贈隱者','姚係','唐','唐诗','tang','','[]','雲觀此山北，與君攜手稀。',72,'全唐诗/poet.tang.13000.json','["雲觀此山北，與君攜手稀。", "林端涉橫水，洞口入斜暉。", "頗覺鸞鶴邇，忽爲煙霧飛。", "故人清和客，默會琴心微。", "丹術幸可授，青龍當未歸。", "悠悠平生意，此日復相違。"]'),
('48f1f014-da88-4c84-9b73-79b9ff2e1162','送周愿判官歸嶺南','姚係','唐','唐诗','tang','','[]','早蟬望秋鳴，夜琴怨離聲。',96,'全唐诗/poet.tang.13000.json','["早蟬望秋鳴，夜琴怨離聲。", "眇然多異感，值子江山行。", "由來重義人，感激事縱橫。", "往復念遐阻，淹留慕平生。", "晨奔九衢餞，暮始萬里程。", "山驛風月榭，海門煙霞城。", "易綃泉源近，拾翠沙漵明。", "蘭蕙一爲贈，貧交空復情。"]'),
('f6963394-b39a-4899-8607-fcac7af9e2b3','送陸渾主簿趙宗儒之任','姚係','唐','唐诗','tang','','[]','山中眇然意，此意乃平生。',96,'全唐诗/poet.tang.13000.json','["山中眇然意，此意乃平生。", "常日望鳴臯，遙對洛陽城。", "故人吏爲隱，懷此若蓬瀛。", "夕氣冒巖上，晨流瀉岸明。", "存亡區中事，影響羽人情。", "溪寂值猨下，雲歸聞鶴聲。", "及茲春始暮，花葛正明榮。", "會有攜手日，悠悠去無程。"]'),
('15df8151-88f7-46a1-bfef-790acfcdb1e1','楊參軍莊送宇文邈','姚係','唐','唐诗','tang','','[]','秋雲冒原隰，野鳥滿林聲。',72,'全唐诗/poet.tang.13000.json','["秋雲冒原隰，野鳥滿林聲。", "愛此田舍事，稽君車馬程。", "離堂慘不喧，脈脈復盈盈。", "蘭葉一經霜，香銷爲贈輕。", "燈光耿方寂，蟲思隱餘清。", "相望忽無際，如含江海情。"]'),
('c3caf4a4-4512-4a42-b34f-1e8c3f2e8950','京西遇舊識兼送往隴西','姚係','唐','唐诗','tang','','[]','蟬鳴一何急，日暮秋風樹。',36,'全唐诗/poet.tang.13000.json','["蟬鳴一何急，日暮秋風樹。", "即此不勝愁，隴陰人更去。", "相逢與相失，共是亡羊路。"]'),
('ad2d6b86-8381-47ab-b445-cc46c28b0be4','古別離','姚係','唐','唐诗','tang','','[]','涼風已嫋嫋，露重木蘭枝。',48,'全唐诗/poet.tang.13000.json','["涼風已嫋嫋，露重木蘭枝。", "獨上高樓望，行人遠不知。", "輕寒入洞戶，明月滿秋池。", "燕去鴻方至，年年是別離。"]'),
('e86a927e-fe41-4bd4-9e00-2a5e5b1aab06','野居池上看月','姚係','唐','唐诗','tang','','[]','悠然雲間月，復此照池塘。',48,'全唐诗/poet.tang.13000.json','["悠然雲間月，復此照池塘。", "泫露蒼茫濕，沈波澹灩光。", "應門當未曙，歌吹滿昭陽。", "遠近徒傷目，清輝靄自長。"]'),
('138a236c-ce00-433b-8931-5460b685d243','庭柳','姚係','唐','唐诗','tang','','[]','褭褭柳楊枝，當軒雜珮垂。',48,'全唐诗/poet.tang.13000.json','["褭褭柳楊枝，當軒雜珮垂。", "交陰總共密，分條各自宜。", "因依似永久，攬結更傷離。", "愛此陽春色，秋風莫遽吹。"]'),
('5b4b1689-e229-4002-a9d4-c99999b9d628','硤州旅舍奉懷蘇州韋郎中','令狐峘','唐','唐诗','tang','','[]','儒服學從政，遂爲塵事嬰。',96,'全唐诗/poet.tang.13000.json','["儒服學從政，遂爲塵事嬰。", "銜命東復西，孰堪異鄉情。", "懷祿且懷恩，策名敢逃名。", "羨彼農畝人，白首親友幷。", "江山入秋氣，草木彫晚榮。", "方塘寒露凝，旅管涼飆生。", "懿交守東吳，夢想聞頌聲。", "雲水方浩浩，離憂何平時。"]'),
('35c04ebe-2894-441a-ab7a-65c4ad2cded6','釋奠日國學觀禮聞雅頌','令狐峘','唐','唐诗','tang','','[]','肅肅先師廟，依依胄子羣。',72,'全唐诗/poet.tang.13000.json','["肅肅先師廟，依依胄子羣。", "滿庭陳舊禮，開戶拜清芬。", "萬舞當華燭，簫韶入翠雲。", "頌歌清曉聽，雅吹度風聞。", "澹泊調元氣，中和美聖君。", "唯餘東魯客，蹈舞向南熏。"]'),
('e491bb5b-4dc4-48a1-8e27-6ad20691adbc','釋奠日國學觀禮聞雅頌','滕珦','唐','唐诗','tang','','[]','太學時觀禮，東方曉色分。',72,'全唐诗/poet.tang.13000.json','["太學時觀禮，東方曉色分。", "威儀何棣棣，環珮又紛紛。", "古樂從空盡，清歌幾處聞。", "六和成遠吹，九奏動行雲。", "聖上尊儒學，春秋奠茂勳。", "幸因陪齒列，聊以頌斯文。"]'),
('ab8bc9ef-caab-4fc0-a99a-cf3e2ca892ea','奉和聖製麟德殿燕百僚應制','常衮','唐','唐诗','tang','','[]','雲闢御筵張，山呼聖壽長。',72,'全唐诗/poet.tang.13000.json','["雲闢御筵張，山呼聖壽長。", "玉闌豐瑞草，金陛立神羊。", "台鼎資庖膳，天星奉酒漿。", "蠻夷陪作位，犀象舞成行。", "網已袪三面，歌因守四方。", "千秋不可極，花發滿宮香。"]'),
('c193ecd8-d9f3-47aa-9445-5a3942ce54d2','晚秋集賢院即事寄徐薛二侍郎','常衮','唐','唐诗','tang','','[]','穆穆上清居，沈沈中祕書。',144,'全唐诗/poet.tang.13000.json','["穆穆上清居，沈沈中祕書。", "金鋪深內殿，石甃淨寒渠。", "花樹臺斜倚，空煙閣半虛。", "縹囊披錦繡，翠軸卷瓊琚。", "墨潤冰文繭，香銷蠹字魚。", "翻黃桐葉老，吐白桂花初。", "舊德雙遊處，聊芳十載餘。", "北朝榮庾薛，西漢盛嚴徐。", "侍講親華扆，徴吟步綺疏。", "綴簾金翡翠，賜硯玉蟾蜍。", "序秩東南遠，離憂歲月除。", "承明期重入，江海意何如。"]'),
('295e5733-ef27-469e-afc1-2a487f3f9b4a','早秋望華清宮樹因以成詠','常衮','唐','唐诗','tang','','[]','可憐雲木叢，滿禁碧濛濛。',120,'全唐诗/poet.tang.13000.json','["可憐雲木叢，滿禁碧濛濛。", "色潤靈泉近，險清輦路通。", "玉壇標八桂，金井識雙桐。", "交映凝寒露，相和起夜風。", "數枝盤石上，幾葉落雲中。", "燕拂宜秋霽，蟬鳴覺晝空。", "翠屏更隱見，珠綴共玲瓏。", "雷雨生成早，樵蘇禁令雄。", "野藤高助綠，仙果迥呈紅。", "惆悵繚垣暮，茲山聞暗蟲。"]'),
('fc029604-680e-4a44-9318-c28b4b3e689b','和考功員外杪秋憶終南舊宅之作','常衮','唐','唐诗','tang','','[]','靜憶溪邊宅，知君許謝公。',96,'全唐诗/poet.tang.13000.json','["靜憶溪邊宅，知君許謝公。", "曉霜凝耒耜，初日照梧桐。", "澗鼠喧藤蔓，山禽竄石叢。", "白雲當嶺雨，黃葉繞階風。", "野菓垂橋上，高泉落水中。", "歡榮來自間，羸賤賞曾通。", "月滿珠藏海，天晴鶴在籠。", "餘陰如可寄，願得隱牆東。"]'),
('1ced84be-43c1-42b1-8740-f884b354c351','題金吾郭將軍石洑茅堂','常衮','唐','唐诗','tang','','[]','雲戟曙沈沈，軒墀清且深。',96,'全唐诗/poet.tang.13000.json','["雲戟曙沈沈，軒墀清且深。", "家傳成棟美，堯寵結茅心。", "玉佩多依石，油幢亦在林。", "爐香諸洞暖，殿影衆山陰。", "草奏風生筆，筵開雪滿琴。", "客從龍闕至，僧自虎溪尋。", "瀟灑延清賞，周流會素襟。", "終朝惜塵步，一醉見華簪。"]'),
('565a2c0f-1c88-4611-b7b8-d5218070b564','登棲霞寺','常衮','唐','唐诗','tang','','[]','林香雨氣新，山寺綠無塵。',72,'全唐诗/poet.tang.13000.json','["林香雨氣新，山寺綠無塵。", "遂結雲外侶，共遊天上春。", "鶴鳴金閣麗，僧語竹房鄰。", "待月水流急，惜花風起頻。", "何方非壞境，此地有歸人。", "迴首空門外，皤然一幻身。"]'),
('1e3efaa1-c7ef-4dae-b156-1e7cc5fda201','逢南中使寄嶺外故人','常衮','唐','唐诗','tang','','[]','見說南來處，蒼梧指桂林。',72,'全唐诗/poet.tang.13000.json','["見說南來處，蒼梧指桂林。", "過秋天更煖，邊海日長陰。", "巴路緣雲出，蠻鄉入洞深。", "信回人自老，夢到月應沈。", "碧水通春色，青山寄遠心。", "炎方難久客，爲爾一霑襟。"]'),
('10888010-cf60-49f7-b7e8-eac8bc94c29e','代員將軍罷戰後歸故里','常衮','唐','唐诗','tang','','[]','結髮事疆場，全生到海鄉。',96,'全唐诗/poet.tang.13000.json','["結髮事疆場，全生到海鄉。", "連雲防鐵嶺，同日破漁陽。", "牧馬胡天晚，移軍磧路長。", "枕戈眠古戍，吹角立繁霜。", "歸老勳仍在，酬恩虜未忘。", "獨行過邑里，多病對農桑。", "雄劒依塵橐，兵符寄藥囊。", "空餘麾下將，猶逐羽林郎。"]'),
('16416b61-ecc2-4ae7-8cb2-7dd2bb5521d2','詠冬瑰花','常衮','唐','唐诗','tang','','[]','獨鶴寄煙霜，雙鸞思晚芳。',96,'全唐诗/poet.tang.13000.json','["獨鶴寄煙霜，雙鸞思晚芳。", "舊陰依謝宅，新豔出蕭牆。", "蝶散搖輕露，鶯銜入夕陽。", "雨朝勝濯錦，風夜劇焚香。", "麗日千層豔，孤霞一片光。", "密來驚葉少，動處覺枝長。", "布影期高賞，留春爲遠方。", "嘗聞贈瓊玖，叨和愧升堂。"]'),
('6196a33c-c420-4b81-9d97-e93c46f3c8dd','句','常衮','唐','唐诗','tang','','[]','風候已應同嶺北，雲山仍喜似終南。',16,'全唐诗/poet.tang.13000.json','["風候已應同嶺北，雲山仍喜似終南。"]'),
('37d05ab2-8a42-4338-a7a7-a1cd4b6d1d17','登聖善寺閣','褚朝陽','唐','唐诗','tang','','["\u9ec4\u6cb3"]','飛閣青霞裏，先秋獨早涼。',48,'全唐诗/poet.tang.13000.json','["飛閣青霞裏，先秋獨早涼。", "天花映窗近，月桂拂簷香。", "華岳三峰小，黃河一帶長。", "空間指歸路，煙際有垂楊。"]'),
('b6a695c3-28a6-4dde-89f9-c8c15b5c3887','五絲','褚朝陽','唐','唐诗','tang','','[]','越人傳楚俗，截竹競縈絲。',72,'全唐诗/poet.tang.13000.json','["越人傳楚俗，截竹競縈絲。", "水底深休也，日中遠賀之。", "章施文勝質，列匹美於姬。", "錦繡侔新段，羔羊寢舊詩。", "但誇端午節，誰薦屈原祠。", "把酒時伸奠，汨羅空遠而。"]'),
('22638786-aea2-48d0-82ea-08a4fd47a948','奉上徐中書','褚朝陽','唐','唐诗','tang','','[]','中禁仙池越鳳凰，池邊詞客紫薇郎。',32,'全唐诗/poet.tang.13000.json','["中禁仙池越鳳凰，池邊詞客紫薇郎。", "既能作頌雄風起，何不時吹蘭蕙香。"]'),
('4fa428c7-2354-4bfb-817e-8e8b3be85849','小洞庭洄源亭讌四郡太守詩','蘇源明','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','小洞庭兮牽方舟，風嫋嫋兮離平流。',112,'全唐诗/poet.tang.13000.json','["小洞庭兮牽方舟，風嫋嫋兮離平流。", "牽方舟兮小洞庭，雲微微兮連絕𡷨。", "層瀾壯兮緬以沒，重巖轉兮超以忽。", "馮夷逝兮護輕橈，蛟龍行兮落增潮。", "泊中湖兮澹而閑，並曲漵兮悵而還。", "適予手兮非予期，將解袂兮藂予思。", "尚君子兮壽厥身，承明主兮憂斯人。"]'),
('62cb7105-4cf3-4656-b441-fabe9a7f6c6f','秋夜小洞庭離讌詩','蘇源明','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','浮漲湖兮莽迢遙，川后禮兮扈予橈。',64,'全唐诗/poet.tang.13000.json','["浮漲湖兮莽迢遙，川后禮兮扈予橈。", "橫增沃兮蓬仙延，川后福兮易予舷。", "月澄凝兮明空波，星磊落兮耿秋河。", "夜既良兮酒且多，樂方作兮奈別何。"]'),
('a6edde6e-23c4-4049-85a5-9e13be8cb2dd','閨情','鄭虔','唐','唐诗','tang','','[]','銀鑰開香閣，金臺照夜燈。',24,'全唐诗/poet.tang.13000.json','["銀鑰開香閣，金臺照夜燈。", "長征君自慣，獨臥妾何曾。"]'),
('6cc6c85c-d5a0-41f5-8ac8-ece3aaced577','古意','畢耀','唐','唐诗','tang','','[]','璇閨繡戶斜光入，千金女兒倚門立。',64,'全唐诗/poet.tang.13000.json','["璇閨繡戶斜光入，千金女兒倚門立。", "橫波美目雖往來，羅袂遙遙不相及。", "聞道今年初避人，珊珊挂鏡長隨身。", "願得侍兒爲道意，後堂羅帳一相親。"]'),
('e5949236-b878-4ef5-aa53-445651fb04ac','情人玉清歌','畢耀','唐','唐诗','tang','','[]','洛陽有人名玉清，可憐玉清如其名。',90,'全唐诗/poet.tang.13000.json','["洛陽有人名玉清，可憐玉清如其名。", "善踏斜柯能獨立，嬋娟花豔無人及。", "珠爲帬，玉爲纓，臨春風，吹玉笙。", "悠悠滿天星，黃金閣上晚妝成。", "雲和曲中爲曼聲，玉梯不得蹈。", "搖袂兩盈盈，城頭之日復何情。"]'),
('1fc7a06a-394c-4d6f-8f18-c4b0c760351e','贈獨孤常州','畢耀','唐','唐诗','tang','','[]','洪爐無久停，日月速若飛。',24,'全唐诗/poet.tang.13000.json','["洪爐無久停，日月速若飛。", "忽然衝人身，飲酒不須疑。"]'),
('56b938a5-895c-4b05-bef8-c11f37a9b52f','奉和聖製次瓊嶽應制','韋濟','唐','唐诗','tang','','[]','陸海披晴雪，千旗獵早陽。',48,'全唐诗/poet.tang.13000.json','["陸海披晴雪，千旗獵早陽。", "岳臨秦路險，河遶漢垣長。", "行漏通鳷鵲，離宮接建章。", "都門信宿近，歌舞從周王。"]'),
('a1a02ee4-3f26-49f3-84b4-3a0b8b8b0e9c','成都爲客作','田澄','唐','唐诗','tang','','[]','蜀郡將之遠，城南萬里橋。',48,'全唐诗/poet.tang.13000.json','["蜀郡將之遠，城南萬里橋。", "衣緣鄉淚濕，貌以客愁銷。", "地富魚爲米，山芳桂是樵。", "旅遊唯得酒，今日過明朝。"]'),
('3885e598-42c4-4a9c-904f-9b28617d0aae','奉和苑舍人宿直曉翫新池寄南省友','沈東美','唐','唐诗','tang','','[]','傳聞閶闔裏，寓直有神仙。',144,'全唐诗/poet.tang.13000.json','["傳聞閶闔裏，寓直有神仙。", "史爲三墳博，郎因五字遷。", "晨臨翔鳳沼，春注躍龍泉。", "去似登天上，來如看鏡前。", "影搖宸翰發，波淨列星懸。", "既濟仍懷友，流謙欲進賢。", "彈冠聲實貴，覆被渥恩偏。", "溫室言雖阻，文場契獨全。", "玉珂光赫奕，朱紱氣蟬聯。", "興逸潘仁賦，名高謝朓篇。", "青雲仰不逮，白雲和難牽。", "苒苒胡爲此，甘心老歲年。"]'),
('1d0b63a5-3a74-48aa-873d-bd2206c7ae06','變律 一','蘇渙','唐','唐诗','tang','','[]','日月東西行，寒暑冬夏易。',72,'全唐诗/poet.tang.13000.json','["日月東西行，寒暑冬夏易。", "陰陽無停機，造化渺莫測。", "開目爲晨光，閉目爲夜色。", "一開復一閉，明晦無休息。", "居然六合外，曠哉天地德。", "天地且不言，世人浪喧喧。"]'),
('a4714c39-186d-4e5f-bd1c-fdb3fbff199d','變律 二','蘇渙','唐','唐诗','tang','','[]','毒蜂成一窠，高挂惡木枝。',84,'全唐诗/poet.tang.13000.json','["毒蜂成一窠，高挂惡木枝。", "行人百步外，目斷魂亦飛。", "長安大道邊，挾彈誰家兒。", "右手持金丸，引滿無所疑。", "一中紛下來，勢若風雨隨。", "身如萬箭攢，宛轉迷所之。", "徒有疾惡心，奈何不知幾。"]'),
('a4e4d5ec-1d8e-4a97-b69e-633f7ae6c0c2','變律 三','蘇渙','唐','唐诗','tang','','[]','養蠶爲素絲，葉盡蠶不老。',72,'全唐诗/poet.tang.13000.json','["養蠶爲素絲，葉盡蠶不老。", "傾筐對空林，此意向誰道。", "一女不得織，萬夫受其寒。", "一夫不得意，四海行路難。", "禍亦不在大，福亦不在先。", "世路險孟門，吾徒當勉旃。"]'),
('7ac1c147-2d6d-4d12-923e-2121413de02a','贈零陵僧','蘇渙','唐','唐诗','tang','','[]','張顛沒在二十年，謂言草聖無人傳。',210,'全唐诗/poet.tang.13000.json','["張顛沒在二十年，謂言草聖無人傳。", "零陵沙門繼其後，新書大字大如斗。", "興來走筆如旋風，醉後耳熱心更兇。", "忽如裴旻舞雙劒，七星錯落纏蛟龍。", "又如吳生畫[鬼神]，魑魅魍魎驚本身。", "鉤鎖相連勢不絕，倔強毒蛇爭屈鐵。", "西河舞劒氣凌雲，孤蓬自振唯有君。", "今日華堂看灑落，四座喧呼歎佳作。", "迴首邀余賦一章，欲令羨價齊鍾張。", "琅誦囗句三百字，何似醉僧顛復狂。", "忽然告我遊南溟，言祈亞相求大名。", "亞相書翰凌獻之，見君絕意必深知。", "南中紙價當日貴，只恐貪泉成墨池。"]'),
('a1634ee2-0c10-47cb-a985-0e36bf3e99a9','江南曲','劉眘虛','唐','唐诗','tang','','[]','美人何蕩漾，湖上風日長。',48,'全唐诗/poet.tang.13000.json','["美人何蕩漾，湖上風日長。", "玉手欲有贈，裴回雙明璫。", "歌聲隨綠水，怨色起青陽。", "日暮還家望，雲波橫洞房。"]'),
('9f097448-4dc7-43ed-aafc-3e256dba23fa','九日送人','劉眘虛','唐','唐诗','tang','','[]','海上正搖落，客中還別離。',48,'全唐诗/poet.tang.13000.json','["海上正搖落，客中還別離。", "同舟去未已，遠送新相知。", "流水意何極，滿尊徒爾爲。", "從來菊花節，早已醉東籬。"]'),
('9532d5be-e0a2-4623-aaf5-322a8b90d1ea','暮秋揚子江寄孟浩然','劉眘虛','唐','唐诗','tang','','["\u601d\u5ff5", "\u53cb\u60c5"]','木葉紛紛下，東南日煙霜。',72,'全唐诗/poet.tang.13000.json','["木葉紛紛下，東南日煙霜。", "林山相晚暮，天海空青蒼。", "暝色況復久，秋聲亦何長。", "孤舟兼微月，獨夜仍越鄉。", "寒笛對京口，故人在襄陽。", "詠思勞今夕，江漢遙相望。"]'),
('4dbfdde1-a5ba-440f-8acc-3d0872c72351','潯陽陶氏別業','劉眘虛','唐','唐诗','tang','','["\u957f\u6c5f"]','陶家習先隱，種柳長江邊。',72,'全唐诗/poet.tang.13000.json','["陶家習先隱，種柳長江邊。", "朝夕潯陽郭，白衣來幾年。", "霽雲明孤嶺，秋水澄寒天。", "物象自清曠，野情何綿聯。", "蕭蕭丘中賞，明宰非徒然。", "願守黍稷稅，歸耕東山田。"]'),
('0732a1c2-259d-451e-b11e-11344d0ed7ce','登廬山峰頂寺','劉眘虛','唐','唐诗','tang','','["\u5e90\u5c71"]','孤峰臨萬象，秋氣何高清。',72,'全唐诗/poet.tang.13000.json','["孤峰臨萬象，秋氣何高清。", "天際南郡出，林端西江明。", "山門二緇叟，振錫聞幽聲。", "心照有無界，業懸前後生。", "雖知真機靜，尚與愛網幷。", "方首金門路，未遑參道情。"]'),
('1ef01a21-89c8-4940-a633-6302a2ebeb0d','尋東溪還湖中作','劉眘虛','唐','唐诗','tang','','[]','出山更回首，日暮清溪深。',72,'全唐诗/poet.tang.13000.json','["出山更回首，日暮清溪深。", "東嶺新別處，數猨叫空林。", "昔遊有初迹，此路還獨尋。", "幽興方在往，歸懷復爲今。", "雲峰勞前意，湖水成遠心。", "望望已超越，坐鳴舟中琴。"]'),
('baa03d77-459d-4b12-855b-6f34c10bfebd','送韓平兼寄郭微','劉眘虛','唐','唐诗','tang','','[]','上客夜相過，小童能酤酒。',84,'全唐诗/poet.tang.13000.json','["上客夜相過，小童能酤酒。", "即爲臨水處，正值歸鴈後。", "前路望鄉山，近家見門柳。", "到時春未暮，風景自應有。", "余憶東州人，經年別來久。", "殷勤爲傳語，日夕念攜手。", "兼問前寄書，書中復達否。"]'),
('c53ff05c-b03f-4424-8d41-199d24f25750','寄閻防','劉眘虛','唐','唐诗','tang','','[]','青冥南山口，君與緇錫鄰。',96,'全唐诗/poet.tang.13000.json','["青冥南山口，君與緇錫鄰。", "深路入古寺，亂花隨暮春。", "紛紛對寂莫，往往落衣巾。", "松色空照水，經聲時有人。", "晚心復南望，山遠情獨親。", "應以修往業，亦惟立此身。", "深林度空夜，煙月資清真。", "莫歎文明日，彌年徒隱淪。"]'),
('8e6ba3fd-d983-4950-9fec-8e55331d0c09','海上詩送薛文學歸海東','劉眘虛','唐','唐诗','tang','','[]','何處歸且遠，送君東悠悠。',108,'全唐诗/poet.tang.13000.json','["何處歸且遠，送君東悠悠。", "滄溟千萬里，日夜一孤舟。", "曠望絕國所，微茫天際愁。", "有時近仙境，不定若夢遊。", "或見青色古，孤山百里秋。", "前心方杳眇，後路勞夷猶。", "離別惜吾道，風波敬皇休。", "春浮花氣遠，思逐海水流。", "日暮驪歌後，永懷空滄洲。"]'),
('7aa1c110-2d0d-4d83-90fc-e0d012fdfd55','越中問海客','劉眘虛','唐','唐诗','tang','','[]','風雨滄洲暮，一帆今始歸。',96,'全唐诗/poet.tang.13000.json','["風雨滄洲暮，一帆今始歸。", "自云發南海，萬里速如飛。", "初謂落何處，永將無所依。", "冥茫漸西見，山色越中微。", "誰念去時遠，人經此路稀。", "泊舟悲且泣，使我亦霑衣。", "浮海焉用說，憶鄉難久違。", "縱爲魯連子，山路有柴扉。"]'),
('a2b4fe60-9809-422d-afa7-143a2088f045','闕題','劉眘虛','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6625\u5929", "\u5199\u666f", "\u4e94\u8a00\u5f8b\u8bd7"]','道由白雲盡，春與青溪長。',48,'全唐诗/poet.tang.13000.json','["道由白雲盡，春與青溪長。", "時有落花至，遠隨流水香。", "閑門向山路，深柳讀書堂。", "幽映每白日，清輝照衣裳。"]'),
('13148989-dfbe-43bf-80dd-55329343c8a2','寄江滔求孟六遺文','劉眘虛','唐','唐诗','tang','','[]','南望襄陽路，思君情轉親。',48,'全唐诗/poet.tang.13000.json','["南望襄陽路，思君情轉親。", "偏知漢水廣，應與孟家鄰。", "在日貪爲善，昨來聞更貧。", "相如有遺草，一爲問家人。"]'),
('2c38ec65-f658-4fad-b296-bb4afd7fa182','積雪爲小山','劉眘虛','唐','唐诗','tang','','[]','飛雪伴春還，春庭曉自閑。',72,'全唐诗/poet.tang.13000.json','["飛雪伴春還，春庭曉自閑。", "虛心應任道，遇賞遂成山。", "峰小形全秀，巖虛勢莫攀。", "以幽能皎潔，謂近可循環。", "孤影臨冰境，寒光對玉顏。", "不隨遲日盡，留顧歲華間。"]'),
('2139e79b-f5fc-4ba9-a768-88dbf03c4578','贈喬琳','劉眘虛','唐','唐诗','tang','','[]','去年上策不見收，今年寄食仍淹留。',80,'全唐诗/poet.tang.13000.json','["去年上策不見收，今年寄食仍淹留。", "羨君有酒能共醉，羨君無錢能不憂。", "如今五侯不待客，羨君不問五侯宅。", "如今七貴方自尊，羨君不過七貴門。", "丈夫會應有知己，世上悠悠何足論。"]'),
('67edf4da-dbe3-4d69-a659-71fbc9c6ea28','茙葵花歌','劉眘虛','唐','唐诗','tang','','["\u5199\u82b1", "\u751f\u6d3b", "\u6292\u6000", "\u82b1"]','昨日一花開，今日一花開。',55,'全唐诗/poet.tang.13000.json','["昨日一花開，今日一花開。", "今日花正好，昨日花已老。", "人生不得長少年，莫惜牀頭酤酒錢。", "請君有錢向酒家，君不見茙葵花。"]'),
('09dd83df-159b-4439-aa5a-fbdd9b27a1a2','句','劉眘虛','唐','唐诗','tang','','[]','歸夢如春水，悠悠遶故鄉。',24,'全唐诗/poet.tang.13000.json','["歸夢如春水，悠悠遶故鄉。", "駐馬渡江處，望鄉待歸舟。"]'),
('8ccee9a6-bff2-4e78-8968-7ab6ead7c79b','冬夜宴蕭十丈因餞殷郭二子西上','息夫牧','唐','唐诗','tang','','[]','有琴斯鳴，于宰之庭。',120,'全唐诗/poet.tang.13000.json','["有琴斯鳴，于宰之庭。", "君子莅止，其心孔平。", "政既告成，德以永貞。", "鳴琴有衎，于潁之畔。", "彼之才髦，其年未冠。", "聞詩聞禮，斐兮璨璨。", "鳴琴其怡，于潁之湄。", "二子翰飛，言戾京師。", "有鬱者桂，爰攀其枝。", "琴既鳴矣，宵既清矣。", "烘煁有煒，酒醴惟旨。", "喟我寤歎，吁其別矣。"]'),
('1bb870b9-66be-4669-bdfe-84c0c75aec34','蟬鳴一篇五章 一','宋華','唐','唐诗','tang','','[]','蟬其鳴矣，於彼疎桐。',50,'全唐诗/poet.tang.13000.json','["蟬其鳴矣，於彼疎桐。", "庇影容跡，何所不容。", "嘒嘒其長，永託于風。", "未見君子，我心仲仲。", "既見君子，樂且有融。"]'),
('997dbf46-01a7-4a5a-81ac-9549592c95c5','蟬鳴一篇五章 二','宋華','唐','唐诗','tang','','[]','彼蟬鳴矣，於林之表。',50,'全唐诗/poet.tang.13000.json','["彼蟬鳴矣，於林之表。", "含風飲露，以樂吾道。", "有懷載遷，伊誰云保。", "未見君子，我心悄悄。", "既見君子，披豁予抱。"]'),
('246b34c8-2ae8-4ee3-a646-e39b0b31d3bc','蟬鳴一篇五章 三','宋華','唐','唐诗','tang','','[]','蟬鳴蟬鳴，幽暢乎而。',50,'全唐诗/poet.tang.13000.json','["蟬鳴蟬鳴，幽暢乎而。", "肅肅爾庭，遠近涼颸。", "言赴高柳，叢篁間之。", "思而不見，如渴如饑。", "亦既覯止，我心則夷。"]'),
('a595de9b-2b7e-4ced-91d3-22438a17b776','蟬鳴一篇五章 四','宋華','唐','唐诗','tang','','[]','蟬鳴伊何，時運未與。',50,'全唐诗/poet.tang.13000.json','["蟬鳴伊何，時運未與。", "匪歎秋徂，怨斯路阻。", "願言莫從，鬱悒誰語。", "君子至止，慰我延佇。", "何斯違斯，倏爾遐舉。"]'),
('524d7587-b9db-401a-8f54-ff39bb60eb26','蟬鳴一篇五章 五','宋華','唐','唐诗','tang','','[]','歲之秋深，蟬其夕吟。',50,'全唐诗/poet.tang.13000.json','["歲之秋深，蟬其夕吟。", "披衣軒除，蕭蕭風林。", "我友來斯，言告離衿。", "何以敘懷，臨水鳴琴。", "何以贈言，委順浮沈。"]'),
('40445dd4-db09-43f4-aa1d-9dc31bf14f12','寄蕭頴士補正字','鄒象先','唐','唐诗','tang','','[]','六月度開雲，三峯翫山翠。',24,'全唐诗/poet.tang.13000.json','["六月度開雲，三峯翫山翠。", "爾時黃綬屈，別後青雲致。"]'),
('f7ed119c-c269-4657-b508-ba5a76adff7f','河中晚霽','韋建','唐','唐诗','tang','','[]','湖廣舟自輕，江天欲澄霽。',120,'全唐诗/poet.tang.13000.json','["湖廣舟自輕，江天欲澄霽。", "是時清楚望，氣色猶霾曀。", "躑躕金霞白，波上日初麗。", "煙紅落鏡中，樹木生天際。", "杳杳涯欲斑，濛濛雲復閉。", "言垂星漢明，又覩寰瀛勢。", "微興從此愜，悠然不知歲。", "試歌滄浪清，遂覺乾坤細。", "肯念客衣薄，將期永投袂。", "遲迴漁父間，一雁聲嘹唳。"]'),
('feec88d1-b8bd-4f59-887a-3fb47159da7f','泊舟盱眙','韋建','唐','唐诗','tang','','[]','泊舟淮水次，霜降夕流清。',48,'全唐诗/poet.tang.13000.json','["泊舟淮水次，霜降夕流清。", "夜久潮浸岸，天寒月近城。", "平沙依鴈宿，候館聽雞鳴。", "鄉國雲霄外，誰堪羈旅情。"]'),
('87355e28-dc3f-4c8b-8d4c-0f50afe018bb','銓試後徴山別業寄源侍御','殷寅','唐','唐诗','tang','','[]','別業在徴山，登高望畿甸。',132,'全唐诗/poet.tang.13000.json','["別業在徴山，登高望畿甸。", "嚴令天地肅，城闕如何見。", "藹藹王侯門，華軒日遊衒。", "幸逢休明代，山虜尚交戰。", "投策去園林，率名皆拜選。", "聖君性則哲，濟濟多英彥。", "裴楷能清通，山濤急推薦。", "謏才甘自屏，薄伎忝餘眷。", "雖承國士恩，尚乏中人援。", "疇昔相知者，今茲秉天憲。", "朱紱何赫赫，繡衣復蔥蒨。"]'),
('3a534189-aff8-47e9-bb0f-7753350c1087','玄元皇帝應角賀聖祚無疆','殷寅','唐','唐诗','tang','','[]','應曆生周日，脩祠表漢年。',96,'全唐诗/poet.tang.13000.json','["應曆生周日，脩祠表漢年。", "復茲秦嶺上，更似霍山前。", "昔贊神功啓，今符聖祚延。", "已題金簡字，仍訪玉堂仙。", "睿祖光元始，曾孫體又玄。", "言因六夢接，慶叶九齡傳。", "北闕心超矣，南山壽固然。", "無由同拜慶，竊抃賀陶甄。"]'),
('2f58fef5-6f8b-41bf-a2b7-9fa46aa0f2e4','秋怨','柳中庸','唐','唐诗','tang','','[]','玉樹起涼煙，凝情一葉前。',48,'全唐诗/poet.tang.13000.json','["玉樹起涼煙，凝情一葉前。", "別離傷曉鏡，搖落思秋弦。", "漢壘關山月，胡笳塞北天。", "不知腸斷夢，空遶幾山川。"]'),
('0a3778fb-6fe4-470e-9a43-9bf8c78553a7','春思贈人','柳中庸','唐','唐诗','tang','','[]','紅粉當三五，青娥豔一雙。',48,'全唐诗/poet.tang.13000.json','["紅粉當三五，青娥豔一雙。", "綺羅迴錦陌，弦管入花江。", "落雁驚金彈，拋杯瀉玉缸。", "誰知褐衣客，顦顇在書窗。"]'),
('741e4915-ced6-4295-b445-f84b68644501','幽院早春','柳中庸','唐','唐诗','tang','','[]','草短花初拆，苔青柳半黃。',36,'全唐诗/poet.tang.13000.json','["草短花初拆，苔青柳半黃。", "隔簾春雨細，高枕曉鶯長。", "無事含閑夢，多情識異香。"]'),
('46c4b862-f6f9-43de-9eb7-6465af52b1f5','寒食戲贈','柳中庸','唐','唐诗','tang','','[]','春暮越江邊，春陰寒食天。',48,'全唐诗/poet.tang.13000.json','["春暮越江邊，春陰寒食天。", "杏花香麥粥，柳絮伴鞦韆。", "酒是芳菲節，人當桃李年。", "不知何處恨，已解入箏弦。"]'),
('e1629d90-2443-46e1-b8a5-7b394970a827','聽箏','柳中庸','唐','唐诗','tang','','[]','抽弦促柱聽秦箏，無限秦人悲怨聲。',64,'全唐诗/poet.tang.13000.json','["抽弦促柱聽秦箏，無限秦人悲怨聲。", "似逐春風知柳態，如隨啼鳥識花情。", "誰家獨夜愁燈影，何處空樓思月明。", "更入幾重離別恨，江南歧路洛陽城。"]'),
('7bec6a44-d780-49de-a561-a8f668da71e0','河陽橋送別','柳中庸','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河流出有浮橋，晉國歸人此路遙。',32,'全唐诗/poet.tang.13000.json','["黃河流出有浮橋，晉國歸人此路遙。", "若傍闌干千里望，北風驅馬雨蕭蕭。"]'),
('92dd65da-8301-4c83-b8f3-986b6095c481','征怨','柳中庸','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u9ec4\u6cb3", "\u8fb9\u585e", "\u4e03\u8a00\u7edd\u53e5"]','歲歲金河復玉關，朝朝馬策與刀環。',32,'全唐诗/poet.tang.13000.json','["歲歲金河復玉關，朝朝馬策與刀環。", "三春白雪歸青冢，萬里黃河遶黑山。"]'),
('218871bc-b14e-44a8-9fde-b9bd347d25c1','涼州曲二首 一','柳中庸','唐','唐诗','tang','','[]','關山萬里遠征人，一望關山淚滿巾。',32,'全唐诗/poet.tang.13000.json','["關山萬里遠征人，一望關山淚滿巾。", "青海戍頭空有月，黃沙磧裏本無春。"]'),
('73b70ce0-ac01-482a-b759-a5ffe845852a','涼州曲二首 二','柳中庸','唐','唐诗','tang','','[]','高檻連天望武威，窮陰拂地戍金微。',32,'全唐诗/poet.tang.13000.json','["高檻連天望武威，窮陰拂地戍金微。", "九城弦管聲遙發，一夜關山雪滿飛。"]'),
('ead025a2-3925-4777-9236-c089b8ef909c','江行','柳中庸','唐','唐诗','tang','','[]','繁陰乍隱洲，落葉初飛浦。',24,'全唐诗/poet.tang.13000.json','["繁陰乍隱洲，落葉初飛浦。", "蕭蕭楚客帆，暮入寒江雨。"]'),
('e4c16400-b46c-4069-9dae-158a4b4e5da2','丁評事宅秋夜宴集','柳中庸','唐','唐诗','tang','','[]','翠幕卷回廊，銀燈開後堂。',48,'全唐诗/poet.tang.13000.json','["翠幕卷回廊，銀燈開後堂。", "風驚擁砌葉，月冷滿庭霜。", "綺席人將醉，繁弦夜未央。", "共憐今促席，誰道客愁長。"]'),
('c8eb0b23-fb4a-450e-b12f-0f6855549aef','夜渡江','柳中庸','唐','唐诗','tang','','[]','夜渚帶浮煙，蒼茫晦遠天。',48,'全唐诗/poet.tang.13000.json','["夜渚帶浮煙，蒼茫晦遠天。", "舟輕不覺動，纜急始知牽。", "聽笛遙尋岸，聞香暗識蓮。", "唯看去帆影，常恐客心懸。"]'),
('3b1d738e-df68-4420-89da-20c14c5fc8a7','揚子途中','柳中庸','唐','唐诗','tang','','[]','楚塞望蒼然，寒林古戍邊。',24,'全唐诗/poet.tang.13000.json','["楚塞望蒼然，寒林古戍邊。", "秋風人渡水，落日雁飛天。"]'),
('1df05a7c-a25e-4bcc-81dd-485f6bffefa3','宴城東莊','崔惠童','唐','唐诗','tang','','[]','一月主人笑幾回，相逢相識且銜杯。',32,'全唐诗/poet.tang.13000.json','["一月主人笑幾回，相逢相識且銜杯。", "眼看春色如流水，今日殘花昨日開。"]'),
('ac916bbf-b5f6-4879-941a-0b4ce20603ac','宴城東莊','崔敏童','唐','唐诗','tang','','[]','一年始有一年春，百歲曾無百歲人。',32,'全唐诗/poet.tang.13000.json','["一年始有一年春，百歲曾無百歲人。", "能向花前幾回醉，十千沽酒莫辭貧。"]'),
('ce3c68c1-2a48-4f7a-9e13-e0fa27179875','奉和聖制早登太行山中言志','苗晉卿','唐','唐诗','tang','','[]','金吾戒道清，羽騎動天聲。',96,'全唐诗/poet.tang.13000.json','["金吾戒道清，羽騎動天聲。", "砥路方南絕，重巖始北征。", "關樓前望遠，河邑下觀平。", "喜氣迴輿合，祥風入斾輕。", "祝堯三老至，會禹百神迎。", "月令農先急，春蒐禮復行。", "仍親后土祭，更理晉陽兵。", "不似勞車轍，空留八駿名。"]'),
('a833a7e3-13da-49f1-83eb-4b3db1dab38d','賦虞書歌','賈躭','唐','唐诗','tang','','[]','衆書之中虞書巧，體法自然歸大道。',96,'全唐诗/poet.tang.13000.json','["衆書之中虞書巧，體法自然歸大道。", "不同懷素只攻顛，豈類張芝惟創草。", "形勢素，筋骨老，父子君臣相揖抱。", "孤青似竹更颼颸，闊白如波長浩渺。", "能方正，不隳倒，功夫未至難尋奧。", "須知孔子廟堂碑，便是青箱中至寶。"]'),
('10d94bd5-d2ab-4fc2-8899-4cd3a5fca059','雲門山投龍詩','趙居貞','唐','唐诗','tang','','[]','曉登雲門山，直上一千尺。',192,'全唐诗/poet.tang.13000.json','["曉登雲門山，直上一千尺。", "絕頂彌孤聳，盤途幾傾窄。", "前對豎裂峯，下臨削成壁。", "陽巘靈芝秀，陰崖半天赤。", "大壑靜不波，渺溟無際極。", "是時雪初霽，冱寒水更積。", "披展送龍儀，寧安服狐白。", "沛恩惟聖主，祈福在方伯。", "三元章醮昇，五域囗囗覿。", "帟幕翠微亙，機茵丹洞闢。", "祝起鳴天鼓，拜傳端素冊。", "霞間朱紱縈，嵐際黃裳襞。", "玉策奉誠信，仙佩俟奔驛。", "香氣入岫門，瑞雲出巖石。", "至誠必招感，大福旋來格。", "空中忽神言，帝壽萬千百。"]'),
('500dd912-d70f-4a29-a1e6-fbdd7741e138','扈從迴鑾應制','蕭華','唐','唐诗','tang','','[]','粵在秦京日，議乎封禪難。',96,'全唐诗/poet.tang.13000.json','["粵在秦京日，議乎封禪難。", "豈知陶唐主，道濟蒼生安。", "惟彼烈祖事，增修實榮觀。", "聲名朝萬國，玉帛禮三壇。", "纂聖德重光，建元功載刊。", "仍開舊馳道，不記昔迴鑾。", "羽衛搖晴日，弓戈生早寒。", "猶思檢玉處，却望白雲端。"]'),
('cd788508-d06e-4c46-9222-c899b5487f81','西河郡太原守張夫人輓歌','李岑','唐','唐诗','tang','','[]','鵲印慶仍傳，魚軒寵莫先。',48,'全唐诗/poet.tang.13000.json','["鵲印慶仍傳，魚軒寵莫先。", "從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。", "哀榮今共盡，悽愴杜陵田。"]'),
('a26c7f6d-fcc0-4142-a208-042a43622480','玄元皇帝應見賀聖祚無疆','李岑','唐','唐诗','tang','','[]','皇綱歸有道，帝系祖玄元。',96,'全唐诗/poet.tang.13000.json','["皇綱歸有道，帝系祖玄元。", "運表南山祚，神通北極尊。", "大同齊日月，興廢應乾坤。", "聖后趨庭禮，宗臣稽首言。", "千官欣肆觀，萬國賀深恩。", "錫宴雲天接，飛聲雷地喧。", "祥光浮紫閣，喜氣繞皇軒。", "未預承天命，空勤望帝門。"]'),
('12e57ab2-c932-4965-8aeb-61b29cd04ea7','復游浯溪','元友讓','唐','唐诗','tang','','[]','昔到纔三歲，今來鬢已蒼。',72,'全唐诗/poet.tang.13000.json','["昔到纔三歲，今來鬢已蒼。", "剝苔看篆字，薙草覓書堂。", "引客登臺上，呼童掃樹旁。", "石渠疏擁水，門徑斸藂篁。", "田地潛更主，林園盡廢荒。", "悲涼問耆耋，疆界指垂楊。"]'),
('5e4a5f1d-9f6a-4c43-b3b6-b50266cc484c','南溪別業','蔣冽','唐','唐诗','tang','','[]','結宇依青嶂，開軒對綠疇。',48,'全唐诗/poet.tang.13000.json','["結宇依青嶂，開軒對綠疇。", "樹交花兩色，溪合水同流。", "竹徑春來掃，蘭尊夜不收。", "逍遙自得意，鼓腹醉中遊。"]'),
('df01972d-f851-4b0f-bbd5-9e57be874eb6','古意','蔣冽','唐','唐诗','tang','','[]','冉冉紅羅帳，開君玉樓上。',48,'全唐诗/poet.tang.13000.json','["冉冉紅羅帳，開君玉樓上。", "畫作同心鳥，銜花兩相向。", "春風正可憐，吹暎綠窗前。", "妾意空相感，君心何處邊。"]'),
('cbae9e83-1d83-491a-8b71-fe64540692c6','臺中書懷','蔣冽','唐','唐诗','tang','','[]','持憲當休明，飭躬免顛沛。',96,'全唐诗/poet.tang.13000.json','["持憲當休明，飭躬免顛沛。", "直繩備豪右，正色清冠蓋。", "寄切才恨薄，職雄班匪大。", "坐居三獨中，立在百僚外。", "簡牘時休暇，依然秋興多。", "披書唯骨鯁，循跡少閑和。", "庭樹凌霜柏，池傾萎露荷。", "歲寒應可見，感此遂成歌。"]'),
('f0dc1af7-c04b-47b3-a488-a60082869b1b','經埋輪地','蔣冽','唐','唐诗','tang','','[]','漢家張御史，晉國綠珠樓。',132,'全唐诗/poet.tang.13000.json','["漢家張御史，晉國綠珠樓。", "時代邈已遠，共謝洛陽秋。", "洛陽大道邊，舊地尚依然。", "下馬獨太息，擾擾城市喧。", "時人欣綠珠，詩滿金谷圓。", "千載埋輪地，無人興一言。", "正直死猶忌，況乃未死前。", "汨羅有飜浪，恐是嫌屈原。", "我聞太古水，上與天相連。", "如何一落地，又作九曲泉。", "萬古惟高步，可以旌我賢。"]'),
('0c6ca3cc-dcd9-4b6c-af3c-11b7bc8ad15e','山行見鵲巢','蔣冽','唐','唐诗','tang','','[]','鵲巢性本高，更在西山木。',48,'全唐诗/poet.tang.13000.json','["鵲巢性本高，更在西山木。", "朝下清泉戲，夜近明月宿。", "非直避網羅，兼能免傾覆。", "豈憂五陵子，挾彈來相逐。"]'),
('b22bb299-e951-445a-8926-46d406d65136','巫山之陽香谿之陰明妃神女舊跡存焉','蔣冽','唐','唐诗','tang','','[]','神女歸巫峽，明妃入漢宮。',48,'全唐诗/poet.tang.13000.json','["神女歸巫峽，明妃入漢宮。", "搗衣餘石在，薦枕舊室空。", "行雨有時度，谿流何日窮。", "至今詞賦裏，淒愴寫遺風。"]'),
('272c9e8c-5d6f-4e20-b8d6-e7c8a30b8915','夜飛鵲','蔣冽','唐','唐诗','tang','','[]','北林夜方久，南月影頻移。',24,'全唐诗/poet.tang.13000.json','["北林夜方久，南月影頻移。", "何啻飛三匝，猶言未得枝。"]'),
('13db9634-9391-4c27-b732-15022d699ece','途次維揚望京口寄白下諸公','蔣渙','唐','唐诗','tang','','[]','北望情何限，南行路轉深。',48,'全唐诗/poet.tang.13000.json','["北望情何限，南行路轉深。", "晚帆低荻葉，寒日下楓林。", "雲白蘭陵渚，煙青建業岑。", "江天秋向盡，無處不傷心。"]'),
('6ed1ce5e-d66c-448d-a501-05d2930952d4','登栖霞寺塔','蔣渙','唐','唐诗','tang','','[]','三休尋磴道，九折步雲霓。',48,'全唐诗/poet.tang.13000.json','["三休尋磴道，九折步雲霓。", "瀍澗臨江北，郊原極海西。", "沙平瓜步出，樹遠綠楊低。", "南指晴天外，青峯是會稽。"]'),
('a99c1676-7cc6-4ba2-aaec-9b7df92074e7','和徐侍郎書叢篠韻','蔣渙','唐','唐诗','tang','','[]','中禁夕沈沈，幽篁別作林。',48,'全唐诗/poet.tang.13000.json','["中禁夕沈沈，幽篁別作林。", "色連雞樹近，影落鳳池深。", "爲重凌霜節，能虛應物心。", "年年承雨露，長對紫庭陰。"]'),
('ee558237-de12-44dd-a03c-a49bb884e45a','故太常卿贈禮部尚書李公及夫人輓歌二首 一','蔣渙','唐','唐诗','tang','','[]','白簡嘗持憲，黃圖復尹京。',48,'全唐诗/poet.tang.13000.json','["白簡嘗持憲，黃圖復尹京。", "能標百郡則，威肅一朝清。", "典秩崇三禮，臨戍振五兵。", "更聞傳世業，才子有高名。"]'),
('d96528a7-cbcd-4271-90c1-59fb9242eef4','故太常卿贈禮部尚書李公及夫人輓歌二首 二','蔣渙','唐','唐诗','tang','','[]','封樹遵同穴，生平此共歸。',48,'全唐诗/poet.tang.13000.json','["封樹遵同穴，生平此共歸。", "鏡埋鸞已去，泉掩鳳何飛。", "薤輓疑笳曲，松風思翟衣。", "揚名將寵贈，泉路滿光輝。"]'),
('8c6a491e-d3b5-4a63-8b7e-49e073551a4f','挽湧泉寺僧懷玉','段懷然','唐','唐诗','tang','','[]','我師一念登初地，佛國笙歌兩度來。',32,'全唐诗/poet.tang.13000.json','["我師一念登初地，佛國笙歌兩度來。", "唯有門前古槐樹，枝低只爲挂銀臺。"]'),
('0df89fc3-7295-4b8b-b839-e19186eb453b','辭房相公','張偁','唐','唐诗','tang','','[]','秋風颯颯雨霏霏，愁殺恓遑一布衣。',32,'全唐诗/poet.tang.13000.json','["秋風颯颯雨霏霏，愁殺恓遑一布衣。", "辭君且作隨陽鳥，海內無家何處歸。"]'),
('840561f4-66b7-4c22-9083-b5e727226c2a','移耶溪舊居呈陳元初校書','陳孫','唐','唐诗','tang','','[]','雞犬漁舟裏，長謠任興行。',48,'全唐诗/poet.tang.13000.json','["雞犬漁舟裏，長謠任興行。", "即令邀客醉，已被遠山迎。", "書笈將非重，荷衣著甚輕。", "謝安無個事，忽起爲蒼生。"]'),
('7347c32f-e075-48f9-8e30-ef07fcf12360','西河郡太原守張夫人挽歌','李峯','唐','唐诗','tang','','[]','鵲印慶仍傳，魚軒寵莫先。',48,'全唐诗/poet.tang.13000.json','["鵲印慶仍傳，魚軒寵莫先。", "從夫元凱貴，訓子孟軻賢。", "龍是雙歸日，鸞非獨舞年。", "哀榮今共盡，悽愴杜陵田。"]'),
('fc6d8301-56b5-401b-93c8-bd3085108143','感懷弟妹','沈千運','唐','唐诗','tang','','[]','今日春氣暖，東風杏花拆。',144,'全唐诗/poet.tang.13000.json','["今日春氣暖，東風杏花拆。", "筋力久不如，却羨澗中石。", "神仙杳難準，中壽稀滿百。", "近世多夭傷，喜見鬢髮白。", "杖藜竹樹間，宛宛舊行跡。", "豈知林園主，却是林園客。", "兄弟可存半，空爲亡者惜。", "冥冥無再期，哀哀望松柏。", "骨肉能幾人，年大自疎隔。", "性情誰免此，與我不相易。", "唯念得爾輩，時看慰朝夕。", "平生茲已矣，此外盡非適。"]'),
('4a2c31b1-5107-41c6-8ae6-723852061d89','贈史脩文','沈千運','唐','唐诗','tang','','[]','故人阻千里，會面非別期。',96,'全唐诗/poet.tang.13000.json','["故人阻千里，會面非別期。", "握手於此地，當歡反成悲。", "念離宛猶昨，俄已經數期。", "疇昔皆少年，別來鬢如絲。", "不道舊姓名，相逢知是誰。", "曩遊盡騫翥，與君仍布衣。", "豈曰無其才，命理應有時。", "別路漸欲少，不覺生涕洟。"]'),
('294f0816-30dd-4941-bb26-bb50378c91b0','濮中言懷','沈千運','唐','唐诗','tang','','[]','聖朝優賢良，草澤無遺匿。',120,'全唐诗/poet.tang.13000.json','["聖朝優賢良，草澤無遺匿。", "人生各有命，在余胡不淑。", "一生但區區，五十無寸祿。", "衰退當棄捐，貧賤招毀讟。", "栖栖去人世，屯躓日窮迫。", "不如守田園，歲晏望豐熟。", "壯年失宜盡，老大無筋力。", "始覺前計非，將貽後生福。", "童兒新學稼，少女未能織。", "顧此煩知己，終日求衣食。"]'),
('a6752672-3fd9-441d-a73b-3693a777f9bd','山中作','沈千運','唐','唐诗','tang','','[]','栖隱非別事，所願離風塵。',84,'全唐诗/poet.tang.13000.json','["栖隱非別事，所願離風塵。", "不辭城邑遊，禮樂拘束人。", "邇來歸山林，庶事皆吾身。", "何者爲形骸，誰是智與仁。", "寂寞了閑事，而後知天真。", "咳唾矜崇華，迂俯相屈伸。", "如何巢與由，天子不知臣。"]'),
('56981f4f-ed7a-47b4-9d7f-6d1438bc43e5','古歌','沈千運','唐','唐诗','tang','','[]','北邙不種田，但種松與柏。',24,'全唐诗/poet.tang.13000.json','["北邙不種田，但種松與柏。", "松柏未生處，留待市朝客。"]'),
('0bf23d3c-28d0-4c68-af69-96cd4bb1d5ce','別李季友','王季友','唐','唐诗','tang','','[]','栖鳥不戀枝，喈喈在同聲。',60,'全唐诗/poet.tang.13000.json','["栖鳥不戀枝，喈喈在同聲。", "行子馳出戶，依依主人情。", "昔時霜臺鏡，醜婦羞爾形。", "閉匣二十年，皎潔常獨明。", "今日照離別，前途白髮生。"]'),
('65d48727-36b3-4570-99e0-3bc5c83a9e55','寄韋子春','王季友','唐','唐诗','tang','','[]','出山秋雲曙，山木已再春。',96,'全唐诗/poet.tang.13000.json','["出山秋雲曙，山木已再春。", "食我山中藥，不憶山中人。", "山中誰余密，白髮日相親。", "雀鼠畫夜無，知我廚廩貧。", "依依北舍松，不厭吾南隣。", "有情盡棄捐，土石爲同身。", "夫子質千尋，天澤枝葉新。", "余以不材壽，非智免斧斤。"]'),
('e384335e-1903-46b3-88c7-701ea37ec87c','雜詩','王季友','唐','唐诗','tang','','[]','采山仍采隱，在山不在深。',72,'全唐诗/poet.tang.13000.json','["采山仍采隱，在山不在深。", "持斧事遠遊，固非匠者心。", "翳翳青桐枝，樵爨日所侵。", "斧聲出巖壑，四聽無知音。", "豈爲鼎下薪，當復堂上琴。", "鳳鳥久不栖，且與枳棘林。"]'),
('9fc0c960-e128-4947-abd5-8f7d3b3027a5','滑中贈崔高士瑾','王季友','唐','唐诗','tang','','[]','夫子保藥命，外身得無咎。',144,'全唐诗/poet.tang.13000.json','["夫子保藥命，外身得無咎。", "日月不能老，化腸爲筯否。", "十年前見君，甲子過我壽。", "于何今相逢，華髮在我後。", "近而知其遠，少見今白首。", "遙信蓬萊宮，不死世世有。", "玄石采盈擔，神方秘其肘。", "問家惟指雲，愛氣常言酒。", "攝生固如此，履道當不朽。", "未能太玄同，願亦天地久。", "實腹以芝朮，賤形乃芻狗。", "自勉將勉余，良藥在苦口。"]'),
('dafe58c9-1ace-4b59-a16a-e0a88c395d46','還山留別長安知己','王季友','唐','唐诗','tang','','[]','出山不見家，還山見家在。',48,'全唐诗/poet.tang.13000.json','["出山不見家，還山見家在。", "山門是門前，此去長樵采。", "青溪誰招隱，白髮自相待。", "惟餘澗底松，依依色不改。"]'),
('37d34b6e-d2f9-4c75-9a36-c20740e4cd2e','代賀若令譽贈沈千運','王季友','唐','唐诗','tang','','[]','相逢問姓名亦存，別時無子今有孫。',112,'全唐诗/poet.tang.13000.json','["相逢問姓名亦存，別時無子今有孫。", "山上雙松長不改，百家唯有三家村。", "村南村西車馬道，一宿通舟水浩浩。", "澗中磊磊十里石，河上淤泥種桑麥。", "平坡冢墓皆我親，滿田主人是舊客。", "舉聲酸鼻問同年，十人六七歸下泉。", "分手如何更此地，回頭不語淚潸然。"]'),
('5677dd61-8afe-41a2-8f49-8e5e6f032c6a','酬李十六岐','王季友','唐','唐诗','tang','','[]','鍊丹文武火未成，賣藥販履俱逃名。',160,'全唐诗/poet.tang.13000.json','["鍊丹文武火未成，賣藥販履俱逃名。", "出谷迷行洛陽道，乘流醉臥滑臺城。", "城下故人久離怨，一歡適我兩家願。", "朝飲杖懸沽酒錢，暮餐囊有松花飯。", "于何車馬日憧憧，李膺門館爭登龍。", "千賓揖對若流水，五經發難如叩鐘。", "下筆新詩行滿壁，立談古人坐在席。", "問我草堂有臥雲，知我山儲無儋石。", "自耕自刈食爲天，如鹿如麋飲野泉。", "亦知世上公卿貴，且養丘中草木年。"]'),
('2d398524-cb92-4ff5-ba2b-99a75e2920b9','宿東溪李十五山亭','王季友','唐','唐诗','tang','','[]','上山下山入山谷，溪中落日留我宿。',64,'全唐诗/poet.tang.13000.json','["上山下山入山谷，溪中落日留我宿。", "松石依依當主人，主人不在意亦足。", "名花出地兩重階，絕頂平天一小齋。", "本意由來是山水，何用相逢語舊懷。"]'),
('485c7865-21ae-4cbb-b924-c0ace8600acc','觀于舍人壁畫山水','王季友','唐','唐诗','tang','','[]','野人宿在人家少，朝見此山謂山曉。',64,'全唐诗/poet.tang.13000.json','["野人宿在人家少，朝見此山謂山曉。", "半壁仍棲嶺上雲，開簾欲放湖中鳥。", "獨坐長松是阿誰，再三招手起來遲。", "于公大笑向予說，小弟丹青能爾爲。"]'),
('972d6ce8-67dd-4433-b92d-7df7315d7772','玉壺冰','王季友','唐','唐诗','tang','','[]','玉壺知素結，止水復中澄。',72,'全唐诗/poet.tang.13000.json','["玉壺知素結，止水復中澄。", "堅白能虛受，清寒得自凝。", "分形同曉鏡，照物掩宵燈。", "壁映圓光入，人驚爽氣凌。", "金罍何足貴，瑤席幾回升。", "正值求珪瓚，提攜共飲冰。"]'),
('ffdb69e2-6a36-460f-8aa0-24114e19045f','古塞曲','王季友','唐','唐诗','tang','','[]','進軍飛狐北，窮寇勢將變。',72,'全唐诗/poet.tang.13000.json','["進軍飛狐北，窮寇勢將變。", "日落沙塵昏，背河更一戰。", "騂馬黃金勒，雕弓白羽箭。", "射殺左賢王，歸奏未央殿。", "欲言塞下事，天子不召見。", "東出咸陽門，哀哀淚如霰。"]'),
('5c99c2a8-57c9-4e5c-8198-34bee272ad8b','野外行','于逖','唐','唐诗','tang','','[]','老病無樂事，歲秋悲更長。',96,'全唐诗/poet.tang.13000.json','["老病無樂事，歲秋悲更長。", "窮郊日蕭索，生意已蒼黃。", "小弟髮亦白，兩男俱不強。", "有才且未達，況我非賢良。", "幸以朽鈍姿，野外老風霜。", "寒鴉噪晚景，喬木思故鄉。", "魏人宅蓬池，結網佇鱣魴。", "水清魚不來，歲暮空徬徨。"]'),
('c200f68d-d184-4895-b9dd-bbc56d384e6c','憶舍弟','于逖','唐','唐诗','tang','','[]','衰門少兄弟，兄弟唯兩人。',84,'全唐诗/poet.tang.13000.json','["衰門少兄弟，兄弟唯兩人。", "飢寒各流浪，感念傷我神。", "夏期秋未來，安知無他因。", "不怨別天長，但願見爾身。", "茫茫天地間，萬類各有親。", "安知汝與我，乖隔同胡秦。", "何時對形影，憤懣當共陳。"]'),
('37672f9c-0684-489c-bbf4-8f3dee9e5d35','雜詩','張彪','唐','唐诗','tang','','[]','富貴多勝事，貪賤無良圖。',96,'全唐诗/poet.tang.13000.json','["富貴多勝事，貪賤無良圖。", "上德兼濟心，中才不如愚。", "商者多巧智，農者爭膏腴。", "儒生未遇時，衣食不自如。", "久與故交別，他榮我窮居。", "到門懶入門，何況千里餘。", "君子有褊性，矧乃尋常徒。", "行行任天地，無爲強親疎。"]'),
('52fa8b90-7f88-42a1-a20d-12dc34fba35a','神仙','張彪','唐','唐诗','tang','','[]','神仙可學無，百歲名大約。',84,'全唐诗/poet.tang.13000.json','["神仙可學無，百歲名大約。", "天地何蒼茫，人間半哀樂。", "浮生亮多惑，善事翻爲惡。", "爭先等馳驅，中路苦瘦弱。", "長老思養壽，後生笑寂寞。", "五穀非長年，四氣乃靈藥。", "列子何必待，吾心滿寥廓。"]'),
('0e42b61d-d0b4-4876-bfbd-269008daa0f8','北遊還酬孟雲卿','張彪','唐','唐诗','tang','','[]','忽忽忘前事，志願能相乖。',84,'全唐诗/poet.tang.13000.json','["忽忽忘前事，志願能相乖。", "衣馬久羸弊，誰信文與才。", "善道居貧賤，潔服蒙塵埃。", "行行無定心，壈坎難歸來。", "慈母憂疾疹，至家念栖哀。", "與君宿姻親，深見中外懷。", "俟余惜時節，倀望臨高臺。"]'),
('50c1b634-3358-4815-a597-27f077f8701b','古別離','張彪','唐','唐诗','tang','','[]','別離無遠近，事歡情亦悲。',48,'全唐诗/poet.tang.13000.json','["別離無遠近，事歡情亦悲。", "不聞車輪聲，後會將何時。", "去日忘寄書，來日乖前期。", "縱知明當返，一息千萬思。"]'),
('51d301b0-9e4a-4fce-931c-d10b86c5a0ff','回軍跛者','趙徵明','唐','唐诗','tang','','[]','既老又不全，始得離邊城。',84,'全唐诗/poet.tang.13000.json','["既老又不全，始得離邊城。", "一枝假枯木，步步向南行。", "去時日一百，來時月一程。", "常恐道路旁，掩棄狐兔塋。", "所願死鄉里，到日不願生。", "聞此哀怨詞，念念不忍聽。", "惜無異人術，倏忽具爾形。"]'),
('b9f40f86-1b30-4bbf-9a09-8402a7a296c6','挽歌詞','趙徵明','唐','唐诗','tang','','[]','寒日蒿上明，淒淒郭東路。',60,'全唐诗/poet.tang.13000.json','["寒日蒿上明，淒淒郭東路。", "素車誰家子，丹旐引將去。", "原下荆棘叢，叢邊有新墓。", "人間痛傷別，此是長別處。", "曠野多蕭條，青松白楊樹。"]'),
('2d96f863-72d7-409e-9c94-39f2d68eb802','思歸','趙徵明','唐','唐诗','tang','','[]','爲別未幾日，去日如三秋。',48,'全唐诗/poet.tang.13000.json','["爲別未幾日，去日如三秋。", "猶疑望可見，日日上高樓。", "惟見分手處，白蘋滿芳洲。", "寸心寧死別，不忍生離憂。"]'),
('917ed94c-096c-4143-b5c3-45ca56355320','泉上雨後作','元季川','唐','唐诗','tang','','[]','風雨蕩繁暑，雷息佳霽初。',84,'全唐诗/poet.tang.13000.json','["風雨蕩繁暑，雷息佳霽初。", "衆峰帶雲雨，清氣入我廬。", "颯颯涼飆來，臨窺愜所圖。", "綠蘿長新蔓，褭褭垂坐隅。", "流水復簷下，丹砂發清渠。", "養葛爲我衣，種芋爲我蔬。", "誰是畹與畦，瀰漫連野蕪。"]'),
('265752d4-4e7d-4bc4-b759-5b18e61f2530','登雲中','元季川','唐','唐诗','tang','','[]','灌田東山下，取樂在爾休。',60,'全唐诗/poet.tang.13000.json','["灌田東山下，取樂在爾休。", "清興相引行，日日三四周。", "白鷗與我心，不厭此中遊。", "窮覽頗有適，不極趣無幽。", "憀然歌采薇，曲盡心悠悠。"]'),
('993ee31a-499f-4ef2-be04-a78790652ee5','山中曉興','元季川','唐','唐诗','tang','','[]','河漢降玄霜，昨來節物殊。',60,'全唐诗/poet.tang.13000.json','["河漢降玄霜，昨來節物殊。", "媿無神仙姿，豈有陰陽俱。", "靈鳥望不見，慨然悲高梧。", "華葉隨風揚，珍條雜榛蕪。", "爲君寒谷吟，歎息知何如。"]'),
('a3e37219-3f22-4219-af25-ae4e543e6c01','古遠行','元季川','唐','唐诗','tang','','[]','悠悠遠行者，羈獨當時思。',60,'全唐诗/poet.tang.13000.json','["悠悠遠行者，羈獨當時思。", "道與日月長，人無茅舍期。", "出門萬里心，誰不傷別離。", "縱遠當白髮，歲月悲今時。", "何況異形容，安須與爾悲。"]'),
('7ba64715-231e-46b2-9208-b835894c19c1','晚秋拾遺朱放訪山居','秦系','唐','唐诗','tang','','[]','不逐時人後，終年獨閉關。',48,'全唐诗/poet.tang.13000.json','["不逐時人後，終年獨閉關。", "家中貧自樂，石上臥常閑。", "墜栗添新味，寒花帶老顏。", "侍臣當獻納，那得到空山。"]'),
('95611e85-f502-401b-8e88-d32127303464','題女道士居','秦系','唐','唐诗','tang','','[]','不餌住雲溪，休丹罷藥畦。',48,'全唐诗/poet.tang.13000.json','["不餌住雲溪，休丹罷藥畦。", "杏花虛結子，石髓任成泥。", "掃地青牛臥，栽松白鶴棲。", "共知仙女麗，莫是阮郎妻。"]'),
('62170895-9024-4f30-b962-d1bd01eb00aa','山中枉張宙員外書期訪衡門','秦系','唐','唐诗','tang','','[]','常恨相知晚，朝來枉數行。',48,'全唐诗/poet.tang.13000.json','["常恨相知晚，朝來枉數行。", "臥雲驚聖代，拂石候仙郎。", "時果連枝熟，春醪滿甕香。", "貧家仍有趣，山色滿湖光。"]'),
('3a26e3fb-8954-4a1a-a5f6-53e920d22c26','山中贈張正則評事','秦系','唐','唐诗','tang','','[]','終年常避喧，師事五千言。',48,'全唐诗/poet.tang.13000.json','["終年常避喧，師事五千言。", "流水閑過院，春風與閉門。", "山茶邀上客，桂實落前軒。", "莫強敎余起，微官不足論。"]'),
('eb27dc15-8614-429a-8a34-eac8d5e1541b','題鏡湖野老所居','秦系','唐','唐诗','tang','','[]','湖裏尋君去，樵風往返吹。',48,'全唐诗/poet.tang.13000.json','["湖裏尋君去，樵風往返吹。", "樹喧巢鳥出，路細葑田移。", "漚苧成魚網，枯根是酒巵。", "老年唯自適，生事任羣兒。"]'),
('e975792f-061f-4132-9523-f87eb07ea3e8','早秋宿崔業居處','秦系','唐','唐诗','tang','','[]','從來席不暖，爲爾便淹流。',48,'全唐诗/poet.tang.13000.json','["從來席不暖，爲爾便淹流。", "雞黍今相會，雲山昔共遊。", "上簾宜晚景，臥簟覺新秋。", "身事何須問，余心正四愁。"]'),
('ea158529-b9fd-4a7f-bc24-669b1cecee33','贈烏程楊苹明府','秦系','唐','唐诗','tang','','[]','策杖政成時，清溪弄釣絲。',48,'全唐诗/poet.tang.13000.json','["策杖政成時，清溪弄釣絲。", "當年潘子貌，避病沈侯詩。", "漉酒迎賓急，看花署字遲。", "楊梅今熟未，與我兩三枝。"]'),
('f84b9b4c-b32a-41a9-b21c-4875eb6672e5','徐侍郎素未相識時攜酒命饌兼命諸詩客同訪會稽山居','秦系','唐','唐诗','tang','','[]','忽道仙翁至，幽人學拜迎。',48,'全唐诗/poet.tang.13000.json','["忽道仙翁至，幽人學拜迎。", "華簪窺甕牖，珍味代藜羹。", "洗硯魚仍戲，移樽鳥不驚。", "蘭亭攀敘却，會此越中營。"]'),
('3b28dca6-a10e-4666-9bdc-6f938af982ae','春日閑居三首 一','秦系','唐','唐诗','tang','','[]','一似桃源隱，將令過客迷。',48,'全唐诗/poet.tang.13000.json','["一似桃源隱，將令過客迷。", "礙冠門柳長，驚夢院鶯啼。", "澆藥泉流細，圍碁日影低。", "舉家無外事，共愛草萋萋。"]'),
('95a723b6-b697-4787-bc6f-8b87492fcecb','春日閑居三首 二','秦系','唐','唐诗','tang','','[]','長謠朝復暝，幽獨幾人知。',48,'全唐诗/poet.tang.13000.json','["長謠朝復暝，幽獨幾人知。", "老鶴兼雛弄，叢篁帶笋移。", "白雲將袖拂，青鏡出簷窺。", "邀取漁家叟，花間把酒巵。"]'),
('cf8bbbce-2906-43d8-b1f8-072fa6a3feed','春日閑居三首 三','秦系','唐','唐诗','tang','','[]','寂寂池亭裏，軒窗間綠苔。',48,'全唐诗/poet.tang.13000.json','["寂寂池亭裏，軒窗間綠苔。", "游魚牽荇沒，戲鳥踏花摧。", "小徑僧尋去，高峯鹿下來。", "中年曾屢辟，多病復遲迴。"]'),
('e7fa1a26-801e-4852-822a-668dffde2523','題石室山王宁所居','秦系','唐','唐诗','tang','','[]','白雲知所好，柏葉幸加餐。',48,'全唐诗/poet.tang.13000.json','["白雲知所好，柏葉幸加餐。", "石鏡妻將照，仙書我借看。", "鳥來翻藥椀，猿飲怕魚竿。", "借問簷前樹，何枝曾挂冠。"]'),
('87065899-8186-4213-bacc-ea979b255ce2','送王道士','秦系','唐','唐诗','tang','','[]','真人俄整舃，雙鶴屢飛翔。',48,'全唐诗/poet.tang.13000.json','["真人俄整舃，雙鶴屢飛翔。", "恐入壺中住，須傳肘後方。", "霓裳雲氣潤，石徑朮苗香。", "一去何時見，仙家日月長。"]'),
('967b7b73-9ea6-4478-96e1-75e024831ca4','將移耶溪舊居留贈嚴維秘書','秦系','唐','唐诗','tang','','[]','雞犬漁舟裏，長謠任興行。',48,'全唐诗/poet.tang.13000.json','["雞犬漁舟裏，長謠任興行。", "那邀落日醉，已被遠山迎。", "書篋將非重，荷衣著甚輕。", "謝安無箇事，忽起爲蒼生。"]'),
('ee5ea8e7-5117-4311-a315-e99cb54af115','秋日過僧惟則故院','秦系','唐','唐诗','tang','','[]','衰草經行處，微燈舊道場。',48,'全唐诗/poet.tang.13000.json','["衰草經行處，微燈舊道場。", "門人失譚柄，野鳥上禪牀。", "科斗書空古，栴檀缽自香。", "今朝數行淚，却灑約公房。"]'),
('144012f1-7a20-4c32-8f61-b4726c8aa2e7','山中奉寄錢起員外兼簡苗發員外','秦系','唐','唐诗','tang','','[]','空山歲計是胡麻，窮海無梁泛一槎。',64,'全唐诗/poet.tang.13000.json','["空山歲計是胡麻，窮海無梁泛一槎。", "稚子唯能覓梨栗，逸妻相共老烟霞。", "高吟麗句驚巢鶴，閑閉春風看落花。", "借問省中何水部，今人幾箇屬詩家。"]'),
('99a13a6a-2e20-4db8-96a7-fb26093689d0','獻薛僕射','秦系','唐','唐诗','tang','','[]','由來那敢議輕肥，散髮行歌自採薇。',64,'全唐诗/poet.tang.13000.json','["由來那敢議輕肥，散髮行歌自採薇。", "逋客未能忘野興，辟書翻遣脫荷衣。", "家中匹婦空相笑，池上羣鷗盡欲飛。", "更乞大賢容小隱，益看愚谷有光輝。"]'),
('64896cb9-3383-45d7-b031-489bcd1ae6a2','鮑防員外見尋因書情呈贈','秦系','唐','唐诗','tang','','[]','少小爲儒不自強，如今嬾復見侯王。',64,'全唐诗/poet.tang.13000.json','["少小爲儒不自強，如今嬾復見侯王。", "覽鏡已知身漸老，買山將作計偏長。", "荒涼鳥獸同三逕，撩亂琴書共一牀。", "猶有郎官來問疾，時人莫道我佯狂。"]'),
('3c538370-b0e4-4898-99a4-a4bad2df42d1','寄浙東皇甫中丞','秦系','唐','唐诗','tang','','[]','閑閑麋鹿或相隨，一兩年來鬢欲衰。',64,'全唐诗/poet.tang.13000.json','["閑閑麋鹿或相隨，一兩年來鬢欲衰。", "琴硯共依春酒甕，雲霞覆著破柴籬。", "注書不向時流說，種藥空令道者知。", "久帶紗巾仍藉草，山中那得見朝儀。"]'),
('439515ac-9aad-456b-986c-e63161f13a9d','題章野人山居','秦系','唐','唐诗','tang','','[]','帶郭茅亭詩興饒，回看一曲倚危橋。',64,'全唐诗/poet.tang.13000.json','["帶郭茅亭詩興饒，回看一曲倚危橋。", "門前山色能深淺，壁上湖光自動搖。", "閑花散落填書帙，戲鳥低飛礙柳條。", "向此隱來經幾載，如今已是漢家朝。"]'),
('ce932726-f3d6-4aec-8642-76290d52ad85','山中枉皇甫溫大夫見招書','秦系','唐','唐诗','tang','','[]','十年木屐步苔痕，石上松間水自喧。',64,'全唐诗/poet.tang.13000.json','["十年木屐步苔痕，石上松間水自喧。", "三辟草堂仍被褐，數行書札忽臨門。", "臥多共息嵇康病，才劣虛同郭隗尊。", "亞相已能憐潦倒，山花笑處莫啼猿。"]'),
('41eb942c-0f5d-4834-a8e9-dd270e1ea195','題茅山李尊師山居','秦系','唐','唐诗','tang','','[]','天師百歲少如童，不到山中竟不逢。',64,'全唐诗/poet.tang.13000.json','["天師百歲少如童，不到山中竟不逢。", "洗藥每臨新瀑水，步虛時上最高峰。", "籬間五月留殘雪，座右千年廕老松。", "此去人寰今遠近，回看雲壑一重重。"]'),
('8a50f8db-5778-4953-b345-c433613544fa','耶溪書懷寄劉長卿員外','秦系','唐','唐诗','tang','','[]','時人多笑樂幽棲，晚起閑行獨杖藜。',64,'全唐诗/poet.tang.13000.json','["時人多笑樂幽棲，晚起閑行獨杖藜。", "雲色卷舒前後嶺，藥苗新舊兩三畦。", "偶逢野果將呼子，屢折荆釵亦爲妻。", "擬共釣竿長往復，巖陵灘上勝耶溪。"]'),
('2d3bf54b-d657-43d8-8999-dca60322355d','山中崔大夫有書相問','秦系','唐','唐诗','tang','','[]','客在煙霞裏，閑閑逐狎鷗。',96,'全唐诗/poet.tang.13000.json','["客在煙霞裏，閑閑逐狎鷗。", "終年常裸足，連日半蓬頭。", "帶月乘漁艇，迎寒綻鹿裘。", "已于人事少，多被挂冠留。", "素業堆千卷，清風至一丘。", "蒼黃倒藜杖，傴僂覩銀鉤。", "跡愧巢由隱，才非管樂儔。", "從來自多病，不是傲王侯。"]'),
('f8edd120-3495-418e-8df9-3b36d4bcd328','張建封大夫奏系爲校書郎因寄此作','秦系','唐','唐诗','tang','','[]','久是煙霞客，潭深釣得魚。',24,'全唐诗/poet.tang.13000.json','["久是煙霞客，潭深釣得魚。", "不知芸閣上，遺校幾多書。"]'),
('8804255a-ff41-4156-8da9-4a77a0a01c0e','會稽山居寄薛播侍郎袁高給事高參舍人','秦系','唐','唐诗','tang','','[]','稷卨今爲相，明君復是堯。',24,'全唐诗/poet.tang.13000.json','["稷卨今爲相，明君復是堯。", "寧知買臣困，猶負會稽樵。"]'),
('4d9a2f77-7edd-40c8-a227-1c5d6dac6804','閑居覽史','秦系','唐','唐诗','tang','','[]','長策胸中不復論，荷衣藍縷閉柴門。',32,'全唐诗/poet.tang.13000.json','["長策胸中不復論，荷衣藍縷閉柴門。", "當時漢祖無三傑，爭得咸陽與子孫。"]'),
('7980a789-53da-4d4c-afab-0bbe97dd46bd','山中贈耿拾遺湋兼兩省故人','秦系','唐','唐诗','tang','','[]','數片荷衣不蔽身，青山白鳥豈知貧。',32,'全唐诗/poet.tang.13000.json','["數片荷衣不蔽身，青山白鳥豈知貧。", "如今非是秦時世，更隱桃花亦笑人。"]'),
('f4227169-1e61-4208-aaeb-ebea6439eec0','秋日送僧志幽歸山寺','秦系','唐','唐诗','tang','','[]','禪室繩牀在翠微，松間荷笠一僧歸。',32,'全唐诗/poet.tang.13000.json','["禪室繩牀在翠微，松間荷笠一僧歸。", "磬聲寂歷宜秋夜，手冷燈前自衲衣。"]'),
('4679fdef-381f-44be-9291-8f0181c8c856','題僧明惠房','秦系','唐','唐诗','tang','','[]','簷前朝暮雨添花，八十真僧飯一麻。',32,'全唐诗/poet.tang.13000.json','["簷前朝暮雨添花，八十真僧飯一麻。", "入定幾時將出定，不知巢燕污袈裟。"]'),
('0179a6b0-a00c-495e-91ec-e0a4f0bfdf69','答泉州薛播使君重陽日贈酒','秦系','唐','唐诗','tang','','[]','欲強登高無力也，籬邊黃菊爲誰開。',32,'全唐诗/poet.tang.13000.json','["欲強登高無力也，籬邊黃菊爲誰開。", "共知不是潯陽郡，那得王弘送酒來。"]'),
('0ceb4f66-5d2e-4b52-b611-dc308516edea','題洪道士山院','秦系','唐','唐诗','tang','','[]','霞外主人門不扃，數株桃樹藥囊青。',32,'全唐诗/poet.tang.13000.json','["霞外主人門不扃，數株桃樹藥囊青。", "閑行池畔隨孤鶴，若問多應道姓丁。"]'),
('ced665f5-91f8-4f91-bef6-73ba963cafd2','期王鍊師不至','秦系','唐','唐诗','tang','','[]','黃精蒸罷洗瓊杯，林下從留石上苔。',32,'全唐诗/poet.tang.13000.json','["黃精蒸罷洗瓊杯，林下從留石上苔。", "昨日圍棋未終局，多乘白鶴下山來。"]'),
('1d5032b6-cd8e-4c5e-bbf7-e0f95a18e6a1','題贈張道士山居','秦系','唐','唐诗','tang','','[]','盤石垂蘿即是家，回頭猶看五枝花。',32,'全唐诗/poet.tang.13000.json','["盤石垂蘿即是家，回頭猶看五枝花。", "松間寂寂無煙火，應服朝來一片霞。"]'),
('2de25a81-af75-465c-9354-ca3a2d23c13b','山中書懷寄張建封大夫','秦系','唐','唐诗','tang','','[]','昨日年催白髮新，身如麋鹿不知貧。',32,'全唐诗/poet.tang.13000.json','["昨日年催白髮新，身如麋鹿不知貧。", "時時亦被羣兒笑，賴有南山四老人。"]'),
('10a896fb-d8d1-4d99-98d1-eec0e08dba3e','山中贈諸暨丹丘明府','秦系','唐','唐诗','tang','','[]','荷衣半破帶莓苔，笑向陶潛酒甕開。',32,'全唐诗/poet.tang.13000.json','["荷衣半破帶莓苔，笑向陶潛酒甕開。", "縱醉遠須上山去，白雲那肯下山來。"]'),
('24ada1e5-a398-4e50-883c-e50e7bafa9ce','奉寄晝公','秦系','唐','唐诗','tang','','[]','蓑笠雙童傍酒船，湖山相引到房前。',32,'全唐诗/poet.tang.13000.json','["蓑笠雙童傍酒船，湖山相引到房前。", "團蕉何事敎人見，暫借空牀守坐禪。"]'),
('bb8bcabd-0823-4dea-bf90-a3a59aec3f22','宿雲門上方','秦系','唐','唐诗','tang','','[]','禪室遙看峰頂頭，白雲東去水長流。',32,'全唐诗/poet.tang.13000.json','["禪室遙看峰頂頭，白雲東去水長流。", "松間儻許幽人住，不更將錢買沃州。"]'),
('2938d405-ac85-4e4a-9261-d4b983e0f068','即事奉呈郎中韋使君','秦系','唐','唐诗','tang','','[]','久臥雲間已息機，青袍忽著狎鷗飛。',32,'全唐诗/poet.tang.13000.json','["久臥雲間已息機，青袍忽著狎鷗飛。", "詩興到來無一事，郡中今有謝玄暉。"]'),
('89090db5-934b-4d15-9808-18ceb9d735e9','曉雞','秦系','唐','唐诗','tang','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒棲。',32,'全唐诗/poet.tang.13000.json','["黯黯嚴城罷鼓鼙，數聲相續出寒棲。", "不嫌驚破紗窗夢，却恐爲妖半夜啼。"]'),
('c012d2aa-e678-491c-aa1d-d201ed7d6e2a','寄李白','任華','唐','唐诗','tang','','["\u5e90\u5c71"]','古來文章有能奔逸氣，聳高格。',405,'全唐诗/poet.tang.13000.json','["古來文章有能奔逸氣，聳高格。", "清人心神，驚人魂魄。", "我聞當今有李白，大獵賦，鴻猷文，嗤長卿，笑子雲。", "班張所作瑣細不入耳，未知卿雲得在嗤笑限。", "登廬山，觀瀑布，海風吹不斷，江月照還空。", "余愛此兩句：登天台，望渤海雲垂大鵬飛，山壓巨鰲背，斯言亦好在。", "至於他作多不拘常律，振擺超騰，既俊且逸。", "或醉中操紙，或興來走筆。", "手下忽然片雲飛，眼前劃見孤峰出。", "而我有時白日忽欲睡，睡覺歘然起攘臂。", "任生知有君，君也知有任生未。", "中間聞道在長安，及余戾止。", "君已江東訪元丹，邂逅不得見君面。", "每常把酒，向東望良久。", "見說往年在翰林，胸中矛戟何森森。", "新詩傳在宮人口，佳句不離明主心。", "身騎天馬多意氣，目送飛鴻對豪貴。", "承恩召入凡幾迴，待詔歸來仍半醉。", "權臣妬盛名，羣犬多吠聲。", "有勅放君却歸隱淪處，高歌大笑出關去。", "且向東山爲外臣，諸侯交迓馳朱輪。", "白璧一雙買交者，黃金百鎰相知人。", "平生傲岸其志不可測，數十年爲客，未嘗一日低顏色。", "八詠樓中坦腹眠，五侯門下無心憶。"]'),
('a24f9678-6279-4a85-be09-d3ebfe919190','寄杜拾遺','任華','唐','唐诗','tang','','["\u534e\u5c71"]','杜拾遺，名甫第二才甚奇。',379,'全唐诗/poet.tang.13000.json','["杜拾遺，名甫第二才甚奇。", "任生與君別，別來已多時，何嘗一日不相思。", "杜拾遺，知不知，昨日有人誦得數篇黃絹詞。", "吾怪異奇特借問，果然稱是杜二之所爲。", "勢攫虎豹，氣騰蛟螭。", "滄海無風似鼓蕩，華嶽平地欲奔馳。", "曹劉俯仰慚大敵，沈謝逡巡稱小兒。", "昔在帝城中，盛名君一個。", "諸人見所作，無不心膽破。", "郎官叢裏作狂歌，丞相閣中常醉臥。", "前年皇帝歸長安，承恩闊步青雲端。", "積翠扈游花匼匝，披香寓直月團欒。", "英才特達承天睠，公卿無不相欽慕。", "只緣汲黯好直言，遂使安仁却爲掾。", "如今避地錦城隅，幕下英僚每日相隨提玉壺。", "半醉起舞捋髭鬚，乍低乍昂傍若無。", "古人制禮但爲防俗士，豈得爲君設之乎。", "而我不飛不鳴亦可以，只待朝廷有知己。", "已曾讀却無限書，拙詩一句兩句在人耳。", "如今看之總無益，又不能崎嶇傍朝市。", "且當事耕稼，豈得便徒爾。", "南陽葛亮爲友朋，東山謝安作鄰里。", "閑常把琴弄，悶即攜樽起。", "鶯啼二月三月時，花發千山萬山裏。"]'),
('58a29f32-5c21-41d8-8119-b87073f59218','懷素上人草書歌','任華','唐','唐诗','tang','','["\u8861\u5c71"]','吾嘗好奇，古來草聖無不知，豈不知右軍與獻之。',405,'全唐诗/poet.tang.13000.json','["吾嘗好奇，古來草聖無不知，豈不知右軍與獻之。", "雖有壯麗之骨，恨無狂逸之姿。", "中間張長史，獨放蕩而不羈，以顛爲名傾蕩於當時。", "張老顛，殊不顛於懷素。", "懷素顛，乃是顛。", "人謂爾從江南來，我謂爾從天上來。", "負顛狂之墨妙，有墨狂之逸才。", "狂僧前日動京華，朝騎王公大人馬，暮宿王公大人家。", "誰不造素屏，誰不塗粉壁。", "粉壁搖晴光，素屏凝曉霜，待君揮灑兮不可彌忘。", "駿馬迎來坐堂中，金盆盛酒竹葉香。", "十桮五桮不解意，百桮已後始顛狂。", "一顛一狂多意氣，大呌一聲起攘臂。", "揮毫倏忽千萬字，有時一字兩字長丈二。", "翕若長鯨潑剌動海島，歘若長蛇戌律透深草。", "回環繚繞相拘連，千變萬化在眼前。", "飄風驟雨相擊射，速祿颯拉動簷隙。", "擲華山巨石以爲點，掣衡山陣雲以爲畫。", "興不盡，勢轉雄。", "恐天低而地窄，更有何處最可憐，褭褭枯藤萬丈懸。", "萬丈懸，拂秋水，映秋天。", "或如絲，或如髮，風吹欲絕又不絕，鋒芒利如歐冶劒。", "勁直渾是幷州鐵，時復枯燥何䙰褷。", "忽覺陰山突兀橫翠微，中有枯松錯落一萬丈。"]'),
('958d2363-c071-403a-bc1e-b1883381977d','金陵酧李翰林謫仙子','魏萬','唐','唐诗','tang','','[]','君抱碧海珠，我懷藍田玉。',288,'全唐诗/poet.tang.13000.json','["君抱碧海珠，我懷藍田玉。", "各稱希代寶，萬里遙相燭。", "長卿慕藺久，子猷意已深。", "平生風雲人，暗合江海心。", "去秋忽乘興，命駕來東土。", "謫仙遊梁園，愛子在鄒魯。", "二處一不見，拂衣向江東。", "五兩挂海月，扁舟隨長風。", "南遊吳越徧，高揖二千石。", "雪上天台山，春逢翰林伯。", "宣父敬項橐，林宗重黃生。", "一長復一少，相看如弟兄。", "惕然意不盡，更逐西南去。", "同舟入秦淮，建業龍盤處。", "楚歌對吳酒，借問承恩初。", "宮買長門賦，天迎駟馬車。", "才高世難容，道廢可推命。", "安石重攜妓，子房空謝病。", "金陵百萬戶，六代帝王都。", "虎石據西江，鍾山臨北湖。", "二山信爲美，王屋人相待。", "應爲岐路多，不知歲寒在。", "君游早晚還，勿久風塵間。", "此別未遠別，秋期到仙山。"]'),
('be6d0130-6df9-45d7-882e-3398fdd4897a','贈李十二白','崔宗之','唐','唐诗','tang','','[]','涼風八九月，白露滿空庭。',179,'全唐诗/poet.tang.13000.json','["涼風八九月，白露滿空庭。", "耿耿意不暢，捎捎風葉聲。", "思見雄俊士，共話今古情。", "李侯忽來儀，把袂苦不早。", "清論既抵掌，玄談又絕倒。", "分明楚漢事，歷歷王霸道。", "擔囊無俗物，訪古千里餘。", "袖有匕首劒，懷中茂陵書。", "雙眸光照人，詞賦凌子虛。", "酌酒弦素秦，霜氣正凝潔。", "平生心中事，今日爲君說。", "我家有別業，寄在嵩之陽。", "明月出高岑，清谿澄素光。", "雲散窗戶靜，風吹松桂香。", "子若同斯遊千載不相忘。"]'),
('aed73061-c161-4c93-bf32-d8c409e5ac06','贈李十二白','崔成甫','唐','唐诗','tang','','[]','我是瀟湘放逐臣，君辭明主漢江濱。',32,'全唐诗/poet.tang.13000.json','["我是瀟湘放逐臣，君辭明主漢江濱。", "天外常求太白老，金陵捉得酒仙人。"]'),
('7d1e0476-7d14-40a4-8a31-eafa1bc29f95','寄題杜拾遺錦江野亭','嚴武','唐','唐诗','tang','','[]','漫向江頭把釣竿，懶眠沙草愛風湍。',64,'全唐诗/poet.tang.13000.json','["漫向江頭把釣竿，懶眠沙草愛風湍。", "莫倚善題鸚鵡賦，何須不著鵕鸃冠。", "腹中書籍幽時曬，肘後醫方靜處看。", "興發會能馳駿馬，應須直到使君灘。"]'),
('569ed2c5-a458-4fd4-ab8c-756a7f9f3e78','酬別杜二','嚴武','唐','唐诗','tang','','[]','獨逢堯典日，再覩漢官時。',120,'全唐诗/poet.tang.13000.json','["獨逢堯典日，再覩漢官時。", "未効風霜勁，空慚雨露私。", "夜鐘清萬戶，曙漏拂千旗。", "並向殊庭謁，俱承別館追。", "斗城憐舊路，渦水惜歸期。", "峰樹還相伴，江雲更對垂。", "試迴滄海櫂，莫妬敬亭詩。", "秪是書應寄，無忘酒共持。", "但令心事在，未肯鬢毛衰。", "最悵巴山裏，清猨醒夢思。"]'),
('b42a6899-25df-4c90-8aa1-3707929f20ac','題巴州光福寺楠木','嚴武','唐','唐诗','tang','','[]','楚江長流對楚寺，楠木幽生赤崖背。',128,'全唐诗/poet.tang.13000.json','["楚江長流對楚寺，楠木幽生赤崖背。", "臨谿插石盤老根，苔色青蒼山雨痕。", "高枝鬧葉鳥不度，半掩白雲朝與暮。", "香殿蕭條轉密陰，花龕滴瀝垂清露。", "聞道偏多越水頭，煙生霽歛使人愁。", "月明忽憶湘川夜，猨呌還思鄂渚秋。", "看君幽靄幾千丈，寂寞窮山今遇賞。", "亦知鐘梵報黃昏，猶臥禪牀戀奇響。"]'),
('f600be4a-fb4c-4656-a203-9eab3847d449','班婕妤','嚴武','唐','唐诗','tang','','[]','賤妾如桃李，君王若歲時。',48,'全唐诗/poet.tang.13000.json','["賤妾如桃李，君王若歲時。", "秋風一已勁，搖落不勝悲。", "寂寂蒼苔滿，沈沈綠草滋。", "繁華非此日，指輦競何辭。"]'),
('d438c27b-a04b-4d22-8d1a-856edf0153d5','巴嶺荅杜二見憶','嚴武','唐','唐诗','tang','','[]','臥向巴山落月時，兩鄉千里夢相思。',64,'全唐诗/poet.tang.13000.json','["臥向巴山落月時，兩鄉千里夢相思。", "可但步兵偏愛酒，也知光祿最能詩。", "江頭赤葉楓愁客，籬外黃花菊對誰。", "跂馬望君非一度，冷猨秋鴈不勝悲。"]'),
('3e07861d-a4bc-436e-a8bc-256e865edaa8','軍城早秋','嚴武','唐','唐诗','tang','','["\u98ce", "\u5199\u98ce", "\u8fb9\u585e"]','昨夜秋風入漢關，朔雲邊月滿西山。',32,'全唐诗/poet.tang.13000.json','["昨夜秋風入漢關，朔雲邊月滿西山。", "更催飛將追驕虜，莫遣沙場匹馬遠。"]'),
('01610841-4c30-48d5-9891-1ef8abe037c2','潭州留別杜員外院長','韋迢','唐','唐诗','tang','','[]','江畔長沙驛，相逢纜客船。',48,'全唐诗/poet.tang.13000.json','["江畔長沙驛，相逢纜客船。", "大名詩獨步，小郡海西偏。", "地濕愁飛鵩，天炎畏跕鳶。", "去留俱失意，把臂共潸然。"]'),
('dcec503b-6166-446d-97b8-e97367465b22','早發湘潭寄杜員外院長','韋迢','唐','唐诗','tang','','[]','北風昨夜雨，江上早來涼。',48,'全唐诗/poet.tang.13000.json','["北風昨夜雨，江上早來涼。", "楚岫千峰翠，湘潭一葉黃。", "故人湖外客，白首尚爲郎。", "相憶無南鴈，何時有報章。"]'),
('9f7a8a88-9357-4aaf-a776-8dda768111da','寄杜員外','郭受','唐','唐诗','tang','','[]','新詩海內流傳久，舊德朝中屬望勞。',64,'全唐诗/poet.tang.13000.json','["新詩海內流傳久，舊德朝中屬望勞。", "郡邑地卑饒霧雨，江湖天闊足風濤。", "松花酒熟傍看醉，蓮葉舟輕自學操。", "春興不知凡幾首，衡陽紙價頓能高。"]'),
('31922b75-1ce3-436e-bfde-6dc7fe8ef613','晦日呈諸判官','韓滉','唐','唐诗','tang','','[]','晦日新晴春色嬌，萬家攀折渡長橋。',32,'全唐诗/poet.tang.13000.json','["晦日新晴春色嬌，萬家攀折渡長橋。", "年年老向江城寺，不覺春風換柳條。"]'),
('732b5f5f-c66b-418a-8edf-207a527926a8','聽樂悵然自述','韓滉','唐','唐诗','tang','','[]','萬事傷心對管弦，一身含淚向春煙。',32,'全唐诗/poet.tang.13000.json','["萬事傷心對管弦，一身含淚向春煙。", "黃金用盡敎歌舞，留與他人樂少年。"]'),
('b2758d03-e48e-406e-a461-2a47c99126d4','題弟臮述書賦後','竇蒙','唐','唐诗','tang','','[]','受命別家鄉，思歸每斷腸。',72,'全唐诗/poet.tang.13000.json','["受命別家鄉，思歸每斷腸。", "季江留被在，子敬與琴亡。", "吾弟當平昔，才名荷寵光。", "作詩通小雅，獻賦掩長楊。", "流轉三千里，悲啼百萬行。", "庭前紫荆樹，何日再芬芳。"]'),
('ca8203cd-e850-43d3-8fbd-b9d521b5e421','迎春東郊','張濯','唐','唐诗','tang','','["\u9ec4\u5c71"]','顓頊時初謝，句芒令復陳。',96,'全唐诗/poet.tang.13000.json','["顓頊時初謝，句芒令復陳。", "飛灰將應節，賓日已知春。", "考曆明三統，迎祥受萬人。", "衣冠宵執玉，壇墠曉清塵。", "肅穆來東道，回環拱北辰。", "仗前花待發，旂處柳疑新。", "雲斂黃山際，冰開素滻濱。", "聖朝多慶賞，希爲薦沈淪。"]'),
('8ad4658d-483c-4540-ad7a-ee5e7de8041d','題舜廟','張濯','唐','唐诗','tang','','[]','古都遺廟出河濆，萬代千秋仰聖君。',64,'全唐诗/poet.tang.13000.json','["古都遺廟出河濆，萬代千秋仰聖君。", "蒲坂城邊長逝水，蒼梧野外不歸雲。", "寥寥象設魂應在，寂寂虞篇德已聞。", "向晚風吹庭下栢，猶疑琴曲韻南薰。"]'),
('ecfdb48f-8b75-45de-a82e-aa5da56a024c','迎春東郊','王綽','唐','唐诗','tang','','[]','玉管潛移律，東郊始報春。',72,'全唐诗/poet.tang.13000.json','["玉管潛移律，東郊始報春。", "鑾輿應寶運，天仗出佳辰。", "睿澤光時輩，恩輝及物新。", "虬螭動旌斾，煙景入城闉。", "御柳初含色，龍池漸啟津。", "誰憐在陰者，得與蟄蟲伸。"]'),
('580be45a-7004-4b26-b5b5-85a6786c8031','邯鄲少年行','鄭錫','唐','唐诗','tang','','[]','霞鞍金口騮，豹袖紫貂裘。',48,'全唐诗/poet.tang.13000.json','["霞鞍金口騮，豹袖紫貂裘。", "家住叢臺近，門前漳水流。", "喚人呈楚舞，借客試吳鉤。", "見說秦兵至，甘心赴國讐。"]'),
('61f2f234-2d7e-428d-80a8-0aa6c775c198','隴頭別','鄭錫','唐','唐诗','tang','','[]','秋盡初移幕，霑裳一送君。',48,'全唐诗/poet.tang.13000.json','["秋盡初移幕，霑裳一送君。", "據鞍窺古堠，開竈爇寒雲。", "登隴人迴首，臨關馬顧羣。", "從來斷腸處，皆向此中分。"]'),
('d3f6ce71-4ed1-4642-a150-bd3386966687','度關山','鄭錫','唐','唐诗','tang','','[]','象弭插文犀，魚腸瑩鸊鵜。',48,'全唐诗/poet.tang.13000.json','["象弭插文犀，魚腸瑩鸊鵜。", "水聲分隴咽，馬色度關迷。", "曉幕胡沙慘，危烽漢月低。", "仍聞數騎將，更欲出遼西。"]');
